INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3086', 'human', 'decrease', 'low-throughput', 'The genes involved included known IBD-associated host–microbial interaction factors, including DUOX2 and its maturation factor DUOXA231,36, both of which were negatively associated with the abundance of Ruminococcaceae UCG 005 (OTU 89) in the ileum.', 'cell culture', 'HPLC analysis,qPCR,LC/MS analysis', '31142855');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3087', 'human', 'decrease', 'low-throughput', 'The expression of several chemokine genes, some of which have reported antimicrobial properties37 (CXCL6, CCL20), were negatively correlated with the relative abundance of Eubacterium rectale (OTU 120) in the ileum, and Streptococcus (OTU 37) and Eikenella (OTU 39) in the rectum, suggesting that these species are the most susceptible to the activity of these chemokines.', 'cell culture', 'HPLC analysis,qPCR,LC/MS analysis', '31142855');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3109', 'human', 'decrease', 'low-throughput', 'Indoxyl-sulfate (Beta(SE) = -2.74(0.24), P = 8.8x10-29),p-cresyl-sulfate (-1.99(0.24), P = 4.6x10-16), and phenylacetylglutamine (-2.73(0.25),P = 1.2x10-25) were significantly and negatively associated with eGFR after adjusting for age, sex, body mass index (BMI), metabolite batch, type 2 diabetes, family relatedness and multiple testing using Bonferroni correction (Table 2).', 'in vitro experiments', 'GC/MS analysis', '26241311');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3110', 'human', 'decrease', 'low-throughput', 'Indoxyl-sulfate (Beta(SE) = -2.74(0.24), P = 8.8x10-29),p-cresyl-sulfate (-1.99(0.24), P = 4.6x10-16), and phenylacetylglutamine (-2.73(0.25),P = 1.2x10-25) were significantly and negatively associated with eGFR after adjusting for age, sex, body mass index (BMI), metabolite batch, type 2 diabetes, family relatedness and multiple testing using Bonferroni correction (Table 2).', 'in vitro experiments', 'GC/MS analysis', '26241311');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3111', 'human', 'decrease', 'low-throughput', 'Indoxyl-sulfate (Beta(SE) = -2.74(0.24), P = 8.8x10-29),p-cresyl-sulfate (-1.99(0.24), P = 4.6x10-16), and phenylacetylglutamine (-2.73(0.25),P = 1.2x10-25) were significantly and negatively associated with eGFR after adjusting for age, sex, body mass index (BMI), metabolite batch, type 2 diabetes, family relatedness and multiple testing using Bonferroni correction (Table 2).', 'in vitro experiments', 'GC/MS analysis', '26241311');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3141', 'human', 'increase', 'low-throughput', 'In the evaluation of our study, a lower count of A.muciniphila and F. prausnitzii was observed in the micro biota of allergic children. F. prausnitzii and A.muciniphila may have induced anti-inflammatory cytokine IL-10 and may prevent the secretion of pro-inflammatory cytokines like IL-12. These findings suggest that A. muciniphila and F.prausnitzii may suppress inflammation through its secreted metabolites.29 We suggest that all of the aforementioned mechanisms that result from the decrease of F.prausnitzii and A. muciniphila may contribute to allergic asthma in our patient group.', 'cell culture', 'qPCR', '30765132');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3142', 'human', 'decrease', 'low-throughput', 'In the evaluation of our study, a lower count of A.muciniphila and F. prausnitzii was observed in the micro biota of allergic children. F. prausnitzii and A.muciniphila may have induced anti-inflammatory cytokine IL-10 and may prevent the secretion of pro-inflammatory cytokines like IL-12. These findings suggest that A. muciniphila and F.prausnitzii may suppress inflammation through its secreted metabolites.29 We suggest that all of the aforementioned mechanisms that result from the decrease of F.prausnitzii and A. muciniphila may contribute to allergic asthma in our patient group.', 'cell culture', 'qPCR', '30765132');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3143', 'human', 'decrease', 'low-throughput', 'In the evaluation of our study, a lower count of A.muciniphila and F. prausnitzii was observed in the micro biota of allergic children. F. prausnitzii and A.muciniphila may have induced anti-inflammatory cytokine IL-10 and may prevent the secretion of pro-inflammatory cytokines like IL-12. These findings suggest that A. muciniphila and F.prausnitzii may suppress inflammation through its secreted metabolites.29 We suggest that all of the aforementioned mechanisms that result from the decrease of F.prausnitzii and A. muciniphila may contribute to allergic asthma in our patient group.', 'cell culture', 'qPCR', '30765132');
