INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3149', 'human', 'increase', 'low-throughput', 'Based on these results and on the frequent expression of CCR6, CXCR3, and CXCR6 by colon-derived DP8a cells, we then further focused on CCR6, CXCR3, and CXCR6 as potential markers for F prausnitzii–specific DP8a cells: in comparison to LPLs, CCR6þ, CXCR6þ, and CXCR3þ cells represented only 55%, 32%, and 37%, respectively, of DP8a cells derived from PBMCs, and almost 18% of the latter cells expressed the 3 molecules.', 'cell culture', 'ELISA', '29981781');
