INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3237', 'human', 'increase', 'low-throughput', 'The expression of barrier-forming genes, viz. ZO-1, Claudin-1, Occludin and Cingulin were elevated significantly (p < 0.05) by 2.33 ± 0.4, 2.47 ± 0.3, 2.70 ± 0.5 and 3.13 ± 0.6 folds, respectively, after exposure of Caco-2 cells to L. rhamnosus for 6 h as compared to untreated cells (Fig. 2A-D).', 'control experiment,in vitro bacterial culture,cell culture', 'real-time qPCR,real-time PCR,qPCR', '31732863');
