INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3241', 'human', 'decrease', 'low-throughput', 'In contrast to the remarkable elevated levels of hBD-2 mRNA after stimulation with E. coli individually, exclusion, competition and displacement of E. coli by L. rhamnosus considerably reduced its expression which was indicative of the induction of healthy conditions in presence of L. rhamnosus under the pathogenic milieu set in by E. coli alone.', 'control experiment,in vitro bacterial culture,cell culture', 'real-time qPCR,real-time PCR,qPCR', '31732863');
