INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3367', 'human', 'increase', 'low-throughput', 'In the present study, we focused on the impact of SCFAs and the role of PPAR-γin intestinal ANGPTL4 expression. Here, we show that ANGPTL4 expression can be regulated by SCFAs both in vitro and in vivo, with butyrate being the most efficient activator.', 'control experiment', 'real-time qPCR，Western blot assay，ELISA', '23518684');
