INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3421', 'human', 'decrease', 'low-throughput', 'In the present study, LP mitigated the UCB-induced redistribution of occludin, ZO-1, claudin-1, claudin-4, JAM-1 and F-actin.', 'control experiment,in vitro bacterial culture,cell culture', 'Western blot assay, real-time qPCR', '20412608');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3422', 'human', 'increase', 'low-throughput', 'F. prausnitzii, B. longum and F. prausnitzii supernatant clearly facilitated the induction of IL-10 and TGF-β1, while induced relatively mild production of IL-12p70 in both cellular and animal models. The F. prausnitzii, B. longum and supernatant differed in their capacity to induce T-bet, GATA-3 and ROR-γt mRNA expression in human PBMCs (both bacterial strains inhibited the expression of ROR-γt while supernatant inhibited the T-bet and GATA-3). However, all of them induced the Foxp3 and Treg production and ameliorated the TNBS-induced colitis. In addition, F. prausnitzii supernatant exhibited the supreme anti-inflammatory capacity.', 'control experiment,in vitro bacterial culture', 'ELISA,real-time qPCR', '23643066');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3423', 'human', 'increase', 'low-throughput', 'F. prausnitzii, B. longum and F. prausnitzii supernatant clearly facilitated the induction of IL-10 and TGF-β1, while induced relatively mild production of IL-12p70 in both cellular and animal models. The F. prausnitzii, B. longum and supernatant differed in their capacity to induce T-bet, GATA-3 and ROR-γt mRNA expression in human PBMCs (both bacterial strains inhibited the expression of ROR-γt while supernatant inhibited the T-bet and GATA-3). However, all of them induced the Foxp3 and Treg production and ameliorated the TNBS-induced colitis. In addition, F. prausnitzii supernatant exhibited the supreme anti-inflammatory capacity.', 'control experiment,in vitro bacterial culture', 'ELISA,real-time qPCR', '23643066');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3424', 'human', 'increase', 'low-throughput', 'F. prausnitzii, B. longum and F. prausnitzii supernatant clearly facilitated the induction of IL-10 and TGF-β1, while induced relatively mild production of IL-12p70 in both cellular and animal models. The F. prausnitzii, B. longum and supernatant differed in their capacity to induce T-bet, GATA-3 and ROR-γt mRNA expression in human PBMCs (both bacterial strains inhibited the expression of ROR-γt while supernatant inhibited the T-bet and GATA-3). However, all of them induced the Foxp3 and Treg production and ameliorated the TNBS-induced colitis. In addition, F. prausnitzii supernatant exhibited the supreme anti-inflammatory capacity.', 'control experiment,in vitro bacterial culture', 'ELISA,real-time qPCR', '23643066');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3451', 'human', 'increase', 'low-throughput', 'These data show that B dentium–secreted products, including acetate, can modulate 5-HT production by host enterochromaffin cells.', 'in vitro bacterial culture', 'immunostaining, qPCR，LC-MS/MS analysis', '32795610');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3504', 'human', 'decrease', 'low-throughput', 'A Gram-negative anaerobic bacterium, strain 4, capable of metabolizing diosmetin-7-O-glucoside was newly isolated.Its 16S rRNA sequence displayed 99% similarity with that of Escherichia. Then strain 4 was identified as a species of thegenus Escherichia and was named Escherichia sp. 4. Additionally,  an ultraperformance liquid chromatography/quadrupole-time-of-flight mass spectrometry  technique combined with Metabolynx software method was established to screenthe metabolites of diosmetin-7-O-glucoside.', 'in vitro bacterial culture,control experiment', 'HPLC analysis,16S rRNA sequence', '25382172');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3511', 'human', 'decrease', 'low-throughput', 'Inactivated probiotic strains can affect TLR4 expression in a down-regulatory direction as with lipopolysaccharides  after 12 hours. LGG significantly down-regulated expression of p38 while IκB expression was significantly reduced  in L.del-treated DCs. Moreover, we found these Lactobacillus strains could even modify the immune response at  post-transcriptional level by modifying miRNAs expression. Based on our results LGG induced a significant down_regulatory effect on miR-146a expression which is known as a novel fine negative regulator of immune response  targeting NFκB. On the other hand, miR-155 was up-regulated by LGG which is consistent with down-regulation  of p38 and in LGG-treated DCs.', 'cell culture', 'fluorescence microscopy,RT-PCR', '22476320');
