INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3530', 'human', 'decrease', 'low-throughput', 'The amount of TCF7L2 increased gradually over time in control cells, but it was markedly reduced by DIF-3 in a time and dose-dependent manner.', 'cell culture', 'Western blot assay,RT-PCR', '25913757');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3531', 'human', 'decrease', 'low-throughput', 'DIF-3 decreased the expression of cyclin D1 and cMyc to a level comparable to the reduction induced by DIF-1.', 'cell culture', 'Western blot assay,RT-PCR', '25913757');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3532', 'human', 'decrease', 'low-throughput', 'DIF-3 decreased the expression of cyclin D1 and cMyc to a level comparable to the reduction induced by DIF-1.', 'cell culture', 'Western blot assay,RT-PCR', '25913757');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3533', 'human', 'decrease', 'low-throughput', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC3) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 'in vitro bacterial culture,cell culture', 'LC/MS analysis,qPCR', '30683619');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3534', 'human', 'decrease', 'low-throughput', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC4) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 'in vitro bacterial culture,cell culture', 'LC/MS analysis,qPCR', '30683619');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3535', 'human', 'decrease', 'low-throughput', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC5) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 'in vitro bacterial culture,cell culture', 'LC/MS analysis,qPCR', '30683619');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3540', 'human', 'increase', 'low-throughput', 'In summary, our results clearly demonstrate that different E. faecalis strains differentially induce colitis in monoassociated IL-10-/- mice and that severe E. faecalis-induced colitis resulted in decreased Alix/AIP1 protein expression as well as ERK1/2 phosphorylation. Functional studies revealed no effect of Alix/AIP1 on bacteria- and EGF-mediated effects on the epithelium. The 13 differentially regulated proteins might be ofinterest aspotentialmarkers for severeintestinalinflammation.', 'in vitro bacterial culture,cell culture', 'qPCR,ELISA,Western blot assay', '19166300');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3541', 'human', 'decrease', 'low-throughput', 'In summary, our results clearly demonstrate that different E. faecalis strains differentially induce colitis in monoassociated IL-10-/- mice and that severe E. faecalis-induced colitis resulted in decreased Alix/AIP1 protein expression as well as ERK1/2 phosphorylation. Functional studies revealed no effect of Alix/AIP1 on bacteria- and EGF-mediated effects on the epithelium. The 13 differentially regulated proteins might be ofinterest aspotentialmarkers for severeintestinalinflammation.', 'in vitro bacterial culture,cell culture', 'qPCR,ELISA,Western blot assay', '19166300');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3566', 'human', 'increase', 'low-throughput', 'Regulatory T cells (Tregs) that express the transcription factor Foxp3 are critical for regulating intestinal inflammation. Candidate microbe approaches have identified bacterial species and strain-specific molecules that can affect intestinal immune responses, including species that modulate Treg responses. Because neither all humans nor mice harbor the same bacterial strains, we posited that more prevalent factors exist that regulate the number and function of colonic Tregs. We determined that short chain fatty acids (SCFA), gut microbiota-derived bacterial fermentation products, regulate the size and function of the colonic Treg pool and protect against colitis in a Ffar2(GPR43)-dependent manner in mice. Our study reveals that a class of abundant microbial metabolites underlies adaptive immune microbiota co-adaptation and promotes colonic homeostasis and health.', 'cell culture', 'null', '23828891');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3567', 'human', 'increase', 'low-throughput', 'Regulatory T cells (Tregs) that express the transcription factor Foxp3 are critical for regulating intestinal inflammation. Candidate microbe approaches have identified bacterial species and strain-specific molecules that can affect intestinal immune responses, including species that modulate Treg responses. Because neither all humans nor mice harbor the same bacterial strains, we posited that more prevalent factors exist that regulate the number and function of colonic Tregs. We determined that short chain fatty acids (SCFA), gut microbiota-derived bacterial fermentation products, regulate the size and function of the colonic Treg pool and protect against colitis in a Ffar2(GPR43)-dependent manner in mice. Our study reveals that a class of abundant microbial metabolites underlies adaptive immune microbiota co-adaptation and promotes colonic homeostasis and health.', 'cell culture', 'null', '23828891');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3568', 'human', 'increase', 'low-throughput', 'Regulatory T cells (Tregs) that express the transcription factor Foxp3 are critical for regulating intestinal inflammation. Candidate microbe approaches have identified bacterial species and strain-specific molecules that can affect intestinal immune responses, including species that modulate Treg responses. Because neither all humans nor mice harbor the same bacterial strains, we posited that more prevalent factors exist that regulate the number and function of colonic Tregs. We determined that short chain fatty acids (SCFA), gut microbiota-derived bacterial fermentation products, regulate the size and function of the colonic Treg pool and protect against colitis in a Ffar2(GPR43)-dependent manner in mice. Our study reveals that a class of abundant microbial metabolites underlies adaptive immune microbiota co-adaptation and promotes colonic homeostasis and health.', 'cell culture', 'null', '23828891');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3569', 'human', 'decrease', 'low-throughput', 'F. prausnitzii exhibits anti-inflammatory effects, partly due to secreted metabolites able to block nuclear factor-κB activation and the secretion of proinflammatory mediators (41). Oral administration of F. prausnitzii or of supernatant from F. prausnitzii cultures increased the production of IL-10 by blood mononuclear cells and reduced the production of the proinflammatory mediator-like IL-12 in the colon.', 'in vitro bacterial culture', 'RT-qPCR', '20876719');
