INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3588', 'human', 'decrease', 'low-throughput', 'F. prausnitzii modulated the metabolome of the host blood by decreasing IL-1α, IL-2, and IL-5 concentrations.', 'in vivo experiment,in vitro bacterial culture', 'null', '25900655');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3589', 'human', 'decrease', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 'in vitro bacterial culture', '16S rRNA sequence,Western blot assay,RT-PCR', '30566883');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3590', 'human', 'increase', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 'in vitro bacterial culture', '16S rRNA sequence,Western blot assay,RT-PCR', '30566883');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3591', 'human', 'increase', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 'in vitro bacterial culture', '16S rRNA sequence,Western blot assay,RT-PCR', '30566883');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3592', 'human', 'increase', 'low-throughput', 'Our data demonstrate that a dysbiotic gut microbiota in RA patients, characterized by a decrease in Faecalibacterium and expansion of C. aerofaciens and E. lenta, could trigger inflammatory conditions in the gut that depend on the production of chemokines and IL-17A and compromise the gut epithelium integrity. It is possible that the inflammatory conditions can be modulated by prebiotics or probiotics. The therapeutic potential of the only probiotics, lactobacilli, used as treatment for RA is inconclusive, with some studies in favor of their use while others did not show significant improvement with lactobacilli using the American College of Rheumatology (ACR) response criteria for RA .', 'cell culture', '16S rRNA sequence,RT-qPCR', '27102666');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3593', 'human', 'increase', 'low-throughput', 'Our data demonstrate that a dysbiotic gut microbiota in RA patients, characterized by a decrease in Faecalibacterium and expansion of C. aerofaciens and E. lenta, could trigger inflammatory conditions in the gut that depend on the production of chemokines and IL-17A and compromise the gut epithelium integrity. It is possible that the inflammatory conditions can be modulated by prebiotics or probiotics. The therapeutic potential of the only probiotics, lactobacilli, used as treatment for RA is inconclusive, with some studies in favor of their use while others did not show significant improvement with lactobacilli using the American College of Rheumatology (ACR) response criteria for RA .', 'cell culture', '16S rRNA sequence,RT-qPCR', '27102666');
