INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3595', 'human', 'increase', 'low-throughput', 'Our data demonstrate that a dysbiotic gut microbiota in RA patients, characterized by a decrease in Faecalibacterium and expansion of C. aerofaciens and E. lenta, could trigger inflammatory conditions in the gut that depend on the production of chemokines and IL-17A and compromise the gut epithelium integrity. It is possible that the inflammatory conditions can be modulated by prebiotics or probiotics. The therapeutic potential of the only probiotics, lactobacilli, used as treatment for RA is inconclusive, with some studies in favor of their use while others did not show significant improvement with lactobacilli using the American College of Rheumatology (ACR) response criteria for RA .', 'cell culture', '16S rRNA sequence,RT-qPCR', '27102666');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3598', 'human', 'increase', 'low-throughput', 'Here, we show that in colonic cell lines and in primary colonic cells, Enterococcus faecalis isolated from newborn babies possess the ability to regulate peroxisome proliferator-activated receptor-γ1 (PPARγ1) activity through phosphorylation. This results in elevated DNA binding and transcriptional activation of downstream target genes, including IL-10, a cytokine known to modulate innate immune function. Furthermore, phosphorylation appears tightly regulated as phospho-PPARγ1 becomes an immediate substrate for degradation possibly to curtail any extended transactivation. The involvement of PPARγ1 in a myriad of physiological processes further confirms that microflora-driven regulation might be important for a number of homeostatic strategies in the gut.', 'cell culture', 'Western blot assay,RT-PCR', '18234854');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3599', 'human', 'increase', 'low-throughput', 'Here, we show that in colonic cell lines and in primary colonic cells, Enterococcus faecalis isolated from newborn babies possess the ability to regulate peroxisome proliferator-activated receptor-γ1 (PPARγ1) activity through phosphorylation. This results in elevated DNA binding and transcriptional activation of downstream target genes, including IL-10, a cytokine known to modulate innate immune function. Furthermore, phosphorylation appears tightly regulated as phospho-PPARγ1 becomes an immediate substrate for degradation possibly to curtail any extended transactivation. The involvement of PPARγ1 in a myriad of physiological processes further confirms that microflora-driven regulation might be important for a number of homeostatic strategies in the gut.', 'cell culture', 'Western blot assay,RT-PCR', '18234854');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3600', 'human', 'increase', 'low-throughput', 'Here, we show that in colonic cell lines and in primary colonic cells, Enterococcus faecalis isolated from newborn babies possess the ability to regulate peroxisome proliferator-activated receptor-γ1 (PPARγ1) activity through phosphorylation. This results in elevated DNA binding and transcriptional activation of downstream target genes, including IL-10, a cytokine known to modulate innate immune function. Furthermore, phosphorylation appears tightly regulated as phospho-PPARγ1 becomes an immediate substrate for degradation possibly to curtail any extended transactivation. The involvement of PPARγ1 in a myriad of physiological processes further confirms that microflora-driven regulation might be important for a number of homeostatic strategies in the gut.', 'cell culture', 'Western blot assay,RT-PCR', '18234854');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3601', 'human', 'increase', 'low-throughput', 'Here, we show that in colonic cell lines and in primary colonic cells, Enterococcus faecalis isolated from newborn babies possess the ability to regulate peroxisome proliferator-activated receptor-γ1 (PPARγ1) activity through phosphorylation. This results in elevated DNA binding and transcriptional activation of downstream target genes, including IL-10, a cytokine known to modulate innate immune function. Furthermore, phosphorylation appears tightly regulated as phospho-PPARγ1 becomes an immediate substrate for degradation possibly to curtail any extended transactivation. The involvement of PPARγ1 in a myriad of physiological processes further confirms that microflora-driven regulation might be important for a number of homeostatic strategies in the gut.', 'cell culture', 'Western blot assay,RT-PCR', '18234854');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3602', 'human', 'decrease', 'low-throughput', 'Human and murine pregnancy were associated with reduced intestinal FXR signaling, with lower FGF19/15 and resultant increased hepatic bile acid synthesis. Terminal ileal ASBT protein was reduced in murine pregnancy. Cecal bile acid conjugation was reduced in pregnancy because of elevated bile salt hydrolase‐producing Bacteroidetes. CA supplementation induced intestinal FXR signaling, which was not abrogated by pregnancy, with strikingly similar changes to the microbiota and metabonome as identified in pregnancy. Conclusion: The altered intestinal microbiota of pregnancy enhance bile acid deconjugation, reducing ileal bile acid uptake and lowering FXR induction in enterocytes. This exacerbates the effects mediated by reduced bile acid uptake transporters in pregnancy. Thus, in pregnant women and mice, there is reduced FGF19/15‐mediated hepatic repression of hepatic bile acid synthesis, resulting in hypercholanemia.', 'in vivo experiment', 'RT-PCR,16S rRNA sequence', '30983011');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3603', 'human', 'increase', 'low-throughput', 'Human and murine pregnancy were associated with reduced intestinal FXR signaling, with lower FGF19/15 and resultant increased hepatic bile acid synthesis. Terminal ileal ASBT protein was reduced in murine pregnancy. Cecal bile acid conjugation was reduced in pregnancy because of elevated bile salt hydrolase‐producing Bacteroidetes. CA supplementation induced intestinal FXR signaling, which was not abrogated by pregnancy, with strikingly similar changes to the microbiota and metabonome as identified in pregnancy. Conclusion: The altered intestinal microbiota of pregnancy enhance bile acid deconjugation, reducing ileal bile acid uptake and lowering FXR induction in enterocytes. This exacerbates the effects mediated by reduced bile acid uptake transporters in pregnancy. Thus, in pregnant women and mice, there is reduced FGF19/15‐mediated hepatic repression of hepatic bile acid synthesis, resulting in hypercholanemia.', 'in vivo experiment', 'RT-PCR,16S rRNA sequence', '30983011');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3604', 'human', 'increase', 'low-throughput', 'The effect of Lactobacillus plantarum MB452 on tight junction integrity was determined by measuring trans-epithelial electrical resistance (TEER) across Caco-2 cell layers. L. plantarum MB452 caused a dose-dependent TEER increase across Caco-2 cell monolayers compared to control medium. Gene expression was compared in Caco-2 cells untreated or treated with L. plantarum MB452 for 10 hours. Caco-2 cell RNA was hybridised to human oligonucleotide arrays. Data was analysed using linear models and differently expressed genes were examined using pathway analysis tools. Nineteen tight junction-related genes had altered expression levels in response to L. plantarum MB452 (modified-P < 0.05, fold-change > 1.2), including those encoding occludin and its associated plaque proteins that anchor it to the cytoskeleton. L. plantarum MB452 also caused changes in tubulin and proteasome gene expression levels which may be linked to intestinal barrier function.', 'cell culture', 'null', '21143932');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3605', 'human', 'increase', 'low-throughput', 'The effect of Lactobacillus plantarum MB452 on tight junction integrity was determined by measuring trans-epithelial electrical resistance (TEER) across Caco-2 cell layers. L. plantarum MB452 caused a dose-dependent TEER increase across Caco-2 cell monolayers compared to control medium. Gene expression was compared in Caco-2 cells untreated or treated with L. plantarum MB452 for 10 hours. Caco-2 cell RNA was hybridised to human oligonucleotide arrays. Data was analysed using linear models and differently expressed genes were examined using pathway analysis tools. Nineteen tight junction-related genes had altered expression levels in response to L. plantarum MB452 (modified-P < 0.05, fold-change > 1.2), including those encoding occludin and its associated plaque proteins that anchor it to the cytoskeleton. L. plantarum MB452 also caused changes in tubulin and proteasome gene expression levels which may be linked to intestinal barrier function.', 'cell culture', 'null', '21143932');
