INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3608', 'human', 'decrease', 'low-throughput', 'The effect of Lactobacillus plantarum MB452 on tight junction integrity was determined by measuring trans-epithelial electrical resistance (TEER) across Caco-2 cell layers. L. plantarum MB452 caused a dose-dependent TEER increase across Caco-2 cell monolayers compared to control medium. Gene expression was compared in Caco-2 cells untreated or treated with L. plantarum MB452 for 10 hours. Caco-2 cell RNA was hybridised to human oligonucleotide arrays. Data was analysed using linear models and differently expressed genes were examined using pathway analysis tools. Nineteen tight junction-related genes had altered expression levels in response to L. plantarum MB452 (modified-P < 0.05, fold-change > 1.2), including those encoding occludin and its associated plaque proteins that anchor it to the cytoskeleton. L. plantarum MB452 also caused changes in tubulin and proteasome gene expression levels which may be linked to intestinal barrier function.', 'cell culture', 'null', '21143932');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3609', 'human', 'increase', 'low-throughput', 'In this study, we investigated the effects of LA and LA-derived fatty acids on the activation of peroxisome proliferator-activated receptors (PPARs) which regulate whole-body energy metabolism. None of the fatty acids activated PPARd, whereas almost all activated PPARa in luciferase assays. Two fatty acids potently activated PPARg, a master regulator of adipocyte differentiation, with 10-oxo-12(Z)-octadecenoic acid (KetoA) having the most potency. In 3T3- L1 cells, KetoA induced adipocyte differentiation via the activation of PPARg, and increased adiponectin production and insulin-stimulated glucose uptake. These findings suggest that fatty acids, including KetoA, generated in gut by lactic acid bacteria may be involved in the regulation of host energy metabolism.', 'cell culture', 'RT-PCR', '25749343');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3611', 'human', 'decrease', 'low-throughput', 'The addition of the EPM had no significant effect on transcription of IL-1β, TNF-α or IL-10 in hDCs stimulated with L. plantarum (not shown) but significantly decreased the transcript levels of IL-12 at 20h by about 2 fold.', 'in vitro bacterial culture', 'RT-qPCR', '25910186');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3612', 'human', 'decrease', 'low-throughput', 'The addition of the EPM had no significant effect on transcription of IL-1β, TNF-α or IL-10 in hDCs stimulated with L. plantarum (not shown) but significantly decreased the transcript levels of IL-12 at 20h by about 2 fold.', 'in vitro bacterial culture', 'RT-qPCR', '25910186');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3613', 'human', 'decrease', 'low-throughput', 'The EPM of F. prausnitzii HTF-F decreases transcription and production of pro-inflammatory IL-12p70 in L. plantarum-activated hDCs', 'in vitro bacterial culture', 'RT-qPCR', '25910186');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3623', 'human', 'decrease', 'low-throughput', 'F. prausnitzii was found to be underrepresented in the gut microbiotas of patients with Crohn\'s disease, active ulcerative colitis, alternating-type irritable bowel syndrome (IBS-A), and diabetes type II. One of its main fermentation products, the short-chain fatty acid butyrate, serves as the main energy source for colonocytes and has anti-inflammatory properties . F. prausnitzii has been proposed as a potential probiotic for treatment of gut inflammation, as the microbe stimulates the expression of the anti-inflammatory cytokine interleukin 10 (IL-10) in peripheral blood mononuclear cells in vitro. Furthermore, cell supernatants of F. prausnitzii culture reduced the secretion of proinflammatory IL-8 and strongly inhibited NF-κB activation in cancer cells . Butyrate alone did not provoke the observed inhibitory effect , demonstrating that F. prausnitzii likely secretes an unknown anti-inflammatory metabolite apart from butyrate.', 'in vitro bacterial culture', 'LC/MS analysis', '25002542');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3624', 'human', 'decrease', 'low-throughput', 'F. prausnitzii was found to be underrepresented in the gut microbiotas of patients with Crohn\'s disease, active ulcerative colitis, alternating-type irritable bowel syndrome (IBS-A), and diabetes type II. One of its main fermentation products, the short-chain fatty acid butyrate, serves as the main energy source for colonocytes and has anti-inflammatory properties . F. prausnitzii has been proposed as a potential probiotic for treatment of gut inflammation, as the microbe stimulates the expression of the anti-inflammatory cytokine interleukin 10 (IL-10) in peripheral blood mononuclear cells in vitro. Furthermore, cell supernatants of F. prausnitzii culture reduced the secretion of proinflammatory IL-8 and strongly inhibited NF-κB activation in cancer cells . Butyrate alone did not provoke the observed inhibitory effect , demonstrating that F. prausnitzii likely secretes an unknown anti-inflammatory metabolite apart from butyrate.', 'in vitro bacterial culture', 'LC/MS analysis', '25002542');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3625', 'human', 'increase', 'low-throughput', 'F. prausnitzii was found to be underrepresented in the gut microbiotas of patients with Crohn\'s disease, active ulcerative colitis, alternating-type irritable bowel syndrome (IBS-A), and diabetes type II. One of its main fermentation products, the short-chain fatty acid butyrate, serves as the main energy source for colonocytes and has anti-inflammatory properties . F. prausnitzii has been proposed as a potential probiotic for treatment of gut inflammation, as the microbe stimulates the expression of the anti-inflammatory cytokine interleukin 10 (IL-10) in peripheral blood mononuclear cells in vitro. Furthermore, cell supernatants of F. prausnitzii culture reduced the secretion of proinflammatory IL-8 and strongly inhibited NF-κB activation in cancer cells . Butyrate alone did not provoke the observed inhibitory effect , demonstrating that F. prausnitzii likely secretes an unknown anti-inflammatory metabolite apart from butyrate.', 'in vitro bacterial culture', 'LC/MS analysis', '25002542');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3629', 'human', 'increase', 'low-throughput', 'Here we reveal a relationship between gut microbiota and caspase recruitment domain family member 9 (CARD9), a susceptibility gene for inflammatory bowel disease (IBD) that functions in the immune response against microorganisms. CARD9 promotes recovery from colitis by promoting interleukin (IL)-22 production, and Card9�?�?mice are more susceptible to colitis. The microbiota is altered in Card9�?�?mice, and transfer of the microbiota from Card9�?�?to wild-type, germ-free recipients increases their susceptibility to colitis. The microbiota from Card9�?�?mice fails to metabolize tryptophan into metabolites that act as aryl hydrocarbon receptor (AHR) ligands. Intestinal inflammation is attenuated after inoculation of mice with three Lactobacillus strains capable of metabolizing tryptophan or by treatment with an AHR agonist. Reduced production of AHR ligands is also observed in the microbiota from individuals with IBD, particularly in those with CARD9 risk alleles associated with IBD. Our findings reveal that host genes affect the composition and function of the gut microbiota, altering the production of microbial metabolites and intestinal inflammation', 'in vitro bacterial culture', 'qPCR,16S rDNA sequence,HPLC analysis', '27158904');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3630', 'human', 'increase', 'low-throughput', 'Here we reveal a relationship between gut microbiota and caspase recruitment domain family member 9 (CARD9), a susceptibility gene for inflammatory bowel disease (IBD) that functions in the immune response against microorganisms. CARD9 promotes recovery from colitis by promoting interleukin (IL)-22 production, and Card9�?�?mice are more susceptible to colitis. The microbiota is altered in Card9�?�?mice, and transfer of the microbiota from Card9�?�?to wild-type, germ-free recipients increases their susceptibility to colitis. The microbiota from Card9�?�?mice fails to metabolize tryptophan into metabolites that act as aryl hydrocarbon receptor (AHR) ligands. Intestinal inflammation is attenuated after inoculation of mice with three Lactobacillus strains capable of metabolizing tryptophan or by treatment with an AHR agonist. Reduced production of AHR ligands is also observed in the microbiota from individuals with IBD, particularly in those with CARD9 risk alleles associated with IBD. Our findings reveal that host genes affect the composition and function of the gut microbiota, altering the production of microbial metabolites and intestinal inflammation', 'in vitro bacterial culture', 'qPCR,16S rDNA sequence,HPLC analysis', '27158904');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3631', 'human', 'decrease', 'low-throughput', 'Plasma from rats treated for seven days with the non-absorbed antibiotic vancomycin or a mixture of streptomycin, neomycin, polymyxin B and bacitracin was analyzed using mass spectrometry-based metabolite profiling platforms. Antibiotic-induced changes in the abundance of individual groups of intestinal microbiota dramatically altered the host\'s metabolism. Hierarchical clustering of dissimilarities separated the levels of 284 identified metabolites from treated vs. untreated rats; 193 were altered by the antibiotic treatments with a tendency towards decreased metabolite levels. Catabolism of the aromatic amino acids phenylalanine, tryptophan and tyrosine was the most affected pathway comprising 33 affected metabolites. Vancomycin-treated rats were administered amino acid metabolites prior to ischemia/reperfusion studies. Oral or intravenous pretreatment of rats with these amino acid metabolites abolished the decrease in infarct size conferred by vancomycin. Cardioprotection by vancomycin is mediated by activation of pro-survival kinases Akt, p42/44 MAPK and p38 MAPK, as well as activation of KATP channels, classical mediators and effectors of pharmacologic cardioprotection. These proteins are components of known intersecting and interdependent signaling pathways in the myocardium that determine severity of myocardial infarction.', 'in vivo experiment', 'RT-PCR', '27505423');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3645', 'human', 'decrease', 'low-throughput', 'In addition, the mixture considerably inhibited expression of Bcl-2 together with an increase in Bax expression. Likewise, activation stimulated cleavage of caspase-3 and production of reactive oxygen species in HepG2 cell cultures.', 'cell culture、in vitro bacterial culture、control experiment', 'Western blot assay、RT-PCR、HPLC analysis', '21889493');
