INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3657', 'human', 'increase', 'low-throughput', 'S. macedonicus ACA-DC 198 was the strongest inducer of the three pro inflammatory cytokines IL-12 (337 pg mL�?1), TNF-α (36721 pg mL�?) and IFN-γ (37684 pgmL�?). L. plantarum ACA-DC 287 induced lower, but still considerable, amounts of IL-12, TNF-α and IFN-γ (153, 19307 and 28694 pg mL�?, respectively), with higher levels of the anti-inflammatory cytokine IL-10 (1498 pg mL�?) compared to S. macedonicus ACA-DC 198 (777 pg mL�?). The highest secretion of IL-10 (2815 pg mL�?) was displayed when PBMCs were incubated with L. fermentum ACA-DC 179, which also induced notable levels of TNF-α (3579 pg mL�?), but low levels of IFN-γ (115 pg mL�?) and no secretion for IL-12.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'null', '18077037');
