INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3666', 'human', 'decrease', 'low-throughput', 'B. infantis and MO decreased hepatic CYP7A1 and induced Sult2a1, Sult2a2, and Sult2a3 suggesting reduced BA synthesis and increased detoxification. Furthermore, B. infantis and MO increased ileal BA membrane receptor TGR5-regulated signaling. Together, via BA-regulated signaling, synbiotics B. infantis and MO have their unique and combined effects in reversing NASH.', 'in vitro bacterial culture', 'qPCR,LC/MS analysis', '29800811');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3676', 'human', 'increase', 'low-throughput', 'B. infantis and MO decreased hepatic CYP7A1 and induced Sult2a1, Sult2a2, and Sult2a3 suggesting reduced BA synthesis and increased detoxification. Furthermore, B. infantis and MO increased ileal BA membrane receptor TGR5-regulated signaling. Together, via BA-regulated signaling, synbiotics B. infantis and MO have their unique and combined effects in reversing NASH.', 'in vitro bacterial culture', 'qPCR,LC/MS analysis', '11040423');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3677', 'human', 'increase', 'low-throughput', 'There was a significant difference in TLR2 signalling induced by live and UV‐killed bacteria. However, the activation by live bacteria was only 1.1‐fold higher than UV‐killed bacteria; therefore, the difference was less than that seen in apical anaerobic conditions and may not be biologically relevant.', 'in vitro bacterial culture,cell culture,control experiment', 'null', '29112296');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3678', 'human', 'increase', 'low-throughput', 'For the activation of TLR2/6, the interaction between the environment and live/dead status was significant as shown in Figure 5b(p < .001). In apical anaerobic conditions, TLR2/6 activation by live F. prausnitzii was 1.6‐fold higher than by UV‐killed bacteria.', 'in vitro bacterial culture,cell culture,control experiment', 'null', '29112296');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3679', 'human', 'decrease', 'low-throughput', 'There was no TLR4 activation by either live or UV‐killed F. prausnitzii in both conventional and apical anaerobic conditions. The raw luminescence values for the activation of TLR2, TLR2/6,TLR4, and the activation of the control cell line (TLR‐null) are shown in Figure S3.', 'in vitro bacterial culture,cell culture,control experiment', 'null', '29112296');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3712', 'human', 'decrease', 'low-throughput', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 'in vitro bacterial culture,cell culture', 'RT-PCR,fluorescence microscopy', '16534848');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3713', 'human', 'decrease', 'low-throughput', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 'in vitro bacterial culture,cell culture', 'RT-PCR,fluorescence microscopy', '16534848');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3714', 'human', 'decrease', 'low-throughput', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 'in vitro bacterial culture,cell culture', 'RT-PCR,fluorescence microscopy', '16534848');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3715', 'human', 'decrease', 'low-throughput', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 'in vitro bacterial culture,cell culture', 'RT-PCR,fluorescence microscopy', '16534848');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3727', 'human', 'decrease', 'low-throughput', 'The commensal bacteria Escherichia coli, Bifidobacterium adolescentis, Bacteroides vulgatus, Bacteroides distasonis, and Streptococcus salivarius were screened for adhesion to, invasion of, and toxicity for host epithelial cells (EC), and the strains were tested for their ability to inhibit Y. enterocolitica-induced NF-kappaB activation. Additionally, B. adolescentis was administered to mice orally infected with Y. enterocolitica and to mice with mucosae impaired by DSS treatment. None of the commensal bacteria tested was toxic for or invaded the EC. B. adolescentis, B. distasonis, B. vulgatus, and S. salivarius inhibited the Y. enterocolitica-induced NF-kappaB activation and interleukin-8 production in EC. In line with these findings, B. adolescentis-fed mice had significantly lower results for mean pathogen burden in the visceral organs, intestinal tumor necrosis factor alpha mRNA expression, and loss of body weight upon oral infection with Y. enterocolitica. In addition, the administration of B. adolescentis decelerated inflammation upon DSS treatment in mice.', 'in vitro bacterial culture,cell culture', 'RT-PCR', '17485456');
