INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3739', 'human', 'decrease', 'low-throughput', 'L. plantarum prevents EIEC-induced expression of Claudin-1, Occludin, JAM-1 and ZO-1 proteins.', 'in vitro bacterial culture', 'fluorescence microscopy', '19331693');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3748', 'human', 'increase', 'low-throughput', 'Dietary and bacterial metabolites influence immune responses. This raises the question whether the increased incidence of allergies, asthma, some autoimmune diseases, cardiovascular disease, and others might relate to intake of unhealthy foods, and the decreased intake of dietary fiber. In recent years, new knowledge on the molecular mechanisms underpinning a \'diet-gut microbiota-physiology axis\' has emerged to substantiate this idea. Fiber is fermented to short chain fatty acids (SCFAs), particularly acetate, butyrate, and propionate. These metabolites bind \'metabolite-sensing\' G-protein-coupled receptors such as GPR43, GPR41, and GPR109A. These receptors play fundamental roles in the promotion of gut homeostasis and the regulation of inflammatory responses. For instance, these receptors and their metabolites influence Treg biology, epithelial integrity, gut homeostasis, DC biology, and IgA antibody responses. The SCFAs also influence gene transcription in many cells and tissues, through their inhibition of histone deacetylase expression or function.', 'in vitro bacterial culture', 'RT-PCR', '28658542');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3749', 'human', 'increase', 'low-throughput', 'In this study, we investigated the effects of novel fatty acid metabolite derivatives of linoleic acid generated by the gut lactic acid bacteria Lactobacillus plantarum on the Nrf2-ARE pathway. 10-Oxo-trans-11-octadecenoic acid (KetoC) protected HepG2 cells from cytotoxicity induced by hydrogen peroxide. KetoC also significantly increased cellular Nrf2 protein levels, ARE-dependent transcription, and the gene expression of antioxidative enzymes such as heme oxygenase-1 (HO-1), glutamate-cysteine ligase modifier subunit (GCLM), and Nad(p)h: quinone oxidoreductase 1 (NQO1) in HepG2 cells.', 'cell culture', 'null', '26879219');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3750', 'human', 'increase', 'low-throughput', 'In this study, we investigated the effects of novel fatty acid metabolite derivatives of linoleic acid generated by the gut lactic acid bacteria Lactobacillus plantarum on the Nrf2-ARE pathway. 10-Oxo-trans-11-octadecenoic acid (KetoC) protected HepG2 cells from cytotoxicity induced by hydrogen peroxide. KetoC also significantly increased cellular Nrf2 protein levels, ARE-dependent transcription, and the gene expression of antioxidative enzymes such as heme oxygenase-1 (HO-1), glutamate-cysteine ligase modifier subunit (GCLM), and Nad(p)h: quinone oxidoreductase 1 (NQO1) in HepG2 cells.', 'cell culture', 'null', '26879219');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3753', 'human', 'decrease', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 'in vitro bacterial culture', 'null', '19865172');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3754', 'human', 'decrease', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 'in vitro bacterial culture', 'null', '19865172');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3755', 'human', 'decrease', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 'in vitro bacterial culture', 'null', '19865172');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3756', 'human', 'decrease', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 'in vitro bacterial culture', 'null', '19865172');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3757', 'human', 'decrease', 'low-throughput', 'The genome of new equol-producing bacteria, Lactobacillus paracasei JS1, was analyzed. Also, the effect of P. lobata extract fermented with L. paracasei JS1 (FPE) on the skin and intestinal immune response was examined. With gene expression analysis, it was proven that seven skin-related proteins, hyaluronan synthase-1, -2, -3, collagen, elastin, epidermal growth factor, and epidermal growth factor receptor were differentially expressed upon FPE treatment. The messenger RNA expression increased with treatment with the FPE, and a skin moisturizing effect was confirmed by a hematoxylin-eosin staining experiment. In addition, such an experiment showed that proinflammatory cytokines, tumor necrosis factor-α, cyclooxygenase-2, inducible nitric oxide synthase, interleukin-1β, -4, and -6, were reduced in large intestine when treated with FPE.', 'in vitro bacterial culture,cell culture', 'HPLC analysis,RT-PCR', '30767231');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3758', 'human', 'decrease', 'low-throughput', 'The genome of new equol-producing bacteria, Lactobacillus paracasei JS1, was analyzed. Also, the effect of P. lobata extract fermented with L. paracasei JS1 (FPE) on the skin and intestinal immune response was examined. With gene expression analysis, it was proven that seven skin-related proteins, hyaluronan synthase-1, -2, -3, collagen, elastin, epidermal growth factor, and epidermal growth factor receptor were differentially expressed upon FPE treatment. The messenger RNA expression increased with treatment with the FPE, and a skin moisturizing effect was confirmed by a hematoxylin-eosin staining experiment. In addition, such an experiment showed that proinflammatory cytokines, tumor necrosis factor-α, cyclooxygenase-2, inducible nitric oxide synthase, interleukin-1β, -4, and -6, were reduced in large intestine when treated with FPE.', 'in vitro bacterial culture,cell culture', 'HPLC analysis,RT-PCR', '30767231');
