INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3762', 'human', 'decrease', 'low-throughput', 'The genome of new equol-producing bacteria, Lactobacillus paracasei JS1, was analyzed. Also, the effect of P. lobata extract fermented with L. paracasei JS1 (FPE) on the skin and intestinal immune response was examined. With gene expression analysis, it was proven that seven skin-related proteins, hyaluronan synthase-1, -2, -3, collagen, elastin, epidermal growth factor, and epidermal growth factor receptor were differentially expressed upon FPE treatment. The messenger RNA expression increased with treatment with the FPE, and a skin moisturizing effect was confirmed by a hematoxylin-eosin staining experiment. In addition, such an experiment showed that proinflammatory cytokines, tumor necrosis factor-α, cyclooxygenase-2, inducible nitric oxide synthase, interleukin-1β, -4, and -6, were reduced in large intestine when treated with FPE.', 'in vitro bacterial culture,cell culture', 'HPLC analysis,RT-PCR', '30767231');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3765', 'human', 'increase', 'low-throughput', 'A Prevotella and an Atopobium strain were chosen for further study, and shown to up-regulate two PPARγ-target genes, ANGPTL4 and ADRP. The molecular mechanisms of these activations involved the phosphorylation of PPARγ through ERK1/2. The responsible metabolites were shown to be heat sensitive but markedly diverged in size, emphasizing the diversity of bioactive compounds found in the intestine. Here we describe different mechanisms by which single intestinal bacteria can directly impact their host\'s health through transcriptional regulation.', 'in vitro bacterial culture', 'HPLC analysis,GC/MS analysis', '28266623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3766', 'human', 'increase', 'low-throughput', 'A Prevotella and an Atopobium strain were chosen for further study, and shown to up-regulate two PPARγ-target genes, ANGPTL4 and ADRP. The molecular mechanisms of these activations involved the phosphorylation of PPARγ through ERK1/2. The responsible metabolites were shown to be heat sensitive but markedly diverged in size, emphasizing the diversity of bioactive compounds found in the intestine. Here we describe different mechanisms by which single intestinal bacteria can directly impact their host\'s health through transcriptional regulation.', 'in vitro bacterial culture', 'HPLC analysis,GC/MS analysis', '28266623');
