INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3779', 'human', 'increase', 'low-throughput', 'A. muciniphila increased the expression of tlr2 and tlr4. However, EVs at all of the concentrations showed a decrease in tlr4 expression. EVs at the concentrations of 0.1 and 0.5 µg/ml decreased the expression of tlr2. A. muciniphila significantly increased the expression of ocldn and cldn4. Both this bacterium and EVs increased the expression of zo2 in the cell line. Furthermore, this data show that A. muciniphila derived EVs have a dose-independent effect on Caco-2 cells.', 'in vitro bacterial culture,cell culture', 'RT-PCR', '31191842');
