INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3811', 'human', 'increase', 'low-throughput', 'Here we analyse the ability of OMVs and soluble secreted factors to protect epithelial barrier function in polarized T-84 and Caco-2 cells infected with enteropathogenic Escherichia coli (EPEC). Transepithelial electrical resistance, paracellular permeability, mRNA levels and subcellular distribution of tight junction proteins were monitored in the absence or presence of EcN and ECOR63 extracellular fractions. EPEC downregulated expression of ZO-1 ZO-2, occludin and claudin-14 and altered the subcellular localization of ZO-1, occludin and F-actin cytoskeleton. OMVs and soluble factors secreted by EcN and ECOR63 counteracted EPEC-altered transepithelial resistance and paracellular permeability, preserved occludin and claudin-14 mRNA levels, retained ZO-1 and occludin at tight junctions in the cell boundaries and ameliorated F-actin disorganization. Redistribution of ZO-1 was not accompanied by changes at mRNA level.', 'in vitro bacterial culture,cell culture', 'null', '31315566');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3812', 'human', 'increase', 'low-throughput', 'Here we analyse the ability of OMVs and soluble secreted factors to protect epithelial barrier function in polarized T-84 and Caco-2 cells infected with enteropathogenic Escherichia coli (EPEC). Transepithelial electrical resistance, paracellular permeability, mRNA levels and subcellular distribution of tight junction proteins were monitored in the absence or presence of EcN and ECOR63 extracellular fractions. EPEC downregulated expression of ZO-1 ZO-2, occludin and claudin-14 and altered the subcellular localization of ZO-1, occludin and F-actin cytoskeleton. OMVs and soluble factors secreted by EcN and ECOR63 counteracted EPEC-altered transepithelial resistance and paracellular permeability, preserved occludin and claudin-14 mRNA levels, retained ZO-1 and occludin at tight junctions in the cell boundaries and ameliorated F-actin disorganization. Redistribution of ZO-1 was not accompanied by changes at mRNA level.', 'in vitro bacterial culture,cell culture', 'null', '31315566');
