INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3824', 'human', 'decrease', 'low-throughput', 'It has been shown to down-regulate nuclear transcription factor (NF-кB) in human intestinal cells, a central regulator of the host mucosal immune system response to the microbiota.', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay', '25946041');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3825', 'human', 'decrease', 'low-throughput', 'In order to evaluate its impact on a further important transcription factor shown to link metabolism and inflammation in the intestine, namely PPARγ (peroxisome proliferator-activated receptor), we used human intestinal epithelial cell-lines engineered to monitor PPARγ transcriptional activity in response to a wide range of S. salivarius strains.', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay', '25946041');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3826', 'human', 'decrease', 'low-throughput', 'To assess the impact of S. salivarius-dependent inhibition on PPARγ target genes, we quantified by RT-qPCR the expression of Angptl4 and I-FABP (intestinal fatty acid binding protein).The expression of these two well-characterized PPARγ-regulated genes were strongly reduced by S. salivarius supernatant in the presence of the PPARγ-specific ligand, rosiglitazone.', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay', '25946041');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3827', 'human', 'decrease', 'low-throughput', 'To assess the impact of S. salivarius-dependent inhibition on PPARγ target genes, we quantified by RT-qPCR the expression of Angptl4 and I-FABP (intestinal fatty acid binding protein).The expression of these two well-characterized PPARγ-regulated genes were strongly reduced by S. salivarius supernatant in the presence of the PPARγ-specific ligand, rosiglitazone.', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay', '25946041');
