INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3837', 'human', 'decrease', 'low-throughput', 'Incubation with LGG significantly decreased the concentration of IL-8 compared with the control, but no other significant effects were observed for LGG or its genomic DNA isolate.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment,Supplementation of metabolite', 'RT-PCR', '21178864');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3839', 'human', 'increase', 'low-throughput', 'To examine how C. difficile induces indole production, the expression of the tryptophanase gene (tnaA) in the E. coli strains was measured by quantitative real-time PCR. E. coli strains exposed to C. difficile stationary phase supernatant expressed significantly (P   0.0025) higher tnaA levels ( 4-fold) than when cultured alone (Fig. 4A). The increased expression of tnaA in the presence of the stationary-phase culture supernatant suggested that C. difficile likely induces indole at the level of transcription.', 'in vitro bacterial culture、in vitro bacterial culture', 'RT-PCR', '30944877');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3840', 'human', 'increase', 'low-throughput', 'To examine how C. difficile induces indole production, the expression of the tryptophanase gene (tnaA) in the E. coli strains was measured by quantitative real-time PCR. E. coli strains exposed to C. difficile stationary phase supernatant expressed significantly (P   0.0025) higher tnaA levels ( 4-fold) than when cultured alone (Fig. 4A). The increased expression of tnaA in the presence of the stationary-phase culture supernatant suggested that C. difficile likely induces indole at the level of transcription.', 'in vitro bacterial culture、in vitro bacterial culture', 'RT-PCR', '30944877');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3845', 'human', 'decrease', 'low-throughput', 'We examined the effects of UV-killed F. prausnitzii, bacterial fractions,supernatants, or sterile medium on IL-8 secretion in Caco-2 cells,with or without IL-1 stimulation (SI Materials and Methods and Fig. 3A). Either UV-killed F. prausnitzii, membrane extracts, or cytoplasmic extracts, but not DNA or sterile medium, induce low levels of IL-8 secretion. UV-killed F. prausnitzii, bacterial fractions,and sterile medium did not inhibit IL-8 secretion induced by IL-1,compared with negative control. In contrast, supernatant from F.prausnitzii cultures significantly reduces IL-8 secretion induced by IL-1.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3846', 'human', 'decrease', 'low-throughput', 'We examined the effects of UV-killed F. prausnitzii, bacterial fractions,supernatants, or sterile medium on IL-8 secretion in Caco-2 cells,with or without IL-1 stimulation (SI Materials and Methods and Fig. 3A). Either UV-killed F. prausnitzii, membrane extracts, or cytoplasmic extracts, but not DNA or sterile medium, induce low levels of IL-8 secretion. UV-killed F. prausnitzii, bacterial fractions,and sterile medium did not inhibit IL-8 secretion induced by IL-1,compared with negative control. In contrast, supernatant from F.prausnitzii cultures significantly reduces IL-8 secretion induced by IL-1.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3847', 'human', 'decrease', 'low-throughput', 'In vitro peripheral blood mononuclear cell stimulation by F. prausnitzii led to significantly lower IL-12 and IFN-γ production levels and higher secretion of IL-10.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('3848', 'human', 'decrease', 'low-throughput', 'In vitro peripheral blood mononuclear cell stimulation by F. prausnitzii led to significantly lower IL-12 and IFN-γ production levels and higher secretion of IL-10.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
