INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4128', 'human', 'decrease', 'low-throughput', 'Using a publically available database (GSE75214) 25, we found that the expression of host glycosyltransferases, such as MGTA4A and MGAT4B, was significantly impaired in UC patients compared to normal controls (Fig. 4a). The expression of IL22RA2 (also known as IL-22 binding protein (IL-22BP), a soluble IL-22 receptor that blocks IL-22 signaling, was markedly up-regulated in patients with UC, while IL-22 expression was not affected (Fig. 4a and Extended Data Fig. 7a).', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,qPCR', '32066975');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4129', 'human', 'decrease', 'low-throughput', 'Using a publically available database (GSE75214) 25, we found that the expression of host glycosyltransferases, such as MGTA4A and MGAT4B, was significantly impaired in UC patients compared to normal controls (Fig. 4a). The expression of IL22RA2 (also known as IL-22 binding protein (IL-22BP), a soluble IL-22 receptor that blocks IL-22 signaling, was markedly up-regulated in patients with UC, while IL-22 expression was not affected (Fig. 4a and Extended Data Fig. 7a).', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,qPCR', '32066975');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4130', 'human', 'increase', 'low-throughput', 'Using a publically available database (GSE75214) 25, we found that the expression of host glycosyltransferases, such as MGTA4A and MGAT4B, was significantly impaired in UC patients compared to normal controls (Fig. 4a). The expression of IL22RA2 (also known as IL-22 binding protein (IL-22BP), a soluble IL-22 receptor that blocks IL-22 signaling, was markedly up-regulated in patients with UC, while IL-22 expression was not affected (Fig. 4a and Extended Data Fig. 7a).', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,qPCR', '32066975');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4230', 'mouse', 'decrease', 'low-throughput', 'Using human intestinal epithelial cells (IECs), we discovered that SCFAs, particularly butyrate, enhanced IEC barrier formation, induced IL10RA mRNA, IL-10RA protein, and transactivation through activated Stat3 and HDAC inhibition. Loss and gain of IL10RA expression directly correlates with IEC barrier formation and butyrate represses permeability-promoting claudin-2 (Cldn2) tight-junction protein expression through an IL-10RA-dependent mechanism. Our findings provide a novel mechanism by which microbial derived butyrate promotes barrier through IL-10RA-dependent repression of Cldn2.', 'cell culture', 'real-time PCR,qPCR,Western blot assay', '28893958');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4231', 'mouse', 'increase', 'low-throughput', 'Using human intestinal epithelial cells (IECs), we discovered that SCFAs, particularly butyrate, enhanced IEC barrier formation, induced IL10RA mRNA, IL-10RA protein, and transactivation through activated Stat3 and HDAC inhibition. Loss and gain of IL10RA expression directly correlates with IEC barrier formation and butyrate represses permeability-promoting claudin-2 (Cldn2) tight-junction protein expression through an IL-10RA-dependent mechanism. Our findings provide a novel mechanism by which microbial derived butyrate promotes barrier through IL-10RA-dependent repression of Cldn2.', 'cell culture', 'real-time PCR,qPCR,Western blot assay', '28893958');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4232', 'mouse', 'decrease', 'low-throughput', 'Using human intestinal epithelial cells (IECs), we discovered that SCFAs, particularly butyrate, enhanced IEC barrier formation, induced IL10RA mRNA, IL-10RA protein, and transactivation through activated Stat3 and HDAC inhibition. Loss and gain of IL10RA expression directly correlates with IEC barrier formation and butyrate represses permeability-promoting claudin-2 (Cldn2) tight-junction protein expression through an IL-10RA-dependent mechanism. Our findings provide a novel mechanism by which microbial derived butyrate promotes barrier through IL-10RA-dependent repression of Cldn2.', 'cell culture', 'real-time PCR,qPCR,Western blot assay', '28893958');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4243', 'mouse', 'decrease', 'low-throughput', 'Ratelimited enzymes in the process of TG synthesis of the DGAT1/2 mRNA level in the HFD group were signifificantly increased compared with the LFD group. The DGAT2 mRNA level in the HFD-CBM group decreased in the same range as the LFD group, whereas signifificant differences of the DGAT1 mRNA level were not found between the HFD group and the HFD-CBM group.', 'cell culture', 'Western blot assay,GC/MS Analysis, real-time PCR', '24166662');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4244', 'mouse', 'decrease', 'low-throughput', 'several candidate strains were screened to find some probiotics as therapeutics using dextran sodium sulfate (DSS)-induced colitis in mice, and China Center for Type Culture Collection (CCTCC) M206119 strain led to an exacerbated phenotype of DSS-colitis mice. Expression of protective factors zonula occludens-1 and β-defensin 2 was downregulated after CCTCC M206119 treatment. There was an increase in the nuclear translocation of nuclear factor-κB in epithelial cells. Then, intestinal proinflammatory and anti-inflammatory cytokine responses were evaluated. Proinflammatory colonic cytokines [interleukin (IL)-1β, IL-6 and tumor necrosis factor-α] levels were clearly increased in CCTCC-M206119-treated animals, whereas anti-inflammatory colonic cytokine (IL-10) level was lowered compared with saline- or 5-ASA-treated DSS-colitis mice. Next, CCTCC M206119 strain was identified as Lactobacillus crispatus, so it was concluded that not all lactobacilli strains have beneficial effects on intestinal inflammation and that Lactobacillus crispatus (L. crispatus) CCTCC M206119 is involved in exacerbation of intestinal inflammation in DSS-colitis mice.', 'cell culture', 'RT-PCR,HPLC analysis', '22654425');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4245', 'mouse', 'decrease', 'low-throughput', 'several candidate strains were screened to find some probiotics as therapeutics using dextran sodium sulfate (DSS)-induced colitis in mice, and China Center for Type Culture Collection (CCTCC) M206119 strain led to an exacerbated phenotype of DSS-colitis mice. Expression of protective factors zonula occludens-1 and β-defensin 2 was downregulated after CCTCC M206119 treatment. There was an increase in the nuclear translocation of nuclear factor-κB in epithelial cells. Then, intestinal proinflammatory and anti-inflammatory cytokine responses were evaluated. Proinflammatory colonic cytokines [interleukin (IL)-1β, IL-6 and tumor necrosis factor-α] levels were clearly increased in CCTCC-M206119-treated animals, whereas anti-inflammatory colonic cytokine (IL-10) level was lowered compared with saline- or 5-ASA-treated DSS-colitis mice. Next, CCTCC M206119 strain was identified as Lactobacillus crispatus, so it was concluded that not all lactobacilli strains have beneficial effects on intestinal inflammation and that Lactobacillus crispatus (L. crispatus) CCTCC M206119 is involved in exacerbation of intestinal inflammation in DSS-colitis mice.', 'cell culture', 'RT-PCR,HPLC analysis', '22654425');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4246', 'mouse', 'increase', 'low-throughput', 'several candidate strains were screened to find some probiotics as therapeutics using dextran sodium sulfate (DSS)-induced colitis in mice, and China Center for Type Culture Collection (CCTCC) M206119 strain led to an exacerbated phenotype of DSS-colitis mice. Expression of protective factors zonula occludens-1 and β-defensin 2 was downregulated after CCTCC M206119 treatment. There was an increase in the nuclear translocation of nuclear factor-κB in epithelial cells. Then, intestinal proinflammatory and anti-inflammatory cytokine responses were evaluated. Proinflammatory colonic cytokines [interleukin (IL)-1β, IL-6 and tumor necrosis factor-α] levels were clearly increased in CCTCC-M206119-treated animals, whereas anti-inflammatory colonic cytokine (IL-10) level was lowered compared with saline- or 5-ASA-treated DSS-colitis mice. Next, CCTCC M206119 strain was identified as Lactobacillus crispatus, so it was concluded that not all lactobacilli strains have beneficial effects on intestinal inflammation and that Lactobacillus crispatus (L. crispatus) CCTCC M206119 is involved in exacerbation of intestinal inflammation in DSS-colitis mice.', 'cell culture', 'RT-PCR,HPLC analysis', '22654425');
