INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4248', 'mouse', 'increase', 'low-throughput', 'several candidate strains were screened to find some probiotics as therapeutics using dextran sodium sulfate (DSS)-induced colitis in mice, and China Center for Type Culture Collection (CCTCC) M206119 strain led to an exacerbated phenotype of DSS-colitis mice. Expression of protective factors zonula occludens-1 and β-defensin 2 was downregulated after CCTCC M206119 treatment. There was an increase in the nuclear translocation of nuclear factor-κB in epithelial cells. Then, intestinal proinflammatory and anti-inflammatory cytokine responses were evaluated. Proinflammatory colonic cytokines [interleukin (IL)-1β, IL-6 and tumor necrosis factor-α] levels were clearly increased in CCTCC-M206119-treated animals, whereas anti-inflammatory colonic cytokine (IL-10) level was lowered compared with saline- or 5-ASA-treated DSS-colitis mice. Next, CCTCC M206119 strain was identified as Lactobacillus crispatus, so it was concluded that not all lactobacilli strains have beneficial effects on intestinal inflammation and that Lactobacillus crispatus (L. crispatus) CCTCC M206119 is involved in exacerbation of intestinal inflammation in DSS-colitis mice.', 'cell culture', 'RT-PCR,HPLC analysis', '22654425');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4253', 'mouse', 'decrease', 'low-throughput', 'We extended our study to human samples to determine the effect of bile acids on CXCL16 mRNA expression of human liver sinusoidal endothelial cells. Similar to the mouse study, primary bile acids CDCA and TCA induced CXCL16 mRNA expression in SK-HEP1 cells (Fig. 5H). Next, the correlation between bile acids and CXCL16 expression was tested in nontumor liver tissues from HCC or cholangiocarcinoma patients of the Thailand Initiative for Genomics and Expression Research in Liver Cancer (TIGER-LC) cohort (34). Primary bile acid CDCA levels correlated with CXCL16 expression (Fig. 5I), whereas inverse correlation was seen for the secondary bile acid glycolithocholate (GLCA) (fig. S6I). The primary/secondary ratio was associated with CXCL16 increase (fig. S6J), indicating that the opposing effect of bile acids on CXCL16 expression also exists in humans.', 'cell culture', 'real-time PCR', '29798856');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4254', 'mouse', 'decrease', 'low-throughput', 'In summary,this study showed that it is butyrate, in stead of other substances produced by F.prausnitzii,inhibiting HDAC1 to activate Foxp3 and block the IL-6/STAT3/IL-17 pathway,thus regulating Th17/Treg cells and exerting an anti-inflammatory effect in IBD animal models.', 'cell culture', 'GC/MS analysis', '29796620');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4255', 'mouse', 'decrease', 'low-throughput', 'In summary,this study showed that it is butyrate, in stead of other substances produced by F.prausnitzii,inhibiting HDAC1 to activate Foxp3 and block the IL-6/STAT3/IL-17 pathway,thus regulating Th17/Treg cells and exerting an anti-inflammatory effect in IBD animal models.', 'cell culture', 'GC/MS analysis', '29796620');
