INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4350', 'mouse', 'increase', 'low-throughput', 'The main metabolites produced by B. thetaiotaomicron in the GIT were acetate (up to 6 mM) and propionate (up to 2 mM) (Figure 1D). We evaluated the effects of these bacterial metabolites on the amount of KLF4 protein produced by the mucus producing cell line HT29-MTX [31]. The amount of KLF4 protein was higher in the presence than in the absence of acetate (10 and 20 mM) (Figure 3A)whereas propionate (5 and 10 mM) and butyrate (1 and 5 mM) had no effect (Figure 3B, C).', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4352', 'mouse', 'increase', 'low-throughput', 'The amount of KLF4 protein, a transcription factor involved in goblet cell terminal differentiation [30], was higher in Bt-2d and Bt-30d than GF rats (Figure 2D). Also, muc2, muc4, c1galt1 and b4galt4 mRNAs, encoding proteins involved in mucin synthesis and glycosylation, were significantly more abundant in Bt-2d and Bt-30d rats than in GF rats(Table 1). The klf4 mRNA level was higher in Bt-2d, but not in Bt-30d, than in controls (Table 1).', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4353', 'mouse', 'increase', 'low-throughput', 'The amount of KLF4 protein, a transcription factor involved in goblet cell terminal differentiation [30], was higher in Bt-2d and Bt-30d than GF rats (Figure 2D). Also, muc2, muc4, c1galt1 and b4galt4 mRNAs, encoding proteins involved in mucin synthesis and glycosylation, were significantly more abundant in Bt-2d and Bt-30d rats than in GF rats(Table 1). The klf4 mRNA level was higher in Bt-2d, but not in Bt-30d, than in controls (Table 1).', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4354', 'mouse', 'increase', 'low-throughput', 'The amount of KLF4 protein, a transcription factor involved in goblet cell terminal differentiation [30], was higher in Bt-2d and Bt-30d than GF rats (Figure 2D). Also, muc2, muc4, c1galt1 and b4galt4 mRNAs, encoding proteins involved in mucin synthesis and glycosylation, were significantly more abundant in Bt-2d and Bt-30d rats than in GF rats(Table 1). The klf4 mRNA level was higher in Bt-2d, but not in Bt-30d, than in controls (Table 1).', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
