INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4356', 'mouse', 'increase', 'low-throughput', 'We observed an increase in the expression of the sialyltransferase st3gal4.', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4357', 'mouse', 'increase', 'low-throughput', 'We first checked  in vitro  that  B. thetaiotaomicron produced acetate and propionate and that  F. prausnitzii consumed acetate and produced butyrate (Figure 4A). When both bacteria were grown together, butyrate was produced rather than acetate. The butyrate production by F. prausnitzii as higher in the presence than absence of B. thetaiotaomicron  (10.9 ± 0.3 mM versus 7.8 ± 0.5 mM) suggesting that  F. prausnitzii  synthesized butyrate from the acetate produced by  B. thetaiotaomicron .', 'cell culture', 'Western blot assay,real-time qPC,immunohistochemisty assay', '23692866');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4358', 'mouse', 'increase', 'low-throughput', 'In fact,miR-21 was reportedly induced by pathogenic microbes such as Helicobacter pylori, Salmonella Typhimurium, and Mycobacterium species, leading to excessive immune responses (24, 25). Neither LPS nor P3CSK4 acted in a dose-dependent manner, suggesting that cellular mechanisms suppress the excessive induction of miR-21-5p.', 'cell culture', 'RT-qPCR,Western blot assay', '28760826');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4359', 'mouse', 'increase', 'low-throughput', 'In fact,miR-21 was reportedly induced by pathogenic microbes such as Helicobacter pylori, Salmonella Typhimurium, and Mycobacterium species, leading to excessive immune responses (24, 25). Neither LPS nor P3CSK4 acted in a dose-dependent manner, suggesting that cellular mechanisms suppress the excessive induction of miR-21-5p.', 'cell culture', 'RT-qPCR,Western blot assay', '28760826');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4360', 'mouse', 'increase', 'low-throughput', 'In fact,miR-21 was reportedly induced by pathogenic microbes such as Helicobacter pylori, Salmonella Typhimurium, and Mycobacterium species, leading to excessive immune responses (24, 25). Neither LPS nor P3CSK4 acted in a dose-dependent manner, suggesting that cellular mechanisms suppress the excessive induction of miR-21-5p.', 'cell culture', 'RT-qPCR,Western blot assay', '28760826');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4421', 'mouse', 'decrease', 'low-throughput', 'C. butyricum suppresses the expression of MMP-9 in asthmatic mice.', 'cell culture', 'ELISA', '28122397');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4422', 'mouse', 'decrease', 'low-throughput', 'A recent study suggests that for an OVA-sensitized/ challenged mouse, oral L. rhamnosus GG (LGG) can not only reduce lung resistance and pulmonary inflam mation, but also suppress the expression of T helper 2 (Th2) cytokines, MMP-9 and OVA-specific IgE.16 Sim ilarly, oral administration of C. butyricum to asthmatic mice is effective in reducing allergic airway inflamma tion and remodelling in our study.', 'cell culture', 'ELISA', '28122397');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4423', 'mouse', 'decrease', 'low-throughput', 'Both INF-γ(Fig. S2E, Supplementary Information) and IL-10 (Fig. S2F,I, Supplementary Information) in the PC group were decreased compared with the counterparts of the NC group. They increased in the groups that received C. butyricum orally except for BALF IL-10 in the Tre group.', 'cell culture', 'ELISA', '28122397');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4424', 'mouse', 'decrease', 'low-throughput', 'Compared with the NC group, IgE (Fig. 4A) and IgG1(Fig. 4B) were signifificantly elevated in the PC group (P < 0.001). However, they decreased dramatically in the Pre and Tre groups, especially the level of IgG1 in the Tre group.', 'cell culture', 'ELISA', '28122397');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4462', 'mouse', 'increase', 'low-throughput', 'The largest amounts of IL-10 were induced by the Fp strains, Eubacterium hallii (Eh) L2-7 and Megamonas rupellenesis (Mr) Mag1B. In addition, these strains induced the largest amounts of TNF-α and IL-6. The Fp strains, Eh L2-7 and Eubacterium rectale (Er) A1-86 also induced relatively large amounts of IL-1β. Lactobacillus plantarum (Lp) WCFS1, Mr Mag1B and Eh L2-7 were among the most potent inducers of IL-12p70, whereas the Fp strains were among the poorer inducers (Fig. 1). Surprisingly, Ruminococcus bromii (Rb) L2-63, Ch 82-B and Clostridium xylanovorans (Cx) Lac1D induced small or undetectable amounts of some cytokines (Fig. 1) despite having effectively induced hDCs maturation (Supplementary Fig. S1). The five Fp strains had very different cytokines profiles. The highest IL-10 producer was strain A2-165, strains L2-6 and M21/2 induced high amounts of IL-10 but also IL-12p70 while strains S3L/3 and HTF-F induced intermediate to low amounts of both cytokines.', 'cell culture', 'null', '26725514');
