INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4469', 'mouse', 'increase', 'low-throughput', 'The largest amounts of IL-10 were induced by the Fp strains, Eubacterium hallii (Eh) L2-7 and Megamonas rupellenesis (Mr) Mag1B. In addition, these strains induced the largest amounts of TNF-α and IL-6. The Fp strains, Eh L2-7 and Eubacterium rectale (Er) A1-86 also induced relatively large amounts of IL-1β. Lactobacillus plantarum (Lp) WCFS1, Mr Mag1B and Eh L2-7 were among the most potent inducers of IL-12p70, whereas the Fp strains were among the poorer inducers (Fig. 1). Surprisingly, Ruminococcus bromii (Rb) L2-63, Ch 82-B and Clostridium xylanovorans (Cx) Lac1D induced small or undetectable amounts of some cytokines (Fig. 1) despite having effectively induced hDCs maturation (Supplementary Fig. S1). The five Fp strains had very different cytokines profiles. The highest IL-10 producer was strain A2-165, strains L2-6 and M21/2 induced high amounts of IL-10 but also IL-12p70 while strains S3L/3 and HTF-F induced intermediate to low amounts of both cytokines.', 'cell culture', 'null', '26725514');
