INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4493', 'mouse', 'increase', 'low-throughput', 'The metalloprotease GelE, produced by commensal strains of E faecalis, contributes to development of chronic intestinal inflflammation in mice that are susceptible to intestinal inflflammation by impairing epithelial barrier in tegrity.', 'cell culture', 'LC-MS/MS analysis', '21699778');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4496', 'mouse', 'increase', 'low-throughput', 'Our results suggest this is due to GF colonocytes adapting to their suboptimal energetic state by undergoing autophagy. Reduced ATP levels activate AMPK, which, in turn, activates p27 to prevent apoptosis and induce autophagy in these cells.', 'cell culture', 'RT-qPCR,Western blot assay,HPLC analysis,LC/MS analysis', '21531334');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4497', 'mouse', 'increase', 'low-throughput', 'we performed transcriptome profiling and quantitative mass spectrometry on freshly isolated colonocytes from GF and CONV-R mice. For the transcriptome profiling experiments, we identified 624 genes that are upregulated and 813 genes are downregulated in GF compared to CONV-R. All of these gene expression changes are statistically significant with false discovery rates below 0.01. The entire data set and statistical values are included as Table S1. Our transcriptome data includes genes previously shown to be regulated by microbiota in various tissues of zebrafish, mice, and piglets. For example, Angpt14/Fiaf is upregulated in GF compared to CONV while Gpx2, ApoB, Aqp4, and Pla2g4c are downregulated.', 'cell culture', 'RT-qPCR,Western blot assay,HPLC analysis,LC/MS analysis', '21531334');
