INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4509', 'mouse', 'decrease', 'low-throughput', 'mRNA levels of genes encod ing proteins involved in lipogenesis, including Srebf1, Scd1 and Fasn,  were lower in white adipose tissue of HFD mice gavaged with live  B. thetaiotaomicron, whereas expression of genes involved in lipolysis  and fatty acid oxidation, including Adrb3, Pnpla2, Cpt2, Acox1 and  Ppargc1a was higher (Fig. 4k). In addition, expression of markers of  inflammation, Cd68, Ccl2, Il6 and Il1b, in adipose tissue of HFD mice  was attenuated in response to gavage with live B. thetaiotaomicron,  indicating an improved inflammatory status.', 'cell culture', 'RT-qPCR,Western blot assay,HPLC analysis,LC/MS analysis', '28628112');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4510', 'mouse', 'decrease', 'low-throughput', 'mRNA levels of genes encod ing proteins involved in lipogenesis, including Srebf1, Scd1 and Fasn,  were lower in white adipose tissue of HFD mice gavaged with live  B. thetaiotaomicron, whereas expression of genes involved in lipolysis  and fatty acid oxidation, including Adrb3, Pnpla2, Cpt2, Acox1 and  Ppargc1a was higher (Fig. 4k). In addition, expression of markers of  inflammation, Cd68, Ccl2, Il6 and Il1b, in adipose tissue of HFD mice  was attenuated in response to gavage with live B. thetaiotaomicron,  indicating an improved inflammatory status.', 'cell culture', 'real-time PCR,Western blot assay,HPLC analysis,LC/MS analysis,GC/MS analysis', '28628112');
