INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4529', 'mouse', 'increase', 'low-throughput', 'The expression of tight junction protein ZO-1, Occludin and Claudin-1 was measured by western blot. As shown in Fig. 2A, the expression of Claudin-1 was significantly decreased in irinotecan treated mice compared with control group. However, ZO-1 and Oc cludin expression was not modified by irinotecan. Interestingly, EcN significantly restored the decreased Claudin-1 expression.', 'cell culture', 'Western blot assay', '31173781');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4531', 'mouse', 'increase', 'low-throughput', 'Live B. dentium-monoassociated mice exhibited increased colonic expression of goblet cell markers Krüppel-like factor 4 (Klf4), Trefoil factor 3 (Tff3), Relm-β, Muc2, and several glycosyltransferases compared to both heat-killed B. dentium and germfree counterparts.', 'cell culture', 'real-time qPCR', '31213556');
