INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4576', 'mouse', 'decrease', 'low-throughput', 'Indole, the most prevalent metabolite of tryptophan, is produced by a wide range of bacterial species, including those belonging to the genera Escherichia, Bacteroides, and ClostridiumProlonged exposure to indole inhibits ATP production and thus GLP-1 secretion.', 'cell culture', 'null', '25456122');
