INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4588', 'mouse', 'increase', 'low-throughput', 'NaB corrected the HFD-induced gut microbiota imbalance in mice, while it considerably elevated the abundances of the beneficial bacteria Christensenellaceae, Blautia and Lactobacillus . These bacteria can produce butyric acid in what seems like a virtuous circle. And butyrate restored HFD induced intestinal mucosa damage, increased the expression of ZO-1 in small intestine, further decreased the levels of gut endotoxin in serum and liver compared with HF group.', 'control experiment', 'ELISA�?real-time PCR', '28104981');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4589', 'mouse', 'increase', 'low-throughput', 'NaB corrected the HFD-induced gut microbiota imbalance in mice, while it considerably elevated the abundances of the beneficial bacteria Christensenellaceae, Blautia and Lactobacillus . These bacteria can produce butyric acid in what seems like a virtuous circle. And butyrate restored HFD induced intestinal mucosa damage, increased the expression of ZO-1 in small intestine, further decreased the levels of gut endotoxin in serum and liver compared with HF group.', 'control experiment', 'ELISA�?real-time PCR', '28104981');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4590', 'mouse', 'increase', 'low-throughput', 'NaB corrected the HFD-induced gut microbiota imbalance in mice, while it considerably elevated the abundances of the beneficial bacteria Christensenellaceae, Blautia and Lactobacillus . These bacteria can produce butyric acid in what seems like a virtuous circle. And butyrate restored HFD induced intestinal mucosa damage, increased the expression of ZO-1 in small intestine, further decreased the levels of gut endotoxin in serum and liver compared with HF group.', 'control experiment', 'ELISA�?real-time PCR', '28104981');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4597', 'mouse', 'increase', 'low-throughput', 'The helminth Nippostrongylus brasiliensis and a tritrichomonad protist both secreted succinate as a metabolite. In vivo sensing of the tritrichomonad required SUCNR1, whereas N. brasiliensis was SUCNR1 independent. These findings define a paradigm wherein tuft cells monitor microbial metabolites to initiate type 2 immunity and suggest the existence of other sensing pathways triggering the response to helminths.', 'Cell culture,in vitro bacterial culture', 'RT-qPCR,RNA-seq,', '30021144');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4598', 'mouse', 'increase', 'low-throughput', 'The helminth Nippostrongylus brasiliensis and a tritrichomonad protist both secreted succinate as a metabolite. In vivo sensing of the tritrichomonad required SUCNR1, whereas N. brasiliensis was SUCNR1 independent. These findings define a paradigm wherein tuft cells monitor microbial metabolites to initiate type 2 immunity and suggest the existence of other sensing pathways triggering the response to helminths.', 'Cell culture,in vitro bacterial culture', 'RT-qPCR,RNA-seq,', '30021144');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4600', 'mouse', 'increase', 'low-throughput', 'Our study shows that MAM from F. prausnitzii can restore the intestinal barrier structure and function in DM conditions via the regulation of the tight junction pathway and ZO-1 expression.Collectively, our data reveal that MAM protein upregulates ZO-1 expression in intestinal epithelial cells.', 'control experiment,cell culture', '16S high-throughput sequencing,qRT-PCR,Western blot assay', '31503404');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4612', 'mouse', 'decrease', 'low-throughput', 'Faecalibacterium prausnitzii produces butyrate to decrease c-Myc-related metabolism and Th17 differentiation by inhibiting histone deacetylase 3.', 'control experiment,in vitro bacterial culture', 'qPCR,real-time PCR,Western blot assay,GC-MS analysis', '30809639');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4614', 'mouse', 'increase', 'low-throughput', 'F. prausnitzii, B. longum and F. prausnitzii supernatant clearly facilitated the induction of IL-10 and TGF-β1, while induced relatively mild production of IL-12p70 in both cellular and animal models. The F. prausnitzii, B. longum and supernatant differed in their capacity to induce T-bet, GATA-3 and ROR-γt mRNA expression in human PBMCs (both bacterial strains inhibited the expression of ROR-γt while supernatant inhibited the T-bet and GATA-3). However, all of them induced the Foxp3 and Treg production and ameliorated the TNBS-induced colitis. In addition, F. prausnitzii supernatant exhibited the supreme anti-inflammatory capacity.', 'control experiment,in vitro bacterial culture', 'ELISA,real-time qPCR', '23643066');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4615', 'mouse', 'increase', 'low-throughput', 'F. prausnitzii, B. longum and F. prausnitzii supernatant clearly facilitated the induction of IL-10 and TGF-β1, while induced relatively mild production of IL-12p70 in both cellular and animal models. The F. prausnitzii, B. longum and supernatant differed in their capacity to induce T-bet, GATA-3 and ROR-γt mRNA expression in human PBMCs (both bacterial strains inhibited the expression of ROR-γt while supernatant inhibited the T-bet and GATA-3). However, all of them induced the Foxp3 and Treg production and ameliorated the TNBS-induced colitis. In addition, F. prausnitzii supernatant exhibited the supreme anti-inflammatory capacity.', 'control experiment,in vitro bacterial culture', 'ELISA,real-time qPCR', '23643066');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4619', 'mouse', 'decrease', 'low-throughput', 'Colonic cDNA concentrations of IL-1b and TNF-a were significantly down regulated in DSS-treated E. durans-fed mice but not in control or DSS-treated L.delbrueckii- fed mice.', 'in vitro bacterial culture,control experiment', 'qPCR,real-time PCR', '17349085');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4620', 'mouse', 'decrease', 'low-throughput', 'Colonic cDNA concentrations of IL-1b and TNF-a were significantly down regulated in DSS-treated E. durans-fed mice but not in control or DSS-treated L.delbrueckii- fed mice.', 'in vitro bacterial culture,control experiment', 'qPCR,real-time PCR', '17349085');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4623', 'mouse', 'increase', 'low-throughput', 'Lactobacilli Induce IL-22 via Iald.', 'control experiment,in vitro bacterial culture', '16S rRNA sequence,qPCR ,HPLC-HRMS Analysis', '23973224');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4631', 'mouse', 'decrease', 'low-throughput', 'The mRNA levels of  -SMA and TIMP-1 were revealed to be markedly elevated in the livers of the MCD diet-fed mice, and these high expressions were normalized by LcS intervention (Fig. 3B). These data suggest LcS intervention to have suppressed HSC activation and liver fibrosis.', 'control experiment,in vitro bacterial culture', 'real-time RT-qPCR', '24113768');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4632', 'mouse', 'decrease', 'low-throughput', 'The mRNA levels of  -SMA and TIMP-1 were revealed to be markedly elevated in the livers of the MCD diet-fed mice, and these high expressions were normalized by LcS intervention (Fig. 3B). These data suggest LcS intervention to have suppressed HSC activation and liver fibrosis.', 'control experiment,in vitro bacterial culture', 'real-time RT-qPCR', '24113768');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4633', 'mouse', 'decrease', 'low-throughput', 'To investigate the molecular mechanisms underlying the resistance to NASH development conferred by LcS intervention, the mRNA expression levels of lipogenic enzyme genes such as SREBP-1c and FAS, oxidation enzyme genes, CPT-1, and CD36 were examined by quantitative real-time PCR. While MCD diet feeding signifi- cantly elevated the expression of SREBP-1c but not that of FAS, LcS intervention suppressed these mRNA levels compared with the MCD diet alone (Fig. 4A).', 'control experiment,in vitro bacterial culture', 'real-time RT-qPCR', '24113768');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4634', 'mouse', 'decrease', 'low-throughput', 'To investigate the molecular mechanisms underlying the resistance to NASH development conferred by LcS intervention, the mRNA expression levels of lipogenic enzyme genes such as SREBP-1c and FAS, oxidation enzyme genes, CPT-1, and CD36 were examined by quantitative real-time PCR. While MCD diet feeding signifi- cantly elevated the expression of SREBP-1c but not that of FAS, LcS intervention suppressed these mRNA levels compared with the MCD diet alone (Fig. 4A).', 'control experiment,in vitro bacterial culture', 'real-time RT-qPCR', '24113768');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4635', 'mouse', 'increase', 'low-throughput', 'To this end, DCA feeding was performed in HFD-fed mice treated with vancomycin (Figure 2(a,b)). Intriguingly, DCA feeding alone in VCM-treated HFD-fed mice was observed to induce substantial proinflammatory macrophages (iNOS+) infiltration and increase the expression of multiple proinflammatory factors (IL-6, TNF-α, IL-1β, iNOS) in the colon tissue (Figure 2(c–f)), mimicking the inflammatory intestinal damage induced by HFD.', 'control experiment', '16S rDNA sequence,LC-MS/MS analysis,RT-PCR,Western blot assay', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4636', 'mouse', 'increase', 'low-throughput', 'To this end, DCA feeding was performed in HFD-fed mice treated with vancomycin (Figure 2(a,b)). Intriguingly, DCA feeding alone in VCM-treated HFD-fed mice was observed to induce substantial proinflammatory macrophages (iNOS+) infiltration and increase the expression of multiple proinflammatory factors (IL-6, TNF-α, IL-1β, iNOS) in the colon tissue (Figure 2(c–f)), mimicking the inflammatory intestinal damage induced by HFD.', 'control experiment', '16S rDNA sequence,LC-MS/MS analysis,RT-PCR,Western blot assay', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4637', 'mouse', 'increase', 'low-throughput', 'To this end, DCA feeding was performed in HFD-fed mice treated with vancomycin (Figure 2(a,b)). Intriguingly, DCA feeding alone in VCM-treated HFD-fed mice was observed to induce substantial proinflammatory macrophages (iNOS+) infiltration and increase the expression of multiple proinflammatory factors (IL-6, TNF-α, IL-1β, iNOS) in the colon tissue (Figure 2(c–f)), mimicking the inflammatory intestinal damage induced by HFD.', 'control experiment', '16S rDNA sequence,LC-MS/MS analysis,RT-PCR,Western blot assay', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4638', 'mouse', 'increase', 'low-throughput', 'To this end, DCA feeding was performed in HFD-fed mice treated with vancomycin (Figure 2(a,b)). Intriguingly, DCA feeding alone in VCM-treated HFD-fed mice was observed to induce substantial proinflammatory macrophages (iNOS+) infiltration and increase the expression of multiple proinflammatory factors (IL-6, TNF-α, IL-1β, iNOS) in the colon tissue (Figure 2(c–f)), mimicking the inflammatory intestinal damage induced by HFD.', 'control experiment', '16S rDNA sequence,LC-MS/MS analysis,RT-PCR,Western blot assay', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4639', 'mouse', 'increase', 'low-throughput', 'Indeed, DCA stimulation could induce potent increase of mRNA expression level of M2-mAchR in macrophages, and selective inhibition of M2-mAchR significantly reduced theproduction of TNF-α, NO and IL-6 triggered by DCA (Figure 4(d,e) and Supplementary Figure 4c).', 'control experiment', '16S rDNA sequence,LC-MS/MS analysis,RT-PCR,Western blot assay', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4640', 'mouse', 'increase', 'low-throughput', 'Toll-like receptor 2 (TLR2) is up-regulated upon DCA stimulation and involved in DCA-induced macrophage polarization.', 'control experiment', 'RT-PCR,Western blot assay,ChIP', '33006494');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4652', 'mouse', 'increase', 'low-throughput', 'When the complex carbohydrates of breast milk interact with B. fragilis, it produces short-chain fatty acids (SCFAs). We know from animal studies that SCFAs interacting with G-protein-coupled receptors can stimulate regulatory T cells via the GPR 43 receptor to activate the original cells and to produce IL-10, which inhibits inflammation [44].', 'null', 'null', '32229728');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4653', 'mouse', 'increase', 'low-throughput', 'To determine the functional impact of B dentium colonization on enterochromaffin-produced serotonin, we assessed 5-HT concentrations by immunostaining, qPCR,and LC-MS/MS. Increased numbers of 5-HT–positive cells were observed in both the ileum and colon of B dentium mono-associated mice relative to germ-free and heat-killed B dentium–treated mice (Figure 3A and B). Increases in 5-HT were observed in enteroendocrine cells directly above enteric neurons (Figure 3C). Tph-1 is the rate limiting enzyme for 5-HT production in enterochromaffin cells. The results of the immunostaining were corroborated by the significant increase in Tph-1 expression in both the ileum and colon of B dentium mono-associated mice relative to germ-free and heat-killed B dentium–treated mice(Figure 3D). Increased Tph-1 gene expression also was accompanied by significantly increased 5-HT concentrations in the intestinal lumen and feces of mice, as measured by LC-MS/MS (Figure 3E).', 'in vitro bacterial culture', 'immunostaining, qPCR，LC-MS/MS analysis', '32795610');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4654', 'mouse', 'increase', 'low-throughput', 'We found that expression of the colonic 5-HT receptors 2a and 4 (HTR2A and HTR4) were increased significantly in B dentium mono-associated mice (Figure 7A).', 'in vitro bacterial culture', 'qPCR，immunostaining', '32795610');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4655', 'mouse', 'increase', 'low-throughput', 'We found that expression of the colonic 5-HT receptors 2a and 4 (HTR2A and HTR4) were increased significantly in B dentium mono-associated mice (Figure 7A).', 'in vitro bacterial culture', 'qPCR，immunostaining', '32795610');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4683', 'mouse', 'increase', 'low-throughput', 'Analysis of the expression of mRNAs of three TJ proteins (ZO-1, claudin-1, and occludin) indicated greater expression in the Sham Group than in the three other groups (P < 0.05), and greater expression in the two treatment groups than in the SAP + IAH Group (P < 0.05; Figures 4A,B,D). In addition, expression of claudin-2, MMP9 was lower in the Sham Group than in the three other groups (P < 0.05) and lower in the two treatment groups than in the SAP + IAH Group (P < 0.05; Figures 4C,E).', 'in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay', '33192557');
