INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4701', 'mouse', 'increase', 'low-throughput', 'SLC5A8 and GPR43 expressions in butyrate‑treated CRC cells were quantified (Fig. 5B and C for SLC5A8 and GPR43, respectively). In comparison with untreated cells, the NaB‑treated SW480 cells only presented higher GPR43 (P<0.05), but the NaB‑treated SW620 cells expressed the most SLC5A8 (P<0.01) and GPR43 (P<0.05).', 'cell culture,control experiment', 'GC/MS analysis', '33101496');
