INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4816', 'mouse', 'increase', 'low-throughput', 'IAld has recently been identified as an aryl hydrocarbon receptor (AHR) ligand.', 'cell culture,in vitro bacterial culture,control experiment', 'RT-PCR,Western blot assay,HPLC analysis', '29454749');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4822', 'mouse', 'decrease', 'low-throughput', 'In summary, our results clearly demonstrate that different E. faecalis strains differentially induce colitis in monoassociated IL-10-/- mice and that severe E. faecalis-induced colitis resulted in decreased Alix/AIP1 protein expression as well as ERK1/2 phosphorylation. Functional studies revealed no effect of Alix/AIP1 on bacteria- and EGF-mediated effects on the epithelium. The 13 differentially regulated proteins might be ofinterest aspotentialmarkers for severeintestinalinflammation.', 'in vitro bacterial culture,cell culture', 'qPCR,ELISA,Western blot assay', '19166300');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4823', 'mouse', 'decrease', 'low-throughput', 'In summary, our results clearly demonstrate that different E. faecalis strains differentially induce colitis in monoassociated IL-10-/- mice and that severe E. faecalis-induced colitis resulted in decreased Alix/AIP1 protein expression as well as ERK1/2 phosphorylation. Functional studies revealed no effect of Alix/AIP1 on bacteria- and EGF-mediated effects on the epithelium. The 13 differentially regulated proteins might be ofinterest aspotentialmarkers for severeintestinalinflammation.', 'in vitro bacterial culture,cell culture', 'qPCR,ELISA,Western blot assay', '19166300');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('4824', 'mouse', 'decrease', 'low-throughput', 'In summary, our results clearly demonstrate that different E. faecalis strains differentially induce colitis in monoassociated IL-10-/- mice and that severe E. faecalis-induced colitis resulted in decreased Alix/AIP1 protein expression as well as ERK1/2 phosphorylation. Functional studies revealed no effect of Alix/AIP1 on bacteria- and EGF-mediated effects on the epithelium. The 13 differentially regulated proteins might be ofinterest aspotentialmarkers for severeintestinalinflammation.', 'in vitro bacterial culture,cell culture', 'qPCR,ELISA,Western blot assay', '19166300');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5026', 'mouse', 'increase', 'low-throughput', 'Human and murine pregnancy were associated with reduced intestinal FXR signaling, with lower FGF19/15 and resultant increased hepatic bile acid synthesis. Terminal ileal ASBT protein was reduced in murine pregnancy. Cecal bile acid conjugation was reduced in pregnancy because of elevated bile salt hydrolase‐producing Bacteroidetes. CA supplementation induced intestinal FXR signaling, which was not abrogated by pregnancy, with strikingly similar changes to the microbiota and metabonome as identified in pregnancy. Conclusion: The altered intestinal microbiota of pregnancy enhance bile acid deconjugation, reducing ileal bile acid uptake and lowering FXR induction in enterocytes. This exacerbates the effects mediated by reduced bile acid uptake transporters in pregnancy. Thus, in pregnant women and mice, there is reduced FGF19/15‐mediated hepatic repression of hepatic bile acid synthesis, resulting in hypercholanemia.', 'in vivo experiment', 'RT-PCR,16S rRNA sequence', '30983011');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5031', 'mouse', 'decrease', 'low-throughput', 'Inhibitory activity of angiotensin I-converting enzyme (ACE) was examined with (�?-epigallocatechin gallate (EGCG) metabolites produced by intestinal bacteria, together with tea catechins. All of the metabolites showed ACE inhibitory activities.', 'in vitro bacterial culture,in vivo infection experiment', 'HPLC analysis', '26323573');
