INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5040', 'mouse', 'decrease', 'low-throughput', 'Inflammatory responses were induced in GPR41(-/-), GPR43(-/-), and C57BL6 (control) mice by administration of ethanol; 2, 4, 6 trinitrobenzene sulfonic-acid (TNBS); or infection with Citrobacter rodentium. We examined the effects of C rodentium infection on control mice fed SCFAs and/or given injections of antibodies that delay the immune response. We also studied the kinetics of cytokine and chemokine production, leukocyte recruitment, intestinal permeability, and T-cell responses. Primary colon epithelial cells were isolated from GPR41(-/-), GPR43(-/-), and control mice; signaling pathways regulated by SCFAs were identified using immunohistochemical, enzyme-linked immunosorbent assay, and flow cytometry analyses.', 'in vivo experiment,cell culture', 'qPCR', '23665276');
