INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5049', 'mouse', 'increase', 'low-throughput', 'B. infantis and MO decreased hepatic CYP7A1 and induced Sult2a1, Sult2a2, and Sult2a3 suggesting reduced BA synthesis and increased detoxification. Furthermore, B. infantis and MO increased ileal BA membrane receptor TGR5-regulated signaling. Together, via BA-regulated signaling, synbiotics B. infantis and MO have their unique and combined effects in reversing NASH.', 'in vitro bacterial culture', 'qPCR,LC/MS analysis', '15640190');
