INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5090', 'mouse', 'increase', 'low-throughput', 'Therefore, in this study, we investigated the effects of KetoA [10-oxo-12(Z)-octadecenoic acid]—a linoleic acid metabolite produced by gut lactic acid bacteria—on whole-body energy metabolism and found that dietary intake of KetoA could enhance energy expenditure in mice, thereby protecting mice from diet-induced obesity.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment', 'RT-PCR,Western blot assay', '28754711');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5091', 'mouse', 'increase', 'low-throughput', 'Ucp1 expression levels were also observed to have increased after administration of KetoA.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment', 'RT-PCR,Western blot assay', '28754711');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5092', 'mouse', 'increase', 'low-throughput', 'We also confirmed that administration of KetoA induced not only Ucp1, but other genes that are related to BAT function, such as b3AR, Pgc1a , Cpt1b , and Tbx1  in BAT and inguinal WAT of WT\nmice.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment', 'RT-PCR,Western blot assay', '28754711');
