INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5097', 'mouse', 'increase', 'low-throughput', 'Therefore, in this study, we investigated the effects of KetoA [10-oxo-12(Z)-octadecenoic acid]—a linoleic acid metabolite produced by gut lactic acid bacteria—on whole-body energy metabolism and found that dietary intake of KetoA could enhance energy expenditure in mice, thereby protecting mice from diet-induced obesity.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment', 'RT-PCR,Western blot assay', '28754711');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5098', 'mouse', 'increase', 'low-throughput', 'Ucp1 expression levels were also observed to have increased after administration of KetoA.', 'cell culture,in vitro bacterial culture,in vivo infection experiment,control experiment', 'RT-PCR,Western blot assay', '28754711');
