INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5115', 'mouse', 'increase', 'high-throughput', 'To analyze the effect of microbiota and SCFA on the main regulators of gene expression in the intestinal epithelium, we focused on the effects of these conditions on transcription factor expression (Fig. 3A). We observed that major overlap of effects on transcription factor expression was evident after treatment with Akkermansia muciniphila and propionate and butyrate. However, butyrate additionally affected expression of specific transcription factors in the intestinal epithelium of organoids not affected by other conditions (Fig. 3A). The expression of a very small numberof transcription factors was affected specifically by exposure of organoids to acetate or propionate (Fig. 3A).', 'cell culture,in vitro bacterial culture,control experiment', 'null', '25118238');
