INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5334', 'mouse', 'increase', 'low-throughput', 'Forty-eight hours after TNBS instillation,colonic proinflammatory TNF and IL-12 cytokines and anti-inflammatory IL-10 were quantified by ELISA (SI Materials and Methods and Fig. 5). Compared with the no-colitis control group,TNF-α and IL-12 levels were increased, whereas IL-10 levels were barely modified. In the two TNBS groups treated with either F.prausnitzii or its supernatant, the secretion of TNF and IL-12 was significantly lower than in the colitis control group. Interestingly, IL-10 secretion was induced in the colon of mice treated with F.prausnitzii or its supernatant.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5335', 'mouse', 'decrease', 'low-throughput', 'Forty-eight hours after TNBS instillation,colonic proinflammatory TNF and IL-12 cytokines and anti-inflammatory IL-10 were quantified by ELISA (SI Materials and Methods and Fig. 5). Compared with the no-colitis control group,TNF-α and IL-12 levels were increased, whereas IL-10 levels were barely modified. In the two TNBS groups treated with either F.prausnitzii or its supernatant, the secretion of TNF and IL-12 was significantly lower than in the colitis control group. Interestingly, IL-10 secretion was induced in the colon of mice treated with F.prausnitzii or its supernatant.', 'cell culture、in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '18936492');
