INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5338', 'mouse', 'decrease', 'low-throughput', 'Altered substrate oxidation and fecal fat excretion in LHFD-fed GF mice is linked to decreased hepatic Cyp7a1 and Nr1h4 expression.', 'control experiment', 'RT-PCR�?6S rRNA sequence', '27900259');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5339', 'mouse', 'decrease', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5340', 'mouse', 'decrease', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5341', 'mouse', 'increase', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5342', 'mouse', 'decrease', 'low-throughput', 'IFN-TNF-induced an increase in FD-4 permeability;however, the pretreatment of HYA and linoleic acid signififcantly suppressed this increase (Fig. 2C). In contrast, the pretreatment of HYB did not alter IFN-TNF-induced changes in TER and FD-4 permeability. As shown in Fig. 2D,IFN-TNF-induced a marked increase in the secretion of IL-8, which is a major pro-inflammatory cytokine. However,the pretreatment of HYA significantly suppressed IL-8 secretion.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5343', 'mouse', 'increase', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5344', 'mouse', 'increase', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5345', 'mouse', 'increase', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5346', 'mouse', 'decrease', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5347', 'mouse', 'decrease', 'low-throughput', 'The pretreatment of HYA suppressed IFN-induced up-regulation of TNFR2 (but not TNFR1), and it subsequently decreased the ratio of phospho-INF-B p65 expression induced by cytokines (Fig. 3, B and C). In contrast, pretreatment of HYB did not show the same inhibitory effects as HYA.', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5348', 'mouse', 'increase', 'low-throughput', 'It was noteworthy that the pretreatment of HYA augmented the mRNA expression of GPR40 and GPR43 but not GPR120, PPAR, and GPR41 in Caco-2 cells (Fig. 4A). However, the pretreatment of HYB did not up-regulate GPR40 and GPR43 expression (Fig. 4A).', 'cell culture、control experiment', 'Western blot assay、RT-PCR', '25505251');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5363', 'mouse', 'increase', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5364', 'mouse', 'decrease', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5365', 'mouse', 'increase', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5366', 'mouse', 'increase', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5367', 'mouse', 'increase', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5368', 'mouse', 'increase', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 'in vitro bacterial culture、in vivo infection experiment、control experiment', 'qPCR', '25065623');
