INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5585', 'mouse', 'increase', 'low-throughput', 'Taken together, these data demonstrate bacterial-intrinsic phytate metabolism and provoke the hypothesis that breakdown of phytate by microbiota promotes intestinal HDAC activity.', 'in vitro bacterial culture,control experiment', 'qPCR', '32731255');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5586', 'mouse', 'decrease', 'low-throughput', 'Further, colonization of germ-free (GF) mice with butyrate producing bacteria,Faecalibacterium prausnitzii, inhibited IEC-intrinsic HDAC activity.', 'in vitro bacterial culture,control experiment', 'qPCR', '32731255');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5587', 'mouse', 'increase', 'low-throughput', 'CNV mice exhibited significantly higher IP3 in both the intestinal lumen (Fig. 1e) and colonic IECs (Fig. 1f), supporting that microbiota promote increased IP3. To assess the effect of IP3 on epithelial HDAC3 activity, HDAC3 was purified by immunoprecipitation from IECs and incubated with IP3. IP3 increased endogenous HDAC3 activity (Fig. 1g), supporting that IP3 directly activates HDAC3 in IECs.', 'in vitro bacterial culture,control experiment', 'qPCR', '32731255');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5588', 'mouse', 'increase', 'low-throughput', 'Although less potent than IP3, IP4 also increased HDAC activity in IECs (Extended Data Fig. 5f), suggesting that other inositol phosphates simultaneously generated by phytate metabolism may provide synergistic effects.', 'in vitro bacterial culture,control experiment', 'qPCR', '32731255');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5589', 'mouse', 'increase', 'low-throughput', 'Glutamate, the agonist of NMDAR and a major excitatory neurotransmitter in the mammalian central nervous system (CNS) [6], is intracellularly located and extensively distributed in the brain.', 'null', 'null', '32290475');
