INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5598', 'mouse', 'increase', 'low-throughput', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 'cell culture,control experiment,in vitro bacterial culture', '16S rDNA sequence,qPCR', '32668198');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5599', 'mouse', 'increase', 'low-throughput', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 'cell culture,control experiment,in vitro bacterial culture', '16S rDNA sequence,qPCR', '32668198');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5601', 'mouse', 'decrease', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 'in vitro bacterial culture,control experiment', '16S rRNA sequence,HPLC analysis', '32078445');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5602', 'mouse', 'decrease', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 'in vitro bacterial culture,control experiment', '16S rRNA sequence,HPLC analysis', '32078445');
