INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5604', 'mouse', 'increase', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 'in vitro bacterial culture,control experiment', '16S rRNA sequence,HPLC analysis', '32078445');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5617', 'mouse', 'increase', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 'control experiment', '16S rRNA sequence,LC/MS analysis', '33256731');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5618', 'mouse', 'increase', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 'control experiment', '16S rRNA sequence,LC/MS analysis', '33256731');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5619', 'mouse', 'increase', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 'control experiment', '16S rRNA sequence,LC/MS analysis', '33256731');
INSERT INTO `gut_microbiota_gene_change_results` (`index`, `host_type`, `Alteration`, `throughput`, `description`, `experimental_method`, `sequencing_technology`, `Evidence`) VALUES ('5632', 'mouse', 'increase', 'low-throughput', 'Interestingly, in the same mice, indole induced a dramatic increase of the expression of the adrenomedullary Pnmt gene, which is involved in catecholamine biosynthesis.', 'control experiment', 'HPLC analysis,ELISA,RT-PCR', '32569990');
