INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3071, 'human', 'Orientin', 'This strain, which was able to cleave the C-glycoside of orientin to produce luteolin and generate some other metabolites.', 24316522);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3072, 'human', 'Bile acid', 'Deoxycholic acid (DCA) and lithocholic acid (LCA) are secondary bile acids that are generated in the gut by bacterial transformation of primary bile acids, cholic acid(CA), and chenodeoxycholic acid (CDCA), respectively.The proposed pathway for this transformation by Clostridium scindens VPI 12708.', 23836456);
