INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3099, 'human', 'Isoquercitrin', 'Schneider et al. (1999) isolated strains of Eubacterium ramulus from human feces that are capable of degrading quercetin-3-glucoside to 3,4-dihydroxyphenylacetic acid (3,4-DIOHA), butyrate, and acetate.Phloroglucinol was formed as an intermediate.', 10648107);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3100, 'human', 'Isoquercitrin', 'In addition,the identity of fermentation products 3,4-dihydroxyphenylacetic acid, formed from quercetin-3-glucosdide, or taxifolin, 3-(3,4 dihydroxyphenyl)propionic acid, formed from luteolin or eriodictyol, and 4-hydroxyphenylacetic acid, formed from kaempferol, were confirmed by LC-MS/MS. The most intensive ion peaks in the mass spectra of these compounds are listed in Table 2.', 10648107);
