INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3107, 'human', 'Quercetin', 'Luteolin-5-glucoside, diosmetin-7rutinoside, naringenin-7-neohesperidoside, (+)-catechin, and (�?-epicatechin were not degraded. Cell extracts of E. ramulus contained α- and β-D-glucosidase activities, but were devoid of α-L-rhamnosidase activity.', 10648107);
