INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3109, 'human', 'null', 'Indoxyl-sulfate (Beta(SE) = -2.74(0.24), P = 8.8x10-29),p-cresyl-sulfate (-1.99(0.24), P = 4.6x10-16), and phenylacetylglutamine (-2.73(0.25),P = 1.2x10-25) were significantly and negatively associated with eGFR after adjusting for age, sex, body mass index (BMI), metabolite batch, type 2 diabetes, family relatedness and multiple testing using Bonferroni correction (Table 2).', 26241311);
