INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3112, 'human', 'null', 'we demonstrated that GPR41 and GPR43 were modestly expressed in human distal renal tubules and col lecting tubules. We also found that SCFAs (acetate, propionate, and butyrate) inhibited TNF-a induced expression of a pro inflammatory factor, MCP-1, in HRCEs by reducing p38 and JNK phosphorylation via GPR41 and/or GPR43 activation involving Gi/o, particularly Gb/g. To the best of our knowledge, this is the first report to describe the anti-inflammatory effects of SCFAs through a GPR41/43/Gb/g pathway in renal parenchymal cells.', 28322790);
