INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3138, 'human', 'Hesperetin dihydrochalcone', 'C.orbiscindens was not able to convert hesperetindihydrochalcone 4�?â-D-glucoside within a period of 43 h, whereas the aglycon was cleaved by this species. C. orbiscindens formed 0.18 mM 3-(3-hydroxy-4-methoxyphenyl)propionic acid from 0.26 mM hesperetin dihydrochalcone within 23 h of incubation.', 15740074);
