INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3156, 'human', 'null', 'As Erk is a ‘downstream�?signaling component of TLR pathways, we investigated whether succinate alone or in combination with TLR ligands was able to induce proinflammatory cytokine production by human DCs. Succinate alone did not have any great effect on a variety of cytokines and chemokines produced by activated human DCs. However, succinate augmented the expression of TNF and IL-1b by iMoDCs when used in combination with the TLR3 ligand poly(I:C) or the TLR7 agonist imiquimod.', 18820681);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3157, 'human', 'null', 'As Erk is a ‘downstream�?signaling component of TLR pathways, we investigated whether succinate alone or in combination with TLR ligands was able to induce proinflammatory cytokine production by human DCs. Succinate alone did not have any great effect on a variety of cytokines and chemokines produced by activated human DCs. However, succinate augmented the expression of TNF and IL-1b by iMoDCs when used in combination with the TLR3 ligand poly(I:C) or the TLR7 agonist imiquimod.', 18820681);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3158, 'human', 'null', 'Succinate alone was able to induce phosphorylation of Erk1/2 in human iMoDCs,in agreement with the reported activity of succinate on GPR91 transfectants. Polyinosinic-polycytidylic acid (poly(I:C)) alone showed a very modest activation of this signaling pathway, but when both poly(I:C) and succinate were present, Erk1/2 phosphorylation was synergistically induced.', 18820681);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3159, 'human', 'null', 'Succinate alone was able to induce phosphorylation of Erk1/2 in human iMoDCs,in agreement with the reported activity of succinate on GPR91 transfectants. Polyinosinic-polycytidylic acid (poly(I:C)) alone showed a very modest activation of this signaling pathway, but when both poly(I:C) and succinate were present, Erk1/2 phosphorylation was synergistically induced.', 18820681);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3160, 'human', 'null', 'In addition, activation of iMoDCs with poly(I:C) or imiquimod in the presence of succinate induced substantial enhancement of the expression of CCL2 mRNA and CXCL8 mRNA (data not shown). Therefore, we concluded that succinate potentiates the production and secretion of proinflam matory mediators by iMoDCs when the cells are stimulated through some TLRs.', 18820681);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3161, 'human', 'null', 'In addition, activation of iMoDCs with poly(I:C) or imiquimod in the presence of succinate induced substantial enhancement of the expression of CCL2 mRNA and CXCL8 mRNA (data not shown). Therefore, we concluded that succinate potentiates the production and secretion of proinflam matory mediators by iMoDCs when the cells are stimulated through some TLRs.', 18820681);
