INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3186, 'human', 'Daidzein', 'One culture produced the metabolites dihydrodaidzein and O-desmethylangolensin, another produced dihydrodaidzein and equol. From the latter, a stable and transferable mixed culture transforming daidzein into equol was obtained. Molecular fingerprinting analysis (denaturing gradient gel electrophoresis) showed the presence of four bacterial species of which only the first three strains could be brought into pure culture. These strains were identified as Lactobacillus mucosae EPI2, Enterococcus faecium EPI1 and Finegoldia magna EPI3, and did not produce equol in pure culture. The fourth species was tentatively identified as Veillonella sp strain EP.', 15578160);
