INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3200, 'human', 'Cianidanol', 'The conversion of both epicatechin and catechin resulted in the formation of metabolite M1 subsequently characterized as 1�?3,4‐dihydroxyphenyl)�?�?2,4,6‐trihydroxyphenyl)propan�?‐ol (3,4‐diHPP�?‐ol, structure in Fig. 3). In accordance with the initial conversion of the catechins, 3,4‐diHPP�?‐ol was formed more rapidly from catechin than from epicatechin.', 21457417);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3201, 'human', '(-)-Epicatechin', 'The conversion of both epicatechin and catechin resulted in the formation of metabolite M1 subsequently characterized as 1�?3,4‐dihydroxyphenyl)�?�?2,4,6‐trihydroxyphenyl)propan�?‐ol (3,4‐diHPP�?‐ol, structure in Fig. 3). In accordance with the initial conversion of the catechins, 3,4‐diHPP�?‐ol was formed more rapidly from catechin than from epicatechin.', 21457417);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3202, 'human', '1-(3,4-Dihydroxyphenyl)-3-(2,4,6-trihydroxyphenyl)-2-propanol', 'Two metabolites, M2 and M3, were first detected after 4 and 6 h, respectively, of incubation with F. plautii aK2. The concentration of M2 was maximal after 6 h and slightly decreased afterwards. The concentration of M3 increased rapidly until 8 h followed by a minor increase during further incubation. Characterization of the observed metabolites by MS analyses and taking literature data into account led to the assignment of M2 as 5�?3,4‐dihydroxyphenyl)‐γ‐valerolactone (3,4‐diHPVL) and M3 as 4‐hydroxy�?�?3,4‐dihydroxyphenyl)valeric acid (4‐H�?,4‐diHPVA) (structures in Fig. 3).', 21457417);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3203, 'human', '1-(3,4-Dihydroxyphenyl)-3-(2,4,6-trihydroxyphenyl)-2-propanol', 'Two metabolites, M2 and M3, were first detected after 4 and 6 h, respectively, of incubation with F. plautii aK2. The concentration of M2 was maximal after 6 h and slightly decreased afterwards. The concentration of M3 increased rapidly until 8 h followed by a minor increase during further incubation. Characterization of the observed metabolites by MS analyses and taking literature data into account led to the assignment of M2 as 5�?3,4‐dihydroxyphenyl)‐γ‐valerolactone (3,4‐diHPVL) and M3 as 4‐hydroxy�?�?3,4‐dihydroxyphenyl)valeric acid (4‐H�?,4‐diHPVA) (structures in Fig. 3).', 21457417);
