INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3249, 'human', 'Daidzein', 'Daidzein was converted to equol by strain DZE.', 18670101);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3250, 'human', 'Succinate', 'PY broth tube tests indicated that strains YIT 12067T and YIT 12068 grew well only in PY medium supplemented with succinate. HPLC analysis showed that succinate was quantitatively converted to propionate. These results indicate that succinate decarboxylation stimulated the growth of strains YIT 12067T and YIT 12068.', 22081579);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3251, 'human', 'Succinate', 'PY broth tube tests indicated that strains YIT 12067T and YIT 12068 grew well only in PY medium supplemented with succinate. HPLC analysis showed that succinate was quantitatively converted to propionate. These results indicate that succinate decarboxylation stimulated the growth of strains YIT 12067T and YIT 12068.', 22081579);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3252, 'human', 'Daidzein', 'In this study, we isolated a human intestinal bacterium capable of transforming daidzein to equol and genistein to 5-hydroxy-equol.', 19139227);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3253, 'human', 'Genistein', 'In this study, we isolated a human intestinal bacterium capable of transforming daidzein to equol and genistein to 5-hydroxy-equol.', 19139227);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3254, 'human', 'Genistein 7-O-glucoside', 'Genistein-7-O-glucoside was partially transformed by way of genistein to the product 2-(4-hydroxyphenyl)-propionic acid.', 11959436);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3255, 'human', 'Genistein', 'Genistein was completely degraded by E. ramulus via 6\'-hydroxy-O-desmethylangolensin to 2-(4-hydroxyphenyl)-propionic acid.', 11959436);
