INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3340, 'human', 'null', 'We cultured fecal specimens from healthy young adults in media containing defatted flaxseeds and detected END from the culture supernatant. Following selection through successive subcultures of the fecal microbiota with defatted flaxseeds as the only carbon source, we obtained a bacterial consortium, designated as END-49, which contained the smallest number of bacterial types still capable of metabolizing defatted flaxseeds to produce END.', 20398397);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3341, 'human', 'null', 'We provide direct evidence that IS activates EGFR and downstream MAPK signaling, which stimulates AhR−ARNT nuclear translocation and results in enhanced OAT1 expression and function in the kidney.', 31341083);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3342, 'human', 'null', 'We provide direct evidence that IS activates EGFR and downstream MAPK signaling, which stimulates AhR−ARNT nuclear translocation and results in enhanced OAT1 expression and function in the kidney.', 31341083);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3343, 'human', 'Choline', 'Interestingly, we found that plasma TMAO was positively correlated with serum sCD14 and sCD163 levels which are biomarkers of monocyte activation and macrophage inflammation and have been reported to be associated with carotid artery atherosclerosis and CVD risk in HIV infected individuals.', 29912352);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3344, 'human', 'Choline', 'Interestingly, we found that plasma TMAO was positively correlated with serum sCD14 and sCD163 levels which are biomarkers of monocyte activation and macrophage inflammation and have been reported to be associated with carotid artery atherosclerosis and CVD risk in HIV infected individuals.', 29912352);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3345, 'human', 'null', 'For the PBMC assay, although all the strains tend to increase the production of IL-10 cytokine, only four strains were able to induce statistically significant increase production of this cytokine .The two most performing strains (A2-165 and 4543) belong to the phylogroup II, group B.', 28713353);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3346, 'human', 'null', 'For the PBMC assay, although all the strains tend to increase the production of IL-10 cytokine, only four strains were able to induce statistically significant increase production of this cytokine .The two most performing strains (A2-165 and 4543) belong to the phylogroup II, group B.', 28713353);
