INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3358, 'human', 'Choline', 'Further, in vitro conversion of choline to TMA was checked in presence/absence of trigonelline and in presence of trigonelline there was significant inhibition of growth of C. freundii and hence significantly reduced levels of TMA was estimated.', 29980011);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3359, 'human', 'Trimethylamine', 'Butin presence oftrigonelline, significantly reduced levels of TMAO was estimated which was, of course, due to flavin monooxygenase (FMO3) enzyme inhibition by trigonelline.', 29980011);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3360, 'human', 'Quercetin', 'The degradation of the flavonol quercetin and the flavone luteolin by Eubacterium ramulus, a strict anaerobe of the human intestinal tract, was studied. Resting cells converted these flavonoids to 3,4-dihydroxyphenylacetic acid and 3-(3,4-dihydroxyphenyl)propionic acid, respectively.', 11722907);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3361, 'human', 'Luteolin', 'The degradation of the flavonol quercetin and the flavone luteolin by Eubacterium ramulus, a strict anaerobe of the human intestinal tract, was studied. Resting cells converted these flavonoids to 3,4-dihydroxyphenylacetic acid and 3-(3,4-dihydroxyphenyl)propionic acid, respectively.', 11722907);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3362, 'human', 'Hesperidin', 'The data herein presented demonstrated that B. pseudocatenulatum can hydrolyze certain rutinose-conjugated polyphenols, such as hesperidin, thus releasing the aglycone form. Therefore, B. pseudocatenulatum may potentially contribute to the bioavailability of this class of molecules.', 25875120);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3363, 'human', 'Hesperidin', 'The data herein presented demonstrated that B. pseudocatenulatum can hydrolyze certain rutinose-conjugated polyphenols, such as hesperidin, thus releasing the aglycone form. Therefore, B. pseudocatenulatum may potentially contribute to the bioavailability of this class of molecules.', 25875120);
