INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3366, 'human', 'Hesperidin', 'The data herein presented demonstrated that B. pseudocatenulatum can hydrolyze certain rutinose-conjugated polyphenols, such as hesperidin, thus releasing the aglycone form. Therefore, B. pseudocatenulatum may potentially contribute to the bioavailability of this class of molecules.', 25875120);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3367, 'human', 'null', 'In the present study, we focused on the impact of SCFAs and the role of PPAR-γin intestinal ANGPTL4 expression. Here, we show that ANGPTL4 expression can be regulated by SCFAs both in vitro and in vivo, with butyrate being the most efficient activator.', 23518684);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3368, 'human', 'null', 'Faecalibacterium prausnitzii is one of the most abundant bacteria in the human gut ecosystem and it is an important supplier of butyrate to the colonic epithelium.', 22357539);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3369, 'human', 'Cianidanol', 'When (+)-catechin was anaerobically incubated with Eg. sp. CAT-1, and the incubation mixture was analyzed by LC/MS, two metabolites, designated CAM1 and CAM2, were detected.', 23207778);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3370, 'human', 'Cianidanol', 'When (+)-catechin was anaerobically incubated with Eg. sp. CAT-1, and the incubation mixture was analyzed by LC/MS, two metabolites, designated CAM1 and CAM2, were detected.', 23207778);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3371, 'human', 'null', 'On the other hand, we confirmed in both ex vivo epithelial cultures and whole mucosal samples that the inflammatory milieu, in particular the presence of TNFɑ, does impact butyrate uptake and oxidation. Indeed, TNFɑ may be responsible for the downregulation of butyrate transporters in the human intestinal epithelium observed in patient biopsies, and that may result in decreased butyrate consumption.', 31211831);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3372, 'human', 'Exopolysaccharides', 'In conclusion, this study revealed that relevant changes in the populations of some major anaerobic intestinal bacterial groups as well as noticeable shifts in SCFA and lactic acid production can result from the presence of bifidobacterial EPS. Microbial population dynamics correlated well and supported the SCFA and lactic acid variations detected. EPS could reach the colon by two different ways: they could be either synthesized by probiotics in food products or by intestinal bacteria in the intestinal environment, thus contributing to the modulation of the intestinal microbiota.', 19735956);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3373, 'human', 'null', 'These results suggest that selected probiotic strains of Bifidobacterium can be used to speed up the release of daidzein, improving its bioavailability for absorption by colonic mucosa and/or biotransformation to S-equol by other intestinal microorganisms.', 18820905);
