INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3385, 'human', 'null', 'We also show that E. lenta further metabolizes the dopamine produced by L-dopa decarboxylation using a distinctly microbial reaction, catechol dehydroxylation.', 31196984);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3386, 'human', 'null', 'Figure 3 shows the metabolites produced by pure cultures of two propionate-producing LUB strains (P-LUB; V. ratti and P.avidum), two butyrate-producing LUB strains (B-LUB; E. hallii and E. limosum); and one LUB SRB strain (D. piger) in YCFA  medium supplemented with lactose, DL-lactate, L-lactate or glucose as a sole carbon source. H2 production and  OD measurements of these pure cultures are shown in Supplementary Figs S3 and S4, respectively.', 28894218);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3387, 'human', 'null', 'Figure 3 shows the metabolites produced by pure cultures of two propionate-producing LUB strains (P-LUB; V. ratti and P.avidum), two butyrate-producing LUB strains (B-LUB; E. hallii and E. limosum); and one LUB SRB strain (D. piger) in YCFA  medium supplemented with lactose, DL-lactate, L-lactate or glucose as a sole carbon source. H2 production and  OD measurements of these pure cultures are shown in Supplementary Figs S3 and S4, respectively.', 28894218);
