INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3404, 'human', 'null', 'Finally, a total of seven metabolites were detected and tentatively identified, such as the demethylation metabolite (M1), deoxidation metabolites (M3, M7) and hydrolysis at the C-28 oligosaccharide metabolites (M5,M6), which were first discovered in this experiment. The results indicate that hydrolysis, demethylation, dehydroxylation, and acetylation were the major metabolic pathways of PDin vitro. Additionally, four bacterial strains from human feces including Enterococcus sp.41, Bacillus sp.46, Escherichia sp.49A and Escherichia sp.64 were detected and further identified with 16S rRNA gene sequencing due to their relatively strong metabolic capacity', 27222071);
