INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3408, 'human', 'Daidzein', 'We isolated nine strains capable of metabolizing isoflavones to equol from human faeces. Seven of these strains could metabolize daidzein via dihydrodaidzein to equol, while the other two isolates could metabolize only dihydrodaidzein to equol.', 18450717);
