INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3439, 'human', 'null', 'Recently, we isolated a dihydrodaidzein (DHD)-producing Clostridium-like bacterium, strain TM-40, from human feces.', 25045313);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3440, 'human', 'DL-Alanine', 'For example, if R1 is a methyl group (-CH3), then the donor amino acid is an alanine, and the product of the oxidative deamination would be pyruvate, a central compounds of the intermediary metabolism.', 22325238);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3441, 'human', 'Glycine', 'For example when R2 is a hydrogen (thus the acceptor amino acid is a glycine) this product corresponds to acetyl-phosphate.', 22325238);
