INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3446, 'human', 'null', 'And yet, in Caco2 cells, indole still elicited a significant saturation of CYP1A1 expression (~15-fold, p < .001), while the remaining tryptophan metabolites elicited nonsaturable yet variable levels of CYP1A1 induction. 2-oxindole, indole-3-acetic acid, 3-methyl indole and kynurenic acid prompted significant CYP1A1 inducibility. The remaining tryptophan metabolites, however, failed to elicit significant induction.', 32783770);
