INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3481, 'human', 'null', 'Interleukin 8 was significantly increased in cell supernatants of 10 mM BUT treated enteroids as well as basolateral media (P < 0.05). Interleukin 18 was not significantly different in cell supernatant, however, there was a tendency for 10 mM BUT to increase expression (P = 0.08;Table 1). Interleukin 18, however was increased by 10 mM BUT treatment in basolateral media(P < 0.05).', 32240190);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3482, 'human', 'D-Glucose', 'B. theta was grown in minimal defined medium on glucose as sole carbon and energy sources, and spent culture medium was analyzed using 1D 1H NMR to detect the secreted metabolome and to identify any new secreted metabolites (see Fig. S1 in the supplemental material). We confirmed previous observations that the major secreted metabolic products were acetate, succinate, formate, and propionate, with small amounts of lactate. In addition, we were able to detect histidine, cysteine, cystine (Cys-Cys disulfide), glutathione, asparagine, and alanine (Fig. 1).', 32873608);
