INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3493, 'human', 'Levodopa', 'Here, we show that C. sporogenes deaminates levodopa, the main treatment in Parkinson’s disease, and identify the aromatic aminotransferase responsible for the initiation of the deamination pathway. The deaminate metabolite from levodopa, 3-(3,4-dihydroxyphenyl)propionic acid, elicits an inhibitory effect on ileal motility in an ex vivo model.', 33076930);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3494, 'human', '5-Hydroxytryptophan', '5-HTP was converted into two new unknown peaks (Additional File1: Fig. S2A, S2B), albeit to a much lesser extent compared to levodopa. Only the first peak could be detected and assigned by LC-MS as 5-hydroxyindole-3-lactic acid (5-HILA) by its predicted exact mass (Additional File 1:Fig. S2C).', 33076930);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3495, 'human', 'Tryptophan', 'Tryptophan and tyrosine were converted to their intermediates ILA (indole-3-lactic acid) and 4-HPLA (3-(4-hydroxyphenyl)lactic acid), respectively, as previously shown [11].', 33076930);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3496, 'human', 'Tyrosine', 'Tryptophan and tyrosine were converted to their intermediates ILA (indole-3-lactic acid) and 4-HPLA (3-(4-hydroxyphenyl)lactic acid), respectively, as previously shown [11].', 33076930);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3497, 'human', 'Levodopa', 'Analogous to tryptophan and tyrosine, levodopa was no longer deaminated to DHPPA but to its intermediate product 3-(3,4-dihydroxy phenyl)lactic acid (DHPLA) (Fig. 1d, e). ', 33076930);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3498, 'human', 'null', 'The human ortholog HM74a is also a nicotinic acid receptor and likely has a similar role in anti-lipolysis.', 15929991);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3499, 'human', 'null', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3500, 'human', 'null', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
