INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3502, 'human', 'null', 'Both (D)- and (L)-OHB, but not acetoacetate or free acetone, elicited a Ca2 response in cells expressing HM74a but not HM74.', 15929991);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3503, 'human', 'null', 'Racemic (DL)-OHB also showed some degree of activity on all receptors; however, it was more potent on HM74a and its ortholog PUMA-G  than on HM74.', 15929991);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3504, 'human', 'Diosmetin 7-O-beta-D-glucopyranoside', 'A Gram-negative anaerobic bacterium, strain 4, capable of metabolizing diosmetin-7-O-glucoside was newly isolated.Its 16S rRNA sequence displayed 99% similarity with that of Escherichia. Then strain 4 was identified as a species of thegenus Escherichia and was named Escherichia sp. 4. Additionally,  an ultraperformance liquid chromatography/quadrupole-time-of-flight mass spectrometry  technique combined with Metabolynx software method was established to screenthe metabolites of diosmetin-7-O-glucoside.', 25382172);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3505, 'human', 'Diosmetin 7-O-beta-D-glucopyranoside', 'A Gram-negative anaerobic bacterium, strain 4, capable of metabolizing diosmetin-7-O-glucoside was newly isolated.Its 16S rRNA sequence displayed 99% similarity with that of Escherichia. Then strain 4 was identified as a species of thegenus Escherichia and was named Escherichia sp. 4. Additionally,  an ultraperformance liquid chromatography/quadrupole-time-of-flight mass spectrometry  technique combined with Metabolynx software method was established to screenthe metabolites of diosmetin-7-O-glucoside.', 25382172);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3506, 'human', 'null', 'We analyzed 50 colon adenomas from AA patients for both microsatellite instability (MSI) and the methylation status of SLC5A8 gene. This gene\'s product is involved in the transport of butyrate that has anti-proliferative properties through its effects on histone acetylation and gene expression. A proteomic analysis to check the expressed histones in adenoma and normal tissues was also performed.No association was found between SLC5A8 methylation and the MSI status. Also, there was no association between SLC5A8 methylation and the sex and age of the patients. However, there were more right sided adenomas with SLC5A8 methylation than the left sided ones. The proteomic analysis revealed distinct histone expression profiles between normal and adenoma tissues.SLC5A8 is highly methylated in AA colon adenomas which points to its potential use as a marker for early detection. The MSI rate is similar to that found in colon cancer tumors in AAs. These findings suggest that both processes stem from the same epigenetic and genetic events occurring at an early stage in colon carcinogenesis in AAs.', 21687703);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3507, 'human', 'null', 'We analyzed 50 colon adenomas from AA patients for both microsatellite instability (MSI) and the methylation status of SLC5A8 gene. This gene\'s product is involved in the transport of butyrate that has anti-proliferative properties through its effects on histone acetylation and gene expression. A proteomic analysis to check the expressed histones in adenoma and normal tissues was also performed.No association was found between SLC5A8 methylation and the MSI status. Also, there was no association between SLC5A8 methylation and the sex and age of the patients. However, there were more right sided adenomas with SLC5A8 methylation than the left sided ones. The proteomic analysis revealed distinct histone expression profiles between normal and adenoma tissues.SLC5A8 is highly methylated in AA colon adenomas which points to its potential use as a marker for early detection. The MSI rate is similar to that found in colon cancer tumors in AAs. These findings suggest that both processes stem from the same epigenetic and genetic events occurring at an early stage in colon carcinogenesis in AAs.', 21687703);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3508, 'human', 'null', 'We analyzed 50 colon adenomas from AA patients for both microsatellite instability (MSI) and the methylation status of SLC5A8 gene. This gene\'s product is involved in the transport of butyrate that has anti-proliferative properties through its effects on histone acetylation and gene expression. A proteomic analysis to check the expressed histones in adenoma and normal tissues was also performed.No association was found between SLC5A8 methylation and the MSI status. Also, there was no association between SLC5A8 methylation and the sex and age of the patients. However, there were more right sided adenomas with SLC5A8 methylation than the left sided ones. The proteomic analysis revealed distinct histone expression profiles between normal and adenoma tissues.SLC5A8 is highly methylated in AA colon adenomas which points to its potential use as a marker for early detection. The MSI rate is similar to that found in colon cancer tumors in AAs. These findings suggest that both processes stem from the same epigenetic and genetic events occurring at an early stage in colon carcinogenesis in AAs.', 21687703);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3509, 'human', 'null', 'In vitro cultivation of PD demonstrated its capacity to transform bile acids and production of succinate. Succinate supplementation in the diet decreased hyperglycemia in ob/ob mice via the activation of intestinal gluconeogenesis (IGN). Gavage with a mixture of LCA and UDCA reduced hyperlipidemia by activating the FXR pathway and repairing gut barrier integrity. Co-treatment with succinate and LCA/UDCA mirrored the benefits of LPD. The binding target of succinate was identified as fructose-1,6-bisphosphatase, the rate-limiting enzyme in IGN. The succinate and secondary bile acids produced by P. distasonis played key roles in the modulation of host metabolism.', 30605678);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3510, 'human', 'null', 'In vitro cultivation of PD demonstrated its capacity to transform bile acids and production of succinate. Succinate supplementation in the diet decreased hyperglycemia in ob/ob mice via the activation of intestinal gluconeogenesis (IGN). Gavage with a mixture of LCA and UDCA reduced hyperlipidemia by activating the FXR pathway and repairing gut barrier integrity. Co-treatment with succinate and LCA/UDCA mirrored the benefits of LPD. The binding target of succinate was identified as fructose-1,6-bisphosphatase, the rate-limiting enzyme in IGN. The succinate and secondary bile acids produced by P. distasonis played key roles in the modulation of host metabolism.', 30605678);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3516, 'human', 'Clindamycin', 'In the CDI chemostat model, clindamycin decreased valerate and deoxycholic acid concentrations and increased C difficile total viable counts (TVC) and valerate precursors, taurocholic acid, and succinate concentrations. After we stopped adding clindamycin, levels of bile acids and succinate recovered, whereas levels of valerate and valerate precursors did not. In the CDI chemostat model FMT increased valerate concentrations and decreased C difficile TVC (94% reduction), spore counts (86% reduction), and valerate precursor concentrations—concentrations of bile acids were unchanged.', 30025704);
