INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3520, 'human', 'null', 'In our study, we demonstrate that n-butyrate, a bacterial metabolite found in high abundance in the colon, regulates macrophage function through the inhibition of HDACs. n-Butyrate may behave as a microbial signal to inform the host immune system that the relative levels of n-butyrate–producing bacteria are within the desired range. In this model, HDACs act as sensors for n-butyrate, and their inhibition by high amounts of this metabolite causes intestinal macrophages to reduce production of proinflammatory mediators such as NO, IL-6, and IL-12.', 24390544);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3521, 'human', 'null', 'In our study, we demonstrate that n-butyrate, a bacterial metabolite found in high abundance in the colon, regulates macrophage function through the inhibition of HDACs. n-Butyrate may behave as a microbial signal to inform the host immune system that the relative levels of n-butyrate–producing bacteria are within the desired range. In this model, HDACs act as sensors for n-butyrate, and their inhibition by high amounts of this metabolite causes intestinal macrophages to reduce production of proinflammatory mediators such as NO, IL-6, and IL-12.', 24390544);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3522, 'human', 'null', 'In our study, we demonstrate that n-butyrate, a bacterial metabolite found in high abundance in the colon, regulates macrophage function through the inhibition of HDACs. n-Butyrate may behave as a microbial signal to inform the host immune system that the relative levels of n-butyrate–producing bacteria are within the desired range. In this model, HDACs act as sensors for n-butyrate, and their inhibition by high amounts of this metabolite causes intestinal macrophages to reduce production of proinflammatory mediators such as NO, IL-6, and IL-12.', 24390544);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3523, 'human', 'Resveratrol', 'In conclusion, we identified 3 microbial trans-resveratrol metabolites, 2 of which were previously unknown and we also identified 2 intestinal bacterial species that were previously not known to produce dihydroresveratrol. In addition, we showed that there can be pronounced interindividual differences in resveratrol conversion by human gut microbiota.', 23283496);
