INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3529, 'human', '1-((3,5-Dichloro)-2,6-dihydroxy-4-methoxyphenyl)-1-hexanone', 'DIF-3 induces proteolysis of cyclin D1 and c-Myc in HCT-116 cells via activation of GSK-3b.', 25913757);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3530, 'human', '1-((3,5-Dichloro)-2,6-dihydroxy-4-methoxyphenyl)-1-hexanone', 'The amount of TCF7L2 increased gradually over time in control cells, but it was markedly reduced by DIF-3 in a time and dose-dependent manner.', 25913757);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3531, 'human', '1-((3,5-Dichloro)-2,6-dihydroxy-4-methoxyphenyl)-1-hexanone', 'DIF-3 decreased the expression of cyclin D1 and cMyc to a level comparable to the reduction induced by DIF-1.', 25913757);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3532, 'human', '1-((3,5-Dichloro)-2,6-dihydroxy-4-methoxyphenyl)-1-hexanone', 'DIF-3 decreased the expression of cyclin D1 and cMyc to a level comparable to the reduction induced by DIF-1.', 25913757);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3533, 'human', 'null', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC3) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 30683619);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3534, 'human', 'null', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC4) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 30683619);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3535, 'human', 'null', 'Butyrate-induced antimicrobial activity was associated with a shift in macrophage metabolism, a reduction in mTOR kinase activity, increased LC3-associated host defense and anti-microbial peptide production in the absence of an increased inflammatory cytokine response. Butyrate drove this monocyte to macrophage differentiation program through histone deacetylase 3 (HDAC5) inhibition. Administration of butyrate induced antimicrobial activity in intestinal macrophages in vivo and increased resistance to enteropathogens.', 30683619);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3536, 'human', 'Xyloglucan Heptasaccharide', 'Commensal bifidobacteria colonize the human gastrointestinal tract and catabolize glycans that are impervious to host digestion. Accordingly, Bifidobacterium longum typically secretes acetate and lactate as fermentative end products. This study tested the hypothesis that B. longum utilizes cranberry-derived xyloglucans in a strain-dependent manner. Interestingly, the B. longum strain that efficiently utilizes cranberry xyloglucans secretes 2.0 to 2.5 mol of acetate-lactate. The 1.5 acetate:lactate ratio theoretical yield obtained in hexose fermentations shifts during xyloglucan metabolism. Accordingly, this metabolic shift is characterized by increased acetate and formate production at the expense of lactate. α-l-Arabinofuranosidase, an arabinan endo-1,5-α-l-arabinosidase, and a β-xylosidase with a carbohydrate substrate-binding protein and carbohydrate ABC transporter membrane proteins are upregulated (>2-fold change), which suggests carbon flux through this catabolic pathway. Finally, syntrophic interactions occurred with strains that utilize carbohydrate products derived from initial degradation from heterologous bacteria.', 28667113);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3537, 'human', 'Xyloglucan Heptasaccharide', 'Commensal bifidobacteria colonize the human gastrointestinal tract and catabolize glycans that are impervious to host digestion. Accordingly, Bifidobacterium longum typically secretes acetate and lactate as fermentative end products. This study tested the hypothesis that B. longum utilizes cranberry-derived xyloglucans in a strain-dependent manner. Interestingly, the B. longum strain that efficiently utilizes cranberry xyloglucans secretes 2.0 to 2.5 mol of acetate-lactate. The 1.5 acetate:lactate ratio theoretical yield obtained in hexose fermentations shifts during xyloglucan metabolism. Accordingly, this metabolic shift is characterized by increased acetate and formate production at the expense of lactate. α-l-Arabinofuranosidase, an arabinan endo-1,5-α-l-arabinosidase, and a β-xylosidase with a carbohydrate substrate-binding protein and carbohydrate ABC transporter membrane proteins are upregulated (>2-fold change), which suggests carbon flux through this catabolic pathway. Finally, syntrophic interactions occurred with strains that utilize carbohydrate products derived from initial degradation from heterologous bacteria.', 28667113);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3538, 'human', 'null', 'We have presented direct evidence that the gut bacterial genotoxin colibactin alkylates DNA in vivo. The ability of pks+ E. coli to generate DNA adducts in mammalian cells and in mice strengthens support for the involvement of colibactin in cancer development or progression since misrepaired mono- and cross-linked adducts may generate mutations in oncogenes or tumor suppressor genes, contributing to tumorigenesis . Our findings will enable efforts to decipher the molecular details of this process. Importantly, this work has also uncovered a candidate metabolite biomarker of colibactin exposure and cancer risk. The ability to directly assess whether exposure to colibactin has occurred in animal models and human patients will help address the critical question of whether pks+ E. coli contribute to colorectal carcinogenesis in patient cohorts .', 30765538);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3539, 'human', 'null', 'We have presented direct evidence that the gut bacterial genotoxin colibactin alkylates DNA in vivo. The ability of pks+ E. coli to generate DNA adducts in mammalian cells and in mice strengthens support for the involvement of colibactin in cancer development or progression since misrepaired mono- and cross-linked adducts may generate mutations in oncogenes or tumor suppressor genes, contributing to tumorigenesis . Our findings will enable efforts to decipher the molecular details of this process. Importantly, this work has also uncovered a candidate metabolite biomarker of colibactin exposure and cancer risk. The ability to directly assess whether exposure to colibactin has occurred in animal models and human patients will help address the critical question of whether pks+ E. coli contribute to colorectal carcinogenesis in patient cohorts .', 30765538);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3542, 'human', 'Soybean Isoflavones', 'An equol-producing bacterium, strain DZET , which was isolated from human faeces, was characterized by morphological, biochemical and molecular methods. The isolate was Grampositive, obligately anaerobic, non-spore forming, asaccharolytic and rod-shaped. 16S rRNA sequence analysis showed 92.8, 91.0, 91.1 and 90.6 % similarities with Slackia faecicanis, Slackia exigua, Slackia heliotrinireducens and Slackia isoflavoniconvertens, respectively. Basedon these data, we propose a novel species of the genus Slackia, Slackia equolifaciens sp. nov.The major cellular fatty acids are C14 : 0, C18 : 1v9c and C18 : 1v9c DMA (dimethyl acetal). The DNA G+C content of the strain is 60.8 mol%. The type strain of S.equolifaciens sp. nov. is DZE.', 19734283);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3543, 'human', 'Daidzein', 'Equol and 5-hydroxy-equol were found in intestinal contents, feces, and urine of SIA rats but not in the corresponding samples of the control rats. 5-Hydroxy-equol was present at much lower concentrations than equol and the main metabolite produced from genistein was the intermediate dihydrogenistein. The plasma of SIA rats contained equol but no 5-hydroxy-equol. Equol formation had no effect on plasma concentrations of the insulin-like growth factor I. The concentrations of daidzein and genistein were considerably lower in all samples of the SIA rats than in those of the control rats. Male SIA rats had higher intestinal and fecal concentrations of the isoflavones and their metabolites than female SIA rats. The observed activity in the rat model indicates that S. isoflavoniconvertens is capable of contributing in vivo to the bioactivation of daidzein and genistein by formation of equol and 5-hydroxy-equol.', 22113864);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3544, 'human', 'Genistein', 'Equol and 5-hydroxy-equol were found in intestinal contents, feces, and urine of SIA rats but not in the corresponding samples of the control rats. 5-Hydroxy-equol was present at much lower concentrations than equol and the main metabolite produced from genistein was the intermediate dihydrogenistein. The plasma of SIA rats contained equol but no 5-hydroxy-equol. Equol formation had no effect on plasma concentrations of the insulin-like growth factor I. The concentrations of daidzein and genistein were considerably lower in all samples of the SIA rats than in those of the control rats. Male SIA rats had higher intestinal and fecal concentrations of the isoflavones and their metabolites than female SIA rats. The observed activity in the rat model indicates that S. isoflavoniconvertens is capable of contributing in vivo to the bioactivation of daidzein and genistein by formation of equol and 5-hydroxy-equol.', 22113864);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3545, 'human', 'null', 'The alignment results showed that homologous proteins for FOS transporters and glycosidases were distributed in 237 of the 453 strains of gut bacteria. La506 msmK encoding the ATP-binding protein and Aec45 fosGH1 encoding glycoside hydrolase were most widely distributed, in 155 and 55 strains, respectively. Seven of eight strains with both transporters and glycosidases were proven to be capable of metabolizing FOS, while five strains without either transporters or glycosidases were not. Fifteen species isolated from human feces and 11 species from the alignment search were identified to be FOS-metabolizing, of which Cronobacter sakazakii, Marvinbryantia formatexigens, Ruminococcus gnavus, and Weissella paramesenteroides are reported here for the first time.', 25653214);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3546, 'human', 'null', 'The alignment results showed that homologous proteins for FOS transporters and glycosidases were distributed in 237 of the 453 strains of gut bacteria. La506 msmK encoding the ATP-binding protein and Aec45 fosGH1 encoding glycoside hydrolase were most widely distributed, in 155 and 55 strains, respectively. Seven of eight strains with both transporters and glycosidases were proven to be capable of metabolizing FOS, while five strains without either transporters or glycosidases were not. Fifteen species isolated from human feces and 11 species from the alignment search were identified to be FOS-metabolizing, of which Cronobacter sakazakii, Marvinbryantia formatexigens, Ruminococcus gnavus, and Weissella paramesenteroides are reported here for the first time.', 25653214);
