INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3579, 'human', 'D-Glucose', 'Two anaerobic, non-spore-forming, pleomorphic, Gram-negative rods, designated YIT 11840T and YIT 11841T, were isolated from human faeces. The organisms were catalase-negative, produced succinic and acetic acids as end products of glucose metabolism and had DNA G+C contents of approximately 48�?9 mol%. Although the phenotypic characteristics of these two strains were very similar, analysis of their 16S rRNA sequence showed that they are only distantly related (93.8 %), indicating that they represent two different species. A comparative sequence analysis revealed that these two species are members of the family ‘Prevotellaceae�?but are phylogenetically distant (<88 % sequence similarity) from the known genera belonging to this family, including Prevotella, Hallela and Xylanibacter.', 19567577);
