INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3619, 'human', 'null', 'Gut flora and plasma microbiome-related metabolites were evaluated by amplicon sequencing of the bacterial 16S ribosomal RNA gene and capillary electrophoresis time-of-flight mass spectrometry, respectively. HF patients were evaluated in both the Decomp and Comp phases during hospitalization. The phylum Actinobacteria was enriched in HF patients compared with control subjects. At the genus level, Bifiodobacterium was abundant while Megamonas was depleted in HF patients. Meanwhile, plasma concentration of trimethylamine N-oxide (TMAO), a gut microbiome-derived metabolite, was increased in HF patients. A correlation analysis revealed positive correlations between the abundance of the genus Escherichia/Shigella and levels of TMAO and indoxyl sulfate (IS, a microbe-dependent uremic toxin) in Comp HF . Escherichia/Shigella was more abundant in Decomp than in Comp HF (P=0.030).Conclusions: Our results suggest that gut microbiome composition and microbiome-related metabolites are altered in HF patient.', 30487369);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3620, 'human', 'null', 'Gut flora and plasma microbiome-related metabolites were evaluated by amplicon sequencing of the bacterial 16S ribosomal RNA gene and capillary electrophoresis time-of-flight mass spectrometry, respectively. HF patients were evaluated in both the Decomp and Comp phases during hospitalization. The phylum Actinobacteria was enriched in HF patients compared with control subjects. At the genus level, Bifiodobacterium was abundant while Megamonas was depleted in HF patients. Meanwhile, plasma concentration of trimethylamine N-oxide (TMAO), a gut microbiome-derived metabolite, was increased in HF patients. A correlation analysis revealed positive correlations between the abundance of the genus Escherichia/Shigella and levels of TMAO and indoxyl sulfate (IS, a microbe-dependent uremic toxin) in Comp HF . Escherichia/Shigella was more abundant in Decomp than in Comp HF (P=0.030).Conclusions: Our results suggest that gut microbiome composition and microbiome-related metabolites are altered in HF patient.', 30487369);
