INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3626, 'human', 'Quercitrin', 'Ultra performance liquid chromatography/quadrupole-time-of-flight mass spectrometry (UPLC/Q-TOF MS) technique combined with MetabolynxTM software was used for analysis of the metabolites of quercitrin by the isolated human intestinal bacteria from the human feces. Four metabolites of quercitrin were detected and tentatively identified based on the characteristics of their protonated ions. The metabolites were metabolized by four main metabolic pathwaysincluding hydroxylation, demethylation, deglycosylation and ring-cleavage. Quercitrin was metabolized to the hydroxyquercitrin and desmethylquercitrin by the majority of the isolated intestinal bacteria such as Bacteroidessp. 54, and was degraded to the deglycosylated product quercetin by rhamnosidase and further ring cleavage metabolite 3,4-dihydroxybenzoic acid by the minority of the isolated bacteria such as Bacteroides sp. 45. The metabolic pathways and most of the metabolites of quercitrin were reported for the first time.', 23754166);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3627, 'human', 'Quercitrin', 'Ultra performance liquid chromatography/quadrupole-time-of-flight mass spectrometry (UPLC/Q-TOF MS) technique combined with MetabolynxTM software was used for analysis of the metabolites of quercitrin by the isolated human intestinal bacteria from the human feces. Four metabolites of quercitrin were detected and tentatively identified based on the characteristics of their protonated ions. The metabolites were metabolized by four main metabolic pathwaysincluding hydroxylation, demethylation, deglycosylation and ring-cleavage. Quercitrin was metabolized to the hydroxyquercitrin and desmethylquercitrin by the majority of the isolated intestinal bacteria such as Bacteroidessp. 54, and was degraded to the deglycosylated product quercetin by rhamnosidase and further ring cleavage metabolite 3,4-dihydroxybenzoic acid by the minority of the isolated bacteria such as Bacteroides sp. 45. The metabolic pathways and most of the metabolites of quercitrin were reported for the first time.', 23754166);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3628, 'human', 'Quercitrin', 'Ultra performance liquid chromatography/quadrupole-time-of-flight mass spectrometry (UPLC/Q-TOF MS) technique combined with MetabolynxTM software was used for analysis of the metabolites of quercitrin by the isolated human intestinal bacteria from the human feces. Four metabolites of quercitrin were detected and tentatively identified based on the characteristics of their protonated ions. The metabolites were metabolized by four main metabolic pathwaysincluding hydroxylation, demethylation, deglycosylation and ring-cleavage. Quercitrin was metabolized to the hydroxyquercitrin and desmethylquercitrin by the majority of the isolated intestinal bacteria such as Bacteroidessp. 54, and was degraded to the deglycosylated product quercetin by rhamnosidase and further ring cleavage metabolite 3,4-dihydroxybenzoic acid by the minority of the isolated bacteria such as Bacteroides sp. 45. The metabolic pathways and most of the metabolites of quercitrin were reported for the first time.', 23754166);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3632, 'human', 'null', 'Plasma from rats treated for seven days with the non-absorbed antibiotic vancomycin or a mixture of streptomycin, neomycin, polymyxin B and bacitracin was analyzed using mass spectrometry-based metabolite profiling platforms. Antibiotic-induced changes in the abundance of individual groups of intestinal microbiota dramatically altered the host\'s metabolism. Hierarchical clustering of dissimilarities separated the levels of 284 identified metabolites from treated vs. untreated rats; 193 were altered by the antibiotic treatments with a tendency towards decreased metabolite levels. Catabolism of the aromatic amino acids phenylalanine, tryptophan and tyrosine was the most affected pathway comprising 33 affected metabolites. Vancomycin-treated rats were administered amino acid metabolites prior to ischemia/reperfusion studies. Oral or intravenous pretreatment of rats with these amino acid metabolites abolished the decrease in infarct size conferred by vancomycin. Cardioprotection by vancomycin is mediated by activation of pro-survival kinases Akt, p42/44 MAPK and p39 MAPK, as well as activation of KATP channels, classical mediators and effectors of pharmacologic cardioprotection. These proteins are components of known intersecting and interdependent signaling pathways in the myocardium that determine severity of myocardial infarction.', 27505423);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3633, 'human', 'null', 'Plasma from rats treated for seven days with the non-absorbed antibiotic vancomycin or a mixture of streptomycin, neomycin, polymyxin B and bacitracin was analyzed using mass spectrometry-based metabolite profiling platforms. Antibiotic-induced changes in the abundance of individual groups of intestinal microbiota dramatically altered the host\'s metabolism. Hierarchical clustering of dissimilarities separated the levels of 284 identified metabolites from treated vs. untreated rats; 193 were altered by the antibiotic treatments with a tendency towards decreased metabolite levels. Catabolism of the aromatic amino acids phenylalanine, tryptophan and tyrosine was the most affected pathway comprising 33 affected metabolites. Vancomycin-treated rats were administered amino acid metabolites prior to ischemia/reperfusion studies. Oral or intravenous pretreatment of rats with these amino acid metabolites abolished the decrease in infarct size conferred by vancomycin. Cardioprotection by vancomycin is mediated by activation of pro-survival kinases Akt, p42/44 MAPK and p40 MAPK, as well as activation of KATP channels, classical mediators and effectors of pharmacologic cardioprotection. These proteins are components of known intersecting and interdependent signaling pathways in the myocardium that determine severity of myocardial infarction.', 27505423);
