INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3642, 'human', '4-N-(3-Chloro-4-fluorophenyl)-6-N-[1-(iodomethyl)piperidin-4-yl]pyrimido[5,4-d]pyrimidine-4,6-diamine', 'The present study identified the metabolites from DN through analysis of organ-specific biotransformation and validated the cardioprotective effects of the screened metabolites using an isoprenaline-induced myocardial ischemia rat model. The findings of the present study provide evidence that, first, diosgenin is generated from DN by intestinal microflora; second, diosgenin can protect the myocardium against ischemic insult in a dose-dependent manner, almost comparable to the effect of DN extract; and, third, DN\'s protective effect can be attributed to the increase of enzymatic and nonenzymatic antioxidants (SOD, CAT, GPx, and T-AOC) in vivo and to a decrease in lipid peroxidation. These phenomena help explain the clinical efficacy of DN as an anti-MI drug.', 29085554);
