INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3694, 'human', 'D-Glucose', 'To gain some specific insight into the roles microorganisms might play in non-alcoholic fatty liver disease (NAFLD), some intestinal and lactic acid bacteria and one yeast  were characterized by high performance liquid chromatography for production of ethanol when grown on different carbohydrates. Highest amounts of ethanol were produced by S. cerevisiae, L. fermentum, and W. confusa on glucose and by S. cerevisiae and W. confusa on fructose.', 26858714);
