INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3705, 'human', 'Daidzein', 'Equol is a metabolite produced from daidzein by enteric microflora, and it has attracted a great deal of attention because of its protective or ameliorative ability against several sex hormone-dependent diseases (e.g., menopausal disorder and lower bone density), which is more potent than that of other isoflavonoids. We purified a novel NADP(H)-dependent daidzein reductase (L-DZNR) from Lactococcus strain 20-92 (Lactococcus 20-92; S. Uchiyama, T. Ueno, and T. Suzuki, international patent WO2005/000042) that is involved in the metabolism of soy isoflavones and equol production and converts daidzein to dihydrodaidzein.', 20639368);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3706, 'human', 'Daidzein', 'Equol is a metabolite produced from daidzein by enteric microflora, and it has attracted a great deal of attention because of its protective or ameliorative ability against several sex hormone-dependent diseases (e.g., menopausal disorder and lower bone density), which is more potent than that of other isoflavonoids. We purified a novel NADP(H)-dependent daidzein reductase (L-DZNR) from Lactococcus strain 20-92 (Lactococcus 20-92; S. Uchiyama, T. Ueno, and T. Suzuki, international patent WO2005/000042) that is involved in the metabolism of soy isoflavones and equol production and converts daidzein to dihydrodaidzein.', 20639368);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3707, 'human', 'Mangiferin', 'The C-glucosyl bond of C-glucosides generally tolerates acid and enzymatic hydrolysis. Many C-glucosides are cleaved by human intestinal bacteria. We isolated the specific bacterium involved in the metabolism of mangiferin (2-b-D-glucopyranosyl-1,3,6,7-tetrahydroxyxanthone), C-glucosyl xanthone, from a mixture of human fecal bacteria. The anaerobic Bacteroides species named MANG, transformed mangiferin to the aglycone, norathyriol, suggesting cleavage of a C-glucosyl bond.', 16141538);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3708, 'human', 'Mangiferin', 'The C-glucosyl bond of C-glucosides generally tolerates acid and enzymatic hydrolysis. Many C-glucosides are cleaved by human intestinal bacteria. We isolated the specific bacterium involved in the metabolism of mangiferin (2-b-D-glucopyranosyl-1,3,6,7-tetrahydroxyxanthone), C-glucosyl xanthone, from a mixture of human fecal bacteria. The anaerobic Bacteroides species named MANG, transformed mangiferin to the aglycone, norathyriol, suggesting cleavage of a C-glucosyl bond.', 16141538);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3709, 'human', 'null', '5-HT storing enterochromaffin (EC) cells are believed to respond to nutrient and gut microbial components, and 5-HT receptor-expressing afferent vagal neurons have been described to be the major sensors of nutrients in the GI-tract. However, the molecular mechanism through which EC cells sense nutrients and gut microbiota is still unclear.Nutrient metabolites apparently do not stimulate EC cells of the small intestine directly but through a paracrine mechanism involving GLP-1 secreted from neighboring enteroendocrine cells. In contrast, colonic EC cells are able to sense a multitude of different metabolites generated by the gut microbiota as well as gut hormones, including GLP-1.', 29576437);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3710, 'human', 'null', '5-HT storing enterochromaffin (EC) cells are believed to respond to nutrient and gut microbial components, and 5-HT receptor-expressing afferent vagal neurons have been described to be the major sensors of nutrients in the GI-tract. However, the molecular mechanism through which EC cells sense nutrients and gut microbiota is still unclear.Nutrient metabolites apparently do not stimulate EC cells of the small intestine directly but through a paracrine mechanism involving GLP-1 secreted from neighboring enteroendocrine cells. In contrast, colonic EC cells are able to sense a multitude of different metabolites generated by the gut microbiota as well as gut hormones, including GLP-1.', 29576437);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3711, 'human', 'null', '5-HT storing enterochromaffin (EC) cells are believed to respond to nutrient and gut microbial components, and 5-HT receptor-expressing afferent vagal neurons have been described to be the major sensors of nutrients in the GI-tract. However, the molecular mechanism through which EC cells sense nutrients and gut microbiota is still unclear.Nutrient metabolites apparently do not stimulate EC cells of the small intestine directly but through a paracrine mechanism involving GLP-1 secreted from neighboring enteroendocrine cells. In contrast, colonic EC cells are able to sense a multitude of different metabolites generated by the gut microbiota as well as gut hormones, including GLP-1.', 29576437);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3712, 'human', 'null', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 16534848);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3713, 'human', 'null', 'The E.limosum produced butyrate, acetate, propionate, and lactate at 0.25, 1.0, 0.025 and 0.07 mmol/L, respectively in medium. At this concentration, each acid had no growth stimulating activity on T84 cells; however, when these acids were mixed together at the above levels, it showed significantly high activity than control. Except for lactate, these acids significantly attenuated IL-6 production at just 0.1 mmol/L. In addition, under TNF-a stimulation, butyrate attenuated the production of TLR4 mRNA. The treatment with E.limosum significantly attenuated clinical and histological scores of colitis with an increase of cecal butyrate levels, compared with the control group.', 16534848);
