INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3716, 'human', 'Rutin', 'In this paper, rutin was metabolized by human intestinal bacteria and five isolated strains including Bacillus sp. 52, Bacteroides sp. 45, 42, 22 and Veillonella sp. 32, the metabolites were identified using ultra performance liquid chromatography/quadrupole-time-of-flight mass spectrometry (UPLC–Q-TOF/MS). As a result, Bacillus sp. 52 and Bacteroides sp. 45 could metabolize rutin to quercetin 3-O-glucoside and leucocyanidin. Bacteroides sp. 42 and Veillonella sp. 32 could convert rutin to leucocyanidin. Bacteroides sp. 22 could hydrolyze rutin to quercetin-3-O-glucoside. In order to further explain the metabolism pathway of rutin,the -d-glucosidase and -l-rhamnosidase activities offive strains weredetermined.', 22583754);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3717, 'human', 'Rutin', 'In this paper, rutin was metabolized by human intestinal bacteria and five isolated strains including Bacillus sp. 52, Bacteroides sp. 45, 42, 22 and Veillonella sp. 32, the metabolites were identified using ultra performance liquid chromatography/quadrupole-time-of-flight mass spectrometry (UPLC–Q-TOF/MS). As a result, Bacillus sp. 52 and Bacteroides sp. 45 could metabolize rutin to quercetin 3-O-glucoside and leucocyanidin. Bacteroides sp. 42 and Veillonella sp. 32 could convert rutin to leucocyanidin. Bacteroides sp. 22 could hydrolyze rutin to quercetin-3-O-glucoside. In order to further explain the metabolism pathway of rutin,the -d-glucosidase and -l-rhamnosidase activities offive strains weredetermined.', 22583754);
