INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3757, 'human', 'Isoflavone', 'The genome of new equol-producing bacteria, Lactobacillus paracasei JS1, was analyzed. Also, the effect of P. lobata extract fermented with L. paracasei JS1 (FPE) on the skin and intestinal immune response was examined. With gene expression analysis, it was proven that seven skin-related proteins, hyaluronan synthase-1, -2, -3, collagen, elastin, epidermal growth factor, and epidermal growth factor receptor were differentially expressed upon FPE treatment. The messenger RNA expression increased with treatment with the FPE, and a skin moisturizing effect was confirmed by a hematoxylin-eosin staining experiment. In addition, such an experiment showed that proinflammatory cytokines, tumor necrosis factor-α, cyclooxygenase-2, inducible nitric oxide synthase, interleukin-1β, -4, and -6, were reduced in large intestine when treated with FPE.', 30767231);
