INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3769, 'human', 'Daidzein', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3770, 'human', 'Daidzin', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
