INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3773, 'human', 'Puerarin', 'A rod-shaped Gram-positive bacterium, strain CG19-1, capable of deglycosylating puerarin to daidzein was isolated from the corresponding suspension. However, the strictly anaerobic isolate was unable to utilize puerarin as sole carbon and energy source nor any of the tested carbohydrates. Comparative 16S rRNA sequence analysis indicated that strain CG19-1 is a new species of the Lachnospiraceae. Strain CG19-1 also converted other aromatic C-glucosides in addition to puerarin. The xanthone C-glucoside mangiferin was deglycosylated to norathyriol. The flavone C-glucosides homoorientin and vitexin were degraded to 3-(3,4-dihydroxyphenyl)propionic acid via luteolin and 3-(4-hydroxyphenyl)propionic acid respectively. In addition, strain CG19-1 converted flavonoid O-glucosides, but at rates that were lower than those of the C-glucosides tested. The isolate deglycosylated the isoflavone O-glucosides daidzin and genistin to daidzein and genistein respectively. Several O-glucosides of the flavones luteolin and apigenin undergoing deglycosylation were subsequently cleaved to 3-(3,4-dihydroxyphenyl)propionic acid and 3-(4-hydroxyphenyl)propionic acid respectively. Moreover, strain CG19-1 cleaved both O-desmethylangolensin and 6\'-hydroxy-O-desmethylangolensin to yield 2-(4-dihydroxyphenyl)propionic acid. The corresponding cleavage product, resorcinol, was only observed for O-desmethylangolensin.', 20946528);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3774, 'human', 'Vitexin', 'A rod-shaped Gram-positive bacterium, strain CG19-1, capable of deglycosylating puerarin to daidzein was isolated from the corresponding suspension. However, the strictly anaerobic isolate was unable to utilize puerarin as sole carbon and energy source nor any of the tested carbohydrates. Comparative 16S rRNA sequence analysis indicated that strain CG19-1 is a new species of the Lachnospiraceae. Strain CG19-1 also converted other aromatic C-glucosides in addition to puerarin. The xanthone C-glucoside mangiferin was deglycosylated to norathyriol. The flavone C-glucosides homoorientin and vitexin were degraded to 3-(3,4-dihydroxyphenyl)propionic acid via luteolin and 3-(4-hydroxyphenyl)propionic acid respectively. In addition, strain CG19-1 converted flavonoid O-glucosides, but at rates that were lower than those of the C-glucosides tested. The isolate deglycosylated the isoflavone O-glucosides daidzin and genistin to daidzein and genistein respectively. Several O-glucosides of the flavones luteolin and apigenin undergoing deglycosylation were subsequently cleaved to 3-(3,4-dihydroxyphenyl)propionic acid and 3-(4-hydroxyphenyl)propionic acid respectively. Moreover, strain CG19-1 cleaved both O-desmethylangolensin and 6\'-hydroxy-O-desmethylangolensin to yield 2-(4-dihydroxyphenyl)propionic acid. The corresponding cleavage product, resorcinol, was only observed for O-desmethylangolensin.', 20946528);
