INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3776, 'human', '6\'-Hydroxy-O-desmethylangolensin', 'A rod-shaped Gram-positive bacterium, strain CG19-1, capable of deglycosylating puerarin to daidzein was isolated from the corresponding suspension. However, the strictly anaerobic isolate was unable to utilize puerarin as sole carbon and energy source nor any of the tested carbohydrates. Comparative 16S rRNA sequence analysis indicated that strain CG19-1 is a new species of the Lachnospiraceae. Strain CG19-1 also converted other aromatic C-glucosides in addition to puerarin. The xanthone C-glucoside mangiferin was deglycosylated to norathyriol. The flavone C-glucosides homoorientin and vitexin were degraded to 3-(3,4-dihydroxyphenyl)propionic acid via luteolin and 3-(4-hydroxyphenyl)propionic acid respectively. In addition, strain CG19-1 converted flavonoid O-glucosides, but at rates that were lower than those of the C-glucosides tested. The isolate deglycosylated the isoflavone O-glucosides daidzin and genistin to daidzein and genistein respectively. Several O-glucosides of the flavones luteolin and apigenin undergoing deglycosylation were subsequently cleaved to 3-(3,4-dihydroxyphenyl)propionic acid and 3-(4-hydroxyphenyl)propionic acid respectively. Moreover, strain CG19-1 cleaved both O-desmethylangolensin and 6\'-hydroxy-O-desmethylangolensin to yield 2-(4-dihydroxyphenyl)propionic acid. The corresponding cleavage product, resorcinol, was only observed for O-desmethylangolensin.', 20946528);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3777, 'human', '(3R)-flavan-3-ols', 'A human intestinal bacterium, Eubacterium (E.) sp. strain SDG-2, was tested for its ability to metabolize various (3R)- and (3S)-flavan-3-ols and their 3-O-gallates. This bacterium cleaved the C-ring of (3R)- and (3S)-flavan-3-ols to give 1,3-diphenylpropan-2-ol derivatives, but not their 3-O-gallates. Furthermore, E. sp. strain SDG-2 had the ability of p-dehydroxylation in the B-ring of (3R)-flavan-3-ols, such as (-)-catechin, (-)-epicatechin, (-)-gallocatechin and (-)-epigallocatechin, but not of (3S)-flavan-3-ols, such as (+)-catechin and (+)-epicatechin.', 11767089);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3778, 'human', '(3S)-flavan-3-ols', 'A human intestinal bacterium, Eubacterium (E.) sp. strain SDG-2, was tested for its ability to metabolize various (3R)- and (3S)-flavan-3-ols and their 3-O-gallates. This bacterium cleaved the C-ring of (3R)- and (3S)-flavan-3-ols to give 1,3-diphenylpropan-2-ol derivatives, but not their 3-O-gallates. Furthermore, E. sp. strain SDG-2 had the ability of p-dehydroxylation in the B-ring of (3R)-flavan-3-ols, such as (-)-catechin, (-)-epicatechin, (-)-gallocatechin and (-)-epigallocatechin, but not of (3S)-flavan-3-ols, such as (+)-catechin and (+)-epicatechin.', 11767089);
