INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (3818, 'human', 'PhIP-N2-β-D-glucuronide', 'B-GUS of Faecalibacterium prausnitzii converted PhIP-G to PhIP and GDH of Flavonifractor plautii, Blautia obeum, Eubacterium hallii, and Lactobacillus reuteri converted PhIP to PhIP-M1 in the presence of glycerol. In addition, B-GUS- and GDH-positive bacteria cooperatively converted PhIP-G to PhIP-M1.', 31096909);
