INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4122, 'human', 'Daidzein', 'In conclusion, the results obtained in this study suggest that the presence of Bacteroides genus in the fecal samples of control subjects seems to be involved in the daidzein transformation to equol, an antioxidative, anti-carcinogenic molecule, which shows the most active estrogenic properties of soy isoflavones.\n', 32218321);
