INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4131, 'human', 'Pyruvate', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4132, 'human', 'Pyruvate', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4133, 'human', 'Pyruvate', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
