INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4135, 'human', 'null', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4136, 'human', 'null', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4137, 'human', 'Trimethylamine', 'We found that TMAO treatment activated astrocytes, as indicated by a ~ 2-fold increase in LCN2 (Fig. 6a) and a ~ 3-fold increase in CD44 (Fig. 6b), a pro-inflammatory intercellular adhesion pro tein characteristic of reactive astrocytes [10].', 32862276);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4138, 'human', 'Trimethylamine', 'We found that TMAO treatment activated astrocytes, as indicated by a ~ 2-fold increase in LCN2 (Fig. 6a) and a ~ 3-fold increase in CD44 (Fig. 6b), a pro-inflammatory intercellular adhesion pro tein characteristic of reactive astrocytes [10].', 32862276);
