INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4144, 'human', 'Secoisolariciresinol diglucoside', 'Over the first 30 min at 37 1C, the amount of SDG converted to SECO by resting cells of Clostridium sp. SDG Mt85-3Db was approximately 8- and 30-fold higher than the amount converted by B. distasonis DSM 20701T and B.ovatus SDG-Mt85-3Cy, respectively.', 16765860);
