INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4150, 'human', 'Lariciresinol', 'In addition,the previously isolated strain E. lenta SECO-Mt75m3 catalysed the reduction of pinoresinol to SECO via lariciresinol.', 16765860);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4151, 'human', 'Pinoresinol', 'In addition,the previously isolated strain E. lenta SECO-Mt75m3 catalysed the reduction of pinoresinol to SECO via lariciresinol.', 16765860);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4152, 'human', 'Matairesinol', 'However, methoxy or hydroxyl groups adjacent to the targeted methoxy groups may be required by P. productus SECO-Mt75m3 to catalyse demethylation, as evident from the inability of this organism to demethylate m-anisic acid. Incubation of P.productus SECO-Mt75m3 with ferulic acid led to complete conversion of the substrate without detection of any products by HPLC, suggesting that P. productus not only catalyses the demethylation of ferulic acid but also a number of additional reactions. More interestingly, P. productus SECO-Mt75m3 catalysed as well the demethyla tion of other lignans, namely lariciresinol (Fig. 2),\nmatairesinol and pinoresinol (data not shown). In addition, the previously isolated strain E. lenta SECO-Mt75m3 catalysed the reduction of pinoresinol to SECO via lariciresinol (Fig. 3).', 16765860);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4153, 'human', 'Secoisolariciresinol', 'In conclusion, SDG metabolising bacteria are expected to play a major role in the activation of various dietary lignans with ensuing consequences on the bioavailability and biological activity of enterolignans. Fig. 4 summarises the new data reported above and the present knowledge about the bacterial pathways of enterolignan production.', 16765860);
