INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4178, 'human', 'Dihydrodaidzein', 'The bacterial strain named Julong 732 is also able to metabolize dihydrodaidzein to S-equol (123). Thus, other bacteria have to be involved in the previous steps of the conversion of daidzein to equol .', 19580283);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4179, 'human', 'Isoxanthohumol', 'Isoxanthohumol is a prenylated flavanone from hops and beer that has interesting biological activities. It can be metabo lized in vivo by colonic microbiota to render 8-prenylnaringenin (133, 134). This metabolic O-demethylation is carried out by Eubacterium species and particularly by Eubacterium limosum.', 19580283);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4180, 'mouse', 'Cholesterol', 'unclassifed Lachnospiraceae, Oscillibacter,  Clostridium IV and Clostridium XlVa of phylum Firmicutes identifed upon RSB application showed similar  trends of correlation. Te relative abundance of the predominant RSB-enriched gut bacterial genus of unclas sifed Lachnospiraceae was positively associated with the concentrations of nine increased metabolites, includ ing cholic acid, 7-dehydrocholesterol, 11-deoxycorticosterone, retinol, chenodeoxycholic acid, L-phenylalanine,  L-glutamate, 3-phenylpropanoic acid and (5Z, 8Z, 11Z, 14Z, 17Z)-eicosapentaenoic acid, and negatively cor related with the concentrations of four metabolites showing decreasing trends, including L-isoleucine, tetra decanoic acid, indole-3-acetic acid, and benzoic acid.', 31780788);
