INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4216, 'mouse', 'Cholesterol', 'Prevotella and Paraprevotella presented negative correlations with the same nine  metabolites 93-phenylpropanoic acid, cholic acid, retinol, L-glutamate, L-phenylalanine, 7-dehydrocholesterol,  chenodeoxycholic acid, (5Z, 8Z, 11Z, 14Z, 17Z)-eicosapentaenoic acid and 11-deoxycorticosterone) and positive  correlations with four metabolites (tetradecanoic acid, L-isoleucine, benzoic acid, and indole-3-acetic acid). Our  results also revealed clear correlations among some metabolites.', 31780788);
