INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4350, 'mouse', 'null', 'The main metabolites produced by B. thetaiotaomicron in the GIT were acetate (up to 6 mM) and propionate (up to 2 mM) (Figure 1D). We evaluated the effects of these bacterial metabolites on the amount of KLF4 protein produced by the mucus producing cell line HT29-MTX [31]. The amount of KLF4 protein was higher in the presence than in the absence of acetate (10 and 20 mM) (Figure 3A)whereas propionate (5 and 10 mM) and butyrate (1 and 5 mM) had no effect (Figure 3B, C).', 23692866);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4351, 'mouse', 'null', 'The main metabolites produced by B. thetaiotaomicron in the GIT were acetate (up to 6 mM) and propionate (up to 2 mM) (Figure 1D). We evaluated the effects of these bacterial metabolites on the amount of KLF4 protein produced by the mucus producing cell line HT29-MTX [31]. The amount of KLF4 protein was higher in the presence than in the absence of acetate (10 and 20 mM) (Figure 3A)whereas propionate (5 and 10 mM) and butyrate (1 and 5 mM) had no effect (Figure 3B, C).', 23692866);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4357, 'mouse', 'Acetate', 'We first checked  in vitro  that  B. thetaiotaomicron produced acetate and propionate and that  F. prausnitzii consumed acetate and produced butyrate (Figure 4A). When both bacteria were grown together, butyrate was produced rather than acetate. The butyrate production by F. prausnitzii as higher in the presence than absence of B. thetaiotaomicron  (10.9 ± 0.3 mM versus 7.8 ± 0.5 mM) suggesting that  F. prausnitzii  synthesized butyrate from the acetate produced by  B. thetaiotaomicron .', 23692866);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4361, 'mouse', 'null', 'Regarding the fecal potential biomarkers, all the elevated potential biomarkers were positively correlated with g__Hungatella, and all the elevated biomarkers but for valine and 2-formaminobenzoylacetate were positively correlated with g__Parabacteroides and g__Intestinibacter. N-acetylputrescine, isoleucine, tyramine, valine, 5-hydroxyindoleacetate, 2formaminobenzoylacetate, hyocholate, and cholate were positively correlated with g__ Ruminococcus_torques_group, while isoleucine was also positively correlated with g__Blautia. N-acetyl-D-mannosamine, chenodeoxycholate, and 12-ketodeoxycholate were positively correlated to g__ Ruminococcus_1, g__norank_f_Lachnospiraceae, g__norank_f_ Ruminococcaceae, and g__unclassified_f_Ruminococcaceae, and ursodeoxycholate and deoxycholate were positively correlated with g__Ruminococcus_1. Also, N-acetyl-D-glucosamine, nutriadeoxycholate vulpecholate, murideoxycholate, urobilin, and 7a-hydroxy-3-oxo-5b-cholanoate were positively correlated with g__norank_f_Lachnospiraceae, g__norank_f_ Ruminococcaceae, and g__unclassified_f_Ruminococcaceae.7-Hydroxy-3-oxocholanoic acid was positively correlated with g__norank_f_Lachnospiraceae, while hypoxanthine was positively correlated with g__Clostridium_sensu_stricto_1.', 31214133);
