INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4431, 'mouse', 'D-Glucose', 'Propionate formation from fucose via propanediol has also been described in the human gut anaerobe Roseburia inulinivorans, which produces butyrate rather than propionate when grown on glucose.', 24553467);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4432, 'mouse', 'L-Fucose', 'The propanediol pathway has been detected in the phylogenetically distant bacteria Salmonella enterica serovar Typhimurium (Bobik et al., 1999) and R. inulinivorans (Scott et al., 2006), suggesting that it might be present in other gut bacteria.', 24553467);
