INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4496, 'mouse', 'null', 'Our results suggest this is due to GF colonocytes adapting to their suboptimal energetic state by undergoing autophagy. Reduced ATP levels activate AMPK, which, in turn, activates p27 to prevent apoptosis and induce autophagy in these cells.', 21531334);
