INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4597, 'mouse', 'null', 'The helminth Nippostrongylus brasiliensis and a tritrichomonad protist both secreted succinate as a metabolite. In vivo sensing of the tritrichomonad required SUCNR1, whereas N. brasiliensis was SUCNR1 independent. These findings define a paradigm wherein tuft cells monitor microbial metabolites to initiate type 2 immunity and suggest the existence of other sensing pathways triggering the response to helminths.', 30021144);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4598, 'mouse', 'null', 'The helminth Nippostrongylus brasiliensis and a tritrichomonad protist both secreted succinate as a metabolite. In vivo sensing of the tritrichomonad required SUCNR1, whereas N. brasiliensis was SUCNR1 independent. These findings define a paradigm wherein tuft cells monitor microbial metabolites to initiate type 2 immunity and suggest the existence of other sensing pathways triggering the response to helminths.', 30021144);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4599, 'mouse', 'omega-6 Fatty Acids', 'Here, we demonstrated that gut microbiota exerted protective effects against HFD-induced obesity and improved glucose homeostasis associated with several mechanisms involving gut microbial metabolites of dietary PUFAs: (1) gut microbiota converted LA to HYA, reducing the adipose inflammation otherwise induced by excessive dietary LA via the AA cascade; (2) HYA activated GPR40 and GPR120 and promoted GLP-1 secretion; and (3) HYA suppressed lipid absorption by promoting intestinal peristalsis via EP3.', 31488836);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4600, 'mouse', 'null', 'Our study shows that MAM from F. prausnitzii can restore the intestinal barrier structure and function in DM conditions via the regulation of the tight junction pathway and ZO-1 expression.Collectively, our data reveal that MAM protein upregulates ZO-1 expression in intestinal epithelial cells.', 31503404);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4601, 'mouse', 'Melamine', 'We further demonstrated that melamine is converted to cyanuric acid in vitro by bacteria cultured from normal rat feces;Klebsiella was subsequently identified in fecal samples by 16S ribosomal DNA sequencing. In culture, Klebsiella terrigena was shown to convert melamine to cyanuric acid directly.', 23408055);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4602, 'mouse', 'null', 'We demonstrate that commensal Bacteroides species limit S. Typhimurium infection in the distalgut. We find that Bacteroides spp. production of the short-chain fatty acid (SCFA) metabolic byproduct propionate directly inhibits S. Typhimurium growth in vitro by disrupting intracellular pH homeostasis and limits distal intestinal expansion and fecal shedding in vivo.', 30057174);
