INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4612, 'mouse', 'null', 'Faecalibacterium prausnitzii produces butyrate to decrease c-Myc-related metabolism and Th17 differentiation by inhibiting histone deacetylase 3.', 30809639);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4613, 'mouse', 'null', 'However, PPD  synergistically enhanced APAP induced hepatic injury in vivo and in vitro. Finally, we  found Saccharomyces cerevisiae, which could reduce intestinal PPD levels, was able  to markedly alleviate APAP induced liver damage at ZT12.', 29524531);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4616, 'mouse', 'null', 'Accordingly, dietary succinate improved glucose and insulin tolerance in wild-type mice, but those effects were absent in mice deficient in IGN. Conventional mice colonized with the succinate producer Prevotella copri exhibited metabolic benefits, which could be related to succinate-activated IGN. Thus, microbiota-produced succinate is a previously unsuspected bacterial metabolite improving glycemic control through activation of IGN.', 27411015);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4617, 'mouse', 'null', 'Butyrate can induce AMPK activation and GLUT4 expression in the adipose tissue, improving cardiovascular disease (CVD)-related metabolic disorder, resisting HFD-induced gut microbiome dysbiosis, and promoting resolvin E1 and lipoxin biosynthesis. Oral supplement of the natural fermentation product butyrate can be a potential strategy for preventing CVD.', 31607907);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4618, 'mouse', 'null', 'Butyrate can induce AMPK activation and GLUT4 expression in the adipose tissue, improving cardiovascular disease (CVD)-related metabolic disorder, resisting HFD-induced gut microbiome dysbiosis, and promoting resolvin E1 and lipoxin biosynthesis. Oral supplement of the natural fermentation product butyrate can be a potential strategy for preventing CVD.', 31607907);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4619, 'mouse', 'null', 'Colonic cDNA concentrations of IL-1b and TNF-a were significantly down regulated in DSS-treated E. durans-fed mice but not in control or DSS-treated L.delbrueckii- fed mice.', 17349085);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4620, 'mouse', 'null', 'Colonic cDNA concentrations of IL-1b and TNF-a were significantly down regulated in DSS-treated E. durans-fed mice but not in control or DSS-treated L.delbrueckii- fed mice.', 17349085);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4621, 'mouse', 'null', 'we demonstrate here that α-defensin 5 expression can also be regulated by microbial metabolites. Among these, lactate appeared to significantly suppress α-defensin 5 gene transcription.', 27760493);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4622, 'mouse', 'null', 'We report that the human gut bacterium Bacteroides thetaiotaomicron relies on the stringent response, an intracellular signaling pathway that allocates resources away from growth, to survive carbon starvation and persist in the gut. Genome-scale transcriptomics, 13C-labeling, and metabolomics analyses reveal that B. thetaiotaomicron uses the alarmone (p)ppGpp to repress multiple biosynthetic pathways and upregulate tricarboxylic acid (TCA) cycle genes in these conditions.', 30008292);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4623, 'mouse', 'null', 'Lactobacilli Induce IL-22 via Iald.', 23973224);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4624, 'mouse', 'Ferulic acid', 'Taxonomic analysis of the cecal microbiota showed an increased abundance of Bacteroidetes, along with a reduction in the population of Firmicutes with HMPA supplementation (Figure 4B). Notably, HMPA intervention induced a drastic increase in the population of Actinobacteria, while the population of Deferribacteres in the cecal microbiota of HMPA-supplemented HFD-fed mice were decreased (Figure 4B). These results were similar to those observed with HMCA supplementation. Hierarchical clustering of individual families also confirmed the effect of HMPA intake on gut microbiota (Figure 4C). The HMPA intervention significantly increased the Bacteroidales S24-7 group and Coriobacteriaceae, which are families within the Bacteroidetes and Actinobacteria, respectively (Figure 4C). These families were also significantly increased in HMCA-supplemented HFD-fed mice (Figure 2D). Meanwhile, significant increases in Prevotellaceae and decreases in Deferribacteraceae were observed in HMPA-supplemented HFD-fed mice, but not in HMCA-supplemented HFD-fed mice (Figures 2D and 4C). These findings demonstrated that HMPA intake changed the composition of mouse gut microbiota.', 31075850);
