INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4639, 'mouse', 'null', 'Indeed, DCA stimulation could induce potent increase of mRNA expression level of M2-mAchR in macrophages, and selective inhibition of M2-mAchR significantly reduced theproduction of TNF-α, NO and IL-6 triggered by DCA (Figure 4(d,e) and Supplementary Figure 4c).', 33006494);
