INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4668, 'mouse', 'null', 'Antimicrobial peptide gene expression of c-type lectins regenerating islet-derived protein 3β (Reg3β) and 3γ (Reg3γ; Fig 2b) were increased moderately due to ACET treatment (20-fold and 40-fold), but were much more significantly increased due to BUT (150-fold and 350-fold,respectively) and PROP (250-fold, and 480-fold, respectively, P < 0.05) compared to CON.Only 1 mM BUT increased Reg3β and Reg3γ expression (80-fold and 100-fold respectively;P < 0.05).', 32240190);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4669, 'mouse', 'null', 'Antimicrobial peptide gene expression of c-type lectins regenerating islet-derived protein 3β (Reg3β) and 3γ (Reg3γ; Fig 2b) were increased moderately due to ACET treatment (20-fold and 40-fold), but were much more significantly increased due to BUT (150-fold and 350-fold,respectively) and PROP (250-fold, and 480-fold, respectively, P < 0.05) compared to CON.Only 1 mM BUT increased Reg3β and Reg3γ expression (80-fold and 100-fold respectively;P < 0.05).', 32240190);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4670, 'mouse', 'null', 'Antimicrobial peptide, β-defensin 1 (Defb1), was increased 3.5-fold due to ACET and BUT treatment, and 6-fold due to PROP treatment (P < 0.05); Fig 2b). 1 mM PROP was sufficient to increase Defb1 expression 2-fold compared to CON (P < 0.05).', 32240190);
