INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4673, 'mouse', 'null', 'Tight junction markers occludin (Ocln), and claudin-3 (Cldn3) were increased nearly 2-fold in enteroids treated with 5 mM ACET (P < 0.05).', 32240190);
