INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4677, 'mouse', 'null', 'Tight junction protein 1 (Tjp1) was not altered by ACET treatment, but was decreased 1.7 and 2-fold respectively due to BUT and PROP treatment (P < 0.05; Fig 2b). There was no\ndifference in Tjp1 expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
