INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4683, 'mouse', 'null', 'Analysis of the expression of mRNAs of three TJ proteins (ZO-1, claudin-1, and occludin) indicated greater expression in the Sham Group than in the three other groups (P < 0.05), and greater expression in the two treatment groups than in the SAP + IAH Group (P < 0.05; Figures 4A,B,D). In addition, expression of claudin-2, MMP9 was lower in the Sham Group than in the three other groups (P < 0.05) and lower in the two treatment groups than in the SAP + IAH Group (P < 0.05; Figures 4C,E).', 33192557);
