INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4701, 'mouse', 'null', 'SLC5A8 and GPR43 expressions in butyrate‑treated CRC cells were quantified (Fig. 5B and C for SLC5A8 and GPR43, respectively). In comparison with untreated cells, the NaB‑treated SW480 cells only presented higher GPR43 (P<0.05), but the NaB‑treated SW620 cells expressed the most SLC5A8 (P<0.01) and GPR43 (P<0.05).', 33101496);
