INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4825, 'mouse', 'Tryptophan', 'Polybrominated diphenyl ethers (PBDEs) are persistent environmental toxicants associated with increased risk for metabolic syndrome.PBDEs altered the largest number of metabolites in the LIC; most were regulated by PBDEs in GF conditions. Importantly, intestinal microbiome was necessary for PBDE-mediated decreases in branched-chain and aromatic amino acid metabolites, including 3-indolepropionic acid, a tryptophan metabolite recently shown to be protective against inflammation and diabetes. Gene-metabolite networks revealed a positive association between the hepatic glycan synthesis gene a-1,6-mannosyltransferase (Alg12) mRNA and mannose, which are important for protein glycosylation. Glycome changes have been observed in patients with metabolic syndrome. In LIC of CV mice, 23 bacterial taxa were regulated by PBDEs. Correlations of certain taxa with distinct serum metabolites further highlight a modulatory role of the microbiome in mediating PBDE effects. In summary, PBDEs impact intermediary metabolism in an intestinal microbiome–dependent manner, suggesting that dysbiosis may contribute to PBDE-mediated toxicities that include metabolic syndrome.', 31123037);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (4826, 'mouse', 'null', 'Differential expression ratios and FDR p-value of genes involved in various intermediary metabolism pathways  in livers of PBDE-exposed CV and GF mice. Data were obtained from RNA-Seq experiments and differential expression was  determined using CuffDiff.', 31123037);
