INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5031, 'mouse', '(-)-Epigallocatechin gallate', 'Inhibitory activity of angiotensin I-converting enzyme (ACE) was examined with (�?-epigallocatechin gallate (EGCG) metabolites produced by intestinal bacteria, together with tea catechins. All of the metabolites showed ACE inhibitory activities.', 26323573);
