INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5047, 'mouse', 'Vorinostat', 'Metabolite profiles of P. mallochii CCH01 were obviously changed by SAHA treatment. Four metabolites (1�?), including two new natural sclerotioramine derivatives, isochromophilone XIV (1) and isochromophilone XV (2), and two known compounds, sclerotioramine (3) and (+)- sclerotiorin (4), were isolated and purified from P. mallochii CCH01 treated with SAHA.', 31632360);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5048, 'mouse', 'Vorinostat', 'Metabolite profiles of P. mallochii CCH01 were obviously changed by SAHA treatment. Four metabolites (1�?), including two new natural sclerotioramine derivatives, isochromophilone XIV (1) and isochromophilone XV (2), and two known compounds, sclerotioramine (3) and (+)- sclerotiorin (4), were isolated and purified from P. mallochii CCH01 treated with SAHA.', 31632360);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5053, 'mouse', 'Isoxanthohumol', 'Recently, it was shown that the exposure to the potent hop phytoestrogen 8-prenylnaringenin (8-PN) depends on intestinal bacterial activation of isoxanthohumol (IX), but this occurs in only one-third of tested individuals. As the butyrate-producing Eubacterium limosum can produce 8-PN from IX, a probiotic strategy was applied to investigate whether 8-PN production could be increased in low 8-PN producers, thus balancing phytoestrogen exposure.', 18567753);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5054, 'mouse', 'P-Cresol', 'In the present study, we investigated the immunological effects of pCS derived from intestinal bacteria in mice. For this purpose, we fed mice a tyrosine-rich diet that causes the accumulation of pCS in their blood. The mice were shown to exhibit decreased Th1-driven 2, 4-dinitrofluorobenzene-induced contact hypersensitivity response. The concentration of pCS in blood was negatively correlated with the degree of the contact hypersensitivity response. In contrast, the T cell-dependent antibody response was not influenced by the accumulated pCS. We also examined the in vitro cytokine responses by T cells in the presence of pCS. The production of IFN-γ was suppressed by pCS. Further, pCS decreased the percentage of IFN-γ-producing Th1 cells. Our results suggest that intestinal bacteria-derived pCS suppressesTh1-type cellular immune responses', 24161588);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5055, 'mouse', 'P-Cresol', 'In the present study, we investigated the immunological effects of pCS derived from intestinal bacteria in mice. For this purpose, we fed mice a tyrosine-rich diet that causes the accumulation of pCS in their blood. The mice were shown to exhibit decreased Th1-driven 2, 4-dinitrofluorobenzene-induced contact hypersensitivity response. The concentration of pCS in blood was negatively correlated with the degree of the contact hypersensitivity response. In contrast, the T cell-dependent antibody response was not influenced by the accumulated pCS. We also examined the in vitro cytokine responses by T cells in the presence of pCS. The production of IFN-γ was suppressed by pCS. Further, pCS decreased the percentage of IFN-γ-producing Th1 cells. Our results suggest that intestinal bacteria-derived pCS suppressesTh1-type cellular immune responses', 24161588);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5056, 'mouse', 'Pectin', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5057, 'mouse', 'Pectin', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
