INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5088, 'mouse', 'null', 'Transverse aortic constriction (TAC) was performed to induce cardiac hypertrophy in Sprague-Dawley (SD) rats. We observed that TMAO levels were significantly elevated in SD rats after 6 weeks of TAC, suggesting the potential role of TMAO in regulating cardiac hypertrophy. In cultured cardiomyocytes, TMAO treatment stimulated cardiac hypertrophy, as indicated by increased cell area of cardiomyocytes and expression of hypertrophic markers including atrial natriuretic peptide (ANP) and beta-myosin heavy chain (β-MHC). Additionally, TMAO treatment induced cardiac hypertrophy and cardiac fibrosis in SD rats. Reducing TMAO synthesis by antibiotics (Abs) attenuated TAC-induced cardiac hypertrophy and fibrosis. Furthermore, pharmacological inhibition of Smad3 by SIS3 significantly reduced the expression of ANP and β-MHC, and cardiomyocyte cell size in TMAO-treated group. These data for the first time demonstrate that gut microbe-derived metabolite TMAO induces cardiac hypertrophy and fibrosis involving Smad3 signaling, suggesting that inhibition of gut microbes or generation of TMAO may become a potential target for the prevention and treatment of cardiac hypertrophy.', 30068915);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5089, 'mouse', 'null', 'Transverse aortic constriction (TAC) was performed to induce cardiac hypertrophy in Sprague-Dawley (SD) rats. We observed that TMAO levels were significantly elevated in SD rats after 6 weeks of TAC, suggesting the potential role of TMAO in regulating cardiac hypertrophy. In cultured cardiomyocytes, TMAO treatment stimulated cardiac hypertrophy, as indicated by increased cell area of cardiomyocytes and expression of hypertrophic markers including atrial natriuretic peptide (ANP) and beta-myosin heavy chain (β-MHC). Additionally, TMAO treatment induced cardiac hypertrophy and cardiac fibrosis in SD rats. Reducing TMAO synthesis by antibiotics (Abs) attenuated TAC-induced cardiac hypertrophy and fibrosis. Furthermore, pharmacological inhibition of Smad3 by SIS3 significantly reduced the expression of ANP and β-MHC, and cardiomyocyte cell size in TMAO-treated group. These data for the first time demonstrate that gut microbe-derived metabolite TMAO induces cardiac hypertrophy and fibrosis involving Smad3 signaling, suggesting that inhibition of gut microbes or generation of TMAO may become a potential target for the prevention and treatment of cardiac hypertrophy.', 30068915);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5090, 'mouse', 'Linoelaidic acid', 'Therefore, in this study, we investigated the effects of KetoA [10-oxo-12(Z)-octadecenoic acid]—a linoleic acid metabolite produced by gut lactic acid bacteria—on whole-body energy metabolism and found that dietary intake of KetoA could enhance energy expenditure in mice, thereby protecting mice from diet-induced obesity.', 28754711);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5091, 'mouse', 'Linoelaidic acid', 'Ucp1 expression levels were also observed to have increased after administration of KetoA.', 28754711);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5092, 'mouse', 'Linoelaidic acid', 'We also confirmed that administration of KetoA induced not only Ucp1, but other genes that are related to BAT function, such as b3AR, Pgc1a , Cpt1b , and Tbx1  in BAT and inguinal WAT of WT\nmice.', 28754711);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5093, 'mouse', 'Linoelaidic acid', 'We also confirmed that administration of KetoA induced not only Ucp1, but other genes that are related to BAT function, such as b3AR, Pgc1a , Cpt1b , and Tbx1  in BAT and inguinal WAT of WT\nmice.', 28754711);
