INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5323, 'mouse', 'null', 'To test this hypothesis, we evaluated the histone modifications H3K27Ac and H3K4me3, which are typically regarded as markers that lead to transcriptional activation, andH3K9me3,which correlates to transcriptional repression (Fig. 5F). ADR led to significant reductions of the activation marker H3K27Ac at the promoter region of both Synpo and Nphs1 genes, which was recovered in the presence of butyrate. In parallel, the increase of the repressive marker H3K9me3 that is due to ADR at the promoter region on both Synpo and Kirrel genes was significantly reduced in the presence of butyrate. Indeed, podocytes grown in vitro showed preserved expression of synaptopodin (Fig. 5G) after treatmentwith butyrate in the presence of ADR.', 31366236);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5324, 'mouse', 'null', 'To test this hypothesis, we evaluated the histone modifications H3K27Ac and H3K4me3, which are typically regarded as markers that lead to transcriptional activation, andH3K9me3,which correlates to transcriptional repression (Fig. 5F). ADR led to significant reductions of the activation marker H3K27Ac at the promoter region of both Synpo and Nphs1 genes, which was recovered in the presence of butyrate. In parallel, the increase of the repressive marker H3K9me3 that is due to ADR at the promoter region on both Synpo and Kirrel genes was significantly reduced in the presence of butyrate. Indeed, podocytes grown in vitro showed preserved expression of synaptopodin (Fig. 5G) after treatmentwith butyrate in the presence of ADR.', 31366236);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5325, 'mouse', 'null', 'To test this hypothesis, we evaluated the histone modifications H3K27Ac and H3K4me3, which are typically regarded as markers that lead to transcriptional activation, andH3K9me3,which correlates to transcriptional repression (Fig. 5F). ADR led to significant reductions of the activation marker H3K27Ac at the promoter region of both Synpo and Nphs1 genes, which was recovered in the presence of butyrate. In parallel, the increase of the repressive marker H3K9me3 that is due to ADR at the promoter region on both Synpo and Kirrel genes was significantly reduced in the presence of butyrate. Indeed, podocytes grown in vitro showed preserved expression of synaptopodin (Fig. 5G) after treatmentwith butyrate in the presence of ADR.', 31366236);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5326, 'mouse', 'null', 'Podocytes grown in vitro in the presence of ADR exhibited significantly increased TRPC5 and TRPC6 gene transcriptions, which were abolished when podocytes were incubated with buty rate.', 31366236);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5327, 'mouse', 'null', 'Podocytes grown in vitro in the presence of ADR exhibited significantly increased TRPC5 and TRPC6 gene transcriptions, which were abolished when podocytes were incubated with buty rate.', 31366236);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5328, 'mouse', 'null', 'Here, the presence of ADR in podocytes grown in vitro decreased the expression levels of RHOA, RAC1, and CDC42, whereas treatmentwith butyrate significantly recovered the levels of both RAC1 and CDC42 but not RHOA.', 31366236);
