INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5346, 'mouse', 'Linoleic acid', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 25505251);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5347, 'mouse', 'Linoleic acid', 'The pretreatment of HYA suppressed IFN-induced up-regulation of TNFR2 (but not TNFR1), and it subsequently decreased the ratio of phospho-INF-B p65 expression induced by cytokines (Fig. 3, B and C). In contrast, pretreatment of HYB did not show the same inhibitory effects as HYA.', 25505251);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5348, 'mouse', 'Linoleic acid', 'It was noteworthy that the pretreatment of HYA augmented the mRNA expression of GPR40 and GPR43 but not GPR120, PPAR, and GPR41 in Caco-2 cells (Fig. 4A). However, the pretreatment of HYB did not up-regulate GPR40 and GPR43 expression (Fig. 4A).', 25505251);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5349, 'mouse', 'null', 'The expression levels of IL�? (Fig. 5A and B) and its receptors CXCR1 (Fig. 5A and C) and CXCR2 (Fig. 5A and D) were significantly increased in the non‑infarct LV of MI + VEH rats compared with the LV of SHAM + VEH rats; however, the expression of these proteins was normalized by DMB treatment.', 31180562);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5350, 'mouse', 'null', 'The expression levels of IL�? (Fig. 5A and B) and its receptors CXCR1 (Fig. 5A and C) and CXCR2 (Fig. 5A and D) were significantly increased in the non‑infarct LV of MI + VEH rats compared with the LV of SHAM + VEH rats; however, the expression of these proteins was normalized by DMB treatment.', 31180562);
