INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5352, 'mouse', 'null', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5353, 'mouse', 'null', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5354, 'mouse', 'null', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5355, 'mouse', 'null', 'Consistent with our previous report, the expression of the senescence inducers p21 (encoded by Cdkn1a) and p16 (encoded by Cdkn2a) was upregulated by DCA treatment (Fig. 3B). Notably, the expression levels of TLR2 and SASP factors, such as IL1β, Groα, and IL6, were significantly enhanced by LTA in DCA-induced senescent HSCs (Fig. 3C).', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5356, 'mouse', 'null', 'Consistent with our previous report, the expression of the senescence inducers p21 (encoded by Cdkn1a) and p16 (encoded by Cdkn2a) was upregulated by DCA treatment (Fig. 3B). Notably, the expression levels of TLR2 and SASP factors, such as IL1β, Groα, and IL6, were significantly enhanced by LTA in DCA-induced senescent HSCs (Fig. 3C).', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5357, 'mouse', 'null', 'The expression of COX2, but not COX1, in DCA-treated primary HSCs was significantly induced by increasing amounts of LTA (Fig. 4C), and the COX2 expression was dependent on TLR2 (Supplementary \nFig. S3). Indeed, we confirmed that TLR2 was expressed in HSCs and this expression was enhanced by LTA alone or DCA plus LTA treatment (Supplementary Fig. S8A).', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5358, 'mouse', 'null', 'The production of IFNγ and TNFα, which are known to activate antitumor immune responses and inhibit cancer cell growth, was significantly and specifically attenuated by PGE2.', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5359, 'mouse', 'null', 'The production of IFNγ and TNFα, which are known to activate antitumor immune responses and inhibit cancer cell growth, was significantly and specifically attenuated by PGE2.', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5360, 'mouse', 'null', 'In contrast, the production of IL10, a potent anti-inflammatory cytokine, and IL6, a known tumor-promoting cytokine, in immune cells was slightly but significantly enhanced (Supplementary Fig. S8D).', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5361, 'mouse', 'null', 'In contrast, the production of IL10, a potent anti-inflammatory cytokine, and IL6, a known tumor-promoting cytokine, in immune cells was slightly but significantly enhanced (Supplementary Fig. S8D).', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5362, 'mouse', 'null', 'PGE2 is known to be recognized by four types of receptors: PTGER1, PTGER2, PTGER3, and PTGER4 (37, 38). In our mouse model, the expression of PTGER4, but not other PGE2 receptors, was significantly upregulated in tumor tissues (Fig. 5C),', 28202625);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5363, 'mouse', 'null', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5364, 'mouse', 'null', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5365, 'mouse', 'null', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5366, 'mouse', 'null', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5367, 'mouse', 'null', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5368, 'mouse', 'null', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
