INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5585, 'mouse', 'Phytic acid', 'Taken together, these data demonstrate bacterial-intrinsic phytate metabolism and provoke the hypothesis that breakdown of phytate by microbiota promotes intestinal HDAC activity.', 32731255);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5586, 'mouse', 'null', 'Further, colonization of germ-free (GF) mice with butyrate producing bacteria,Faecalibacterium prausnitzii, inhibited IEC-intrinsic HDAC activity.', 32731255);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5587, 'mouse', 'null', 'CNV mice exhibited significantly higher IP3 in both the intestinal lumen (Fig. 1e) and colonic IECs (Fig. 1f), supporting that microbiota promote increased IP3. To assess the effect of IP3 on epithelial HDAC3 activity, HDAC3 was purified by immunoprecipitation from IECs and incubated with IP3. IP3 increased endogenous HDAC3 activity (Fig. 1g), supporting that IP3 directly activates HDAC3 in IECs.', 32731255);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5588, 'mouse', 'null', 'Although less potent than IP3, IP4 also increased HDAC activity in IECs (Extended Data Fig. 5f), suggesting that other inositol phosphates simultaneously generated by phytate metabolism may provide synergistic effects.', 32731255);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5589, 'mouse', 'Glutamic acid', 'Glutamate, the agonist of NMDAR and a major excitatory neurotransmitter in the mammalian central nervous system (CNS) [6], is intracellularly located and extensively distributed in the brain.', 32290475);
