INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5591, 'mouse', 'Glutamic acid', 'Non-pathogenic bacteria with glutamate racemase including Corynebacterium glutamicum, Brevibacterium lactofermentum, Brevibacterium avium [121], Mycobacterium smegmatis[122], and Bacillus subtilis[123] convert l-glutamate to d-glutamate.', 32290475);
