INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5597, 'mouse', 'null', 'Furthermore, benzoate, an inhibitor of d-amino acid oxidases (DAAO), can increase d-serine,thereby enhancing NMDAR activation [125,126].', 32290475);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5598, 'mouse', 'Bile acid', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 32668198);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5599, 'mouse', 'Bile acid', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 32668198);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5600, 'mouse', 'Tryptophan', 'HSD significantly reduces intestinal Lactobacillus murinus in hypertensive FVB/N mice, while L murinus can metabolize trypto phan in the diet to produce indole, thereby inhibiting T lymphocyte differentiation into Th17 cells, alleviating inflammation and lowering BP.', 32078445);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5601, 'mouse', 'null', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5602, 'mouse', 'null', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
