INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5605, 'mouse', 'null', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5606, 'mouse', 'null', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5607, 'mouse', 'null', 'We determined that CA7S is a potent agonist of the G-protein-coupled recep tor TGR5 (GPBAR1) and induces GLP-1 secretion. When administered to diet-induced obese (DIO) mice, CA7S in creases insulin secretion and induces systemic glucose clearance.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5608, 'mouse', 'null', 'We determined that CA7S is a potent agonist of the G-protein-coupled recep tor TGR5 (GPBAR1) and induces GLP-1 secretion. When administered to diet-induced obese (DIO) mice, CA7S in creases insulin secretion and induces systemic glucose clearance.', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5609, 'mouse', 'null', 'Consistent with our in vitro results showing that LCA inhibits expression of Asbt and Osta, SG-CMT mice exhibited significantly higher levels of Asbt and Osta expression in the distal ileum compared with sham-CMT (Figure 7E).', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5610, 'mouse', 'null', 'Consistent with our in vitro results showing that LCA inhibits expression of Asbt and Osta, SG-CMT mice exhibited significantly higher levels of Asbt and Osta expression in the distal ileum compared with sham-CMT (Figure 7E).', 33434516);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5611, 'mouse', 'Trimethylamine', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5612, 'mouse', 'Trimethylamine', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
