INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5614, 'mouse', 'Trimethylamine', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5615, 'mouse', 'Trimethylamine', 'Next, we measured the pro-inflammatory tran scription factor nuclear factor kappa B (NF-κB), which is a key regulator of pro-inflammatory cytokine signal ing. Although abundance of phosphorylated (i.e., acti vated) NF-κB was similar between brains from young and old mice (p = 0.49), old mice had ~ 50% higher abundance of total NF-κB (p < 0.001; Fig. 3b), suggest ing a greater capacity to upregulate pro-inflammatory cytokine production.', 32862276);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5616, 'mouse', 'Trimethylamine', 'Finally, LCN2, an established marker of reactive astrocytes involved in the innate immune response to bacteria [5, 63], was higher in brain lysates from old compared to young mice (p < 0.05;Fig. 3c).', 32862276);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5617, 'mouse', 'null', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5618, 'mouse', 'null', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5619, 'mouse', 'null', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5620, 'mouse', 'null', 'mRNA levels of TNF-α and IL-1β in the WAT of ob/ob mice were, respectively, 17- and 4-fold higher than those of C57BL/6 J mice (Fig. 2A). Te iNOS and COX-2 in WAT were also, respectively, 5.4- and 2.2-fold higher than those of C57BL/6 J mice (Fig. 2A). Hepatic gene expression of IL-6 was signifcantly increased in ob/ob mice compared with C57BL/6 J mice although TNF-α and IL-1β were not markedly increased (Fig. 2B).', 32296105);
