INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5625, 'mouse', 'null', 'As a result, stercobilin signifcantly induced NF-κB reporter gene activities in a dose-dependent manner (Fig. 6A). Additionally, ster cobilin signifcantly induced expression of several infammation-related genes, including TNF-α, IL-1β, IL-6, iNOS, and COX-2 (Fig. 6B).', 32296105);
