INSERT INTO `gut_microbiota_metabolite_generation_results` (`index`, `host_type`, `substrate_name`, `description`, `Evidence`) VALUES (5653, 'mouse', 'null', 'The expression of IL-1, IL-17 and TNF-α were higher in the intestinal tract of the germ free mice that had not received a human flora fecal transplant than in those that had received a fecal transplant, and the expression of IL-1, IL 17 and TNF-α decreased significantly after the fecal transplant (Fig. 4c, p < 0.01).', 33233042);
