INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3072, 'human', 'null', 'Bile acid', 'null', 'Deoxycholic acid (DCA) and lithocholic acid (LCA) are secondary bile acids that are generated in the gut by bacterial transformation of primary bile acids, cholic acid(CA), and chenodeoxycholic acid (CDCA), respectively.The proposed pathway for this transformation by Clostridium scindens VPI 12708.', 23836456);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3073, 'human', 'null', 'Cholic acid', 'null', 'Deoxycholic acid (DCA) and lithocholic acid (LCA) are secondary bile acids that are generated in the gut by bacterial transformation of primary bile acids, cholic acid(CA), and chenodeoxycholic acid (CDCA), respectively.The proposed pathway for this transformation by Clostridium scindens VPI 12708.', 23836456);
