INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3088, 'human', 'null', 'Cynaroside', 'null', 'Eubacterium ramulus, a quercetin-3-glucoside degrading anaerobic microorganism that occurs at num bers of approximately 108/g dry feces in humans, was tested for its ability to transform other flavonoids. The organism degraded luteolin-7-glucoside, rutin, quercetin, kaempferol, luteolin, eriodictyol, naringenin, taxifolin, and phloretin to phenolic acids. It hydrolyzed kaempferol-3-sorphoro side-7-glucoside to kaempferol-3-sorphoroside and trans formed 3,4-dihydroxyphenylacetic acid, a product of anaer obic quercetin degradation, very slowly to non-aromatic fermentation products.', 10648107);
