INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3104, 'human', 'null', 'Kaempferol', 'null', 'In addition,the identity of fermentation products 3,4-dihydroxyphenylacetic acid, formed from quercetin-3-glucosdide, or taxifolin, 3-(3,4 dihydroxyphenyl)propionic acid, formed from luteolin or eriodictyol, and 4-hydroxyphenylacetic acid, formed from kaempferol, were confirmed by LC-MS/MS. The most intensive ion peaks in the mass spectra of these compounds are listed in Table 2.', 10648107);
