INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3107, 'human', 'null', 'Quercetin', 'null', 'Luteolin-5-glucoside, diosmetin-7rutinoside, naringenin-7-neohesperidoside, (+)-catechin, and (�?-epicatechin were not degraded. Cell extracts of E. ramulus contained α- and β-D-glucosidase activities, but were devoid of α-L-rhamnosidase activity.', 10648107);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3108, 'human', 'null', 'null', 'null', 'Schneider et al. (1999) isolated strains of Eubacterium ramulus from human feces that are capable of degrading quercetin-3-glucoside to 3,4-dihydroxyphenylacetic acid (3,4-DIOHA), butyrate, and acetate.Phloroglucinol was formed as an intermediate.', 10648107);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3109, 'human', 'decrease', 'null', 'low-throughput', 'Indoxyl-sulfate (Beta(SE) = -2.74(0.24), P = 8.8x10-29),p-cresyl-sulfate (-1.99(0.24), P = 4.6x10-16), and phenylacetylglutamine (-2.73(0.25),P = 1.2x10-25) were significantly and negatively associated with eGFR after adjusting for age, sex, body mass index (BMI), metabolite batch, type 2 diabetes, family relatedness and multiple testing using Bonferroni correction (Table 2).', 26241311);
