INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3123, 'human', 'null', 'Daidzein', 'null', 'A newly identified equol-producing bacterium, Slackia sp.strain NATTS, with a high equol-producing activity was isolated from human feces in Japanese adults.', 24761887);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3124, 'human', 'null', 'D-Glucose', 'null', 'endogenous capability of Escherichia coli for 2,3-butanediol (2,3-BD) synthesis was explored using the anaerobic selection platform based on redox balance. To address the issue of NADH excess associated with the 2,3-BD pathway, we devised a substrate-decoupled system where a pathway intermediate is externally supplied in addition to the carbon source to decouple NADH recycling ratio from the intrinsic pathway stoichiometry.', 27931827);
