INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3138, 'human', 'null', 'Hesperetin dihydrochalcone', 'null', 'C.orbiscindens was not able to convert hesperetindihydrochalcone 4�?â-D-glucoside within a period of 43 h, whereas the aglycon was cleaved by this species. C. orbiscindens formed 0.18 mM 3-(3-hydroxy-4-methoxyphenyl)propionic acid from 0.26 mM hesperetin dihydrochalcone within 23 h of incubation.', 15740074);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3139, 'human', 'null', 'beta-D-Glucopyranoside, 3,5-dihydroxy-4-(3-(3-hydroxy-4-methoxyphenyl)-1-oxopropyl)phenyl', 'null', 'However, hesperetin dihydrochalcone 4�?â-D-glucoside was converted by E. ramulus to hesperetin dihydrochalcone and further to 3-(3-hydroxy-4-methoxyphenyl)propionic acid, but not by C. orbiscindens.', 15740074);
