INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3170, 'human', 'increase', 'null', 'low-throughput', 'We also measured MUC2 mRNA levels in the butyrate-treated cells, and found that 1 mM butyrate treatment for 36 h increased the cellular MUC2 mRNA levels, although the fold increase was less than that for MUC2 proteins (Fig. 3B). These results show that buty rate treatment inhibits the proliferation of LS174T cells but concomitantly increases MUC2 production per cell.', 17374366);
