INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3250, 'human', 'null', 'Succinate', 'null', 'PY broth tube tests indicated that strains YIT 12067T and YIT 12068 grew well only in PY medium supplemented with succinate. HPLC analysis showed that succinate was quantitatively converted to propionate. These results indicate that succinate decarboxylation stimulated the growth of strains YIT 12067T and YIT 12068.', 22081579);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3251, 'human', 'null', 'Succinate', 'null', 'PY broth tube tests indicated that strains YIT 12067T and YIT 12068 grew well only in PY medium supplemented with succinate. HPLC analysis showed that succinate was quantitatively converted to propionate. These results indicate that succinate decarboxylation stimulated the growth of strains YIT 12067T and YIT 12068.', 22081579);
