INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3391, 'human', 'null', 'null', 'null', 'Streptococcus sp. MRG-ICA-B isolated from human intestine were reacted with icariin under anaerobic conditions. The MRG-ICA-B and E strains hydrolyzed only the glucose moiety of icariin, and icariside II was the only metabolite.', 27589718);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3392, 'human', 'null', 'null', 'null', 'Enterococcus sp. MRG-ICA-E isolated from human intestine were reacted with icariin under anaerobic conditions. The MRG-ICA-B and E strains hydrolyzed only the glucose moiety of icariin, and icariside II was the only metabolite.', 27589718);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3393, 'human', 'null', 'null', 'null', 'Blautia sp. MRG-PMF-1 isolated from human intestine were reacted with icariin under anaerobic conditions. It not only produced icariside II  but strain metabolized icariin further to desmethylicaritin via icariside II and icaritin.', 27589718);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3394, 'human', 'null', 'null', 'null', 'Blautia sp. MRG-PMF-1 isolated from human intestine were reacted with icariin under anaerobic conditions. It not only produced icariside II  but strain metabolized icariin further to desmethylicaritin via icariside II and icaritin.', 27589718);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3395, 'human', 'null', 'Puerarin', 'null', 'Puerarin was completely converted to daidzein within 100 min by Lactococcus sp. MRG-IFC-1 and Enterococcus sp. MRG-IFC-2, which is the fastest conversion among the reported human intestinal bacteria.', 25199800);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3396, 'human', 'null', 'Puerarin', 'null', 'Puerarin was completely converted to daidzein within 100 min by Lactococcus sp. MRG-IFC-1 and Enterococcus sp. MRG-IFC-2, which is the fastest conversion among the reported human intestinal bacteria.', 25199800);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3397, 'human', 'null', 'Isoquercitrin', 'null', 'From human feces two phenotypically different types of bacteria were isolated on quercetin-3-gluco_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x0002_side as carbon and energy source. Isolates of one type were identified as strains of Enterococcus casseliflavus. The sugar moiety (4 mM) was fermented to 5.5 ± 2.1 mM formate, 2.1 ± 0.7 mM acetate,1.6 ± 0.3 mM L-lactate, and 1.3 ± 0.4 mM ethanol. The second type of isolate was identified as Eubacterium ramulus. This organism was capable of degrading the aromatic ring system. Growing cultures of Eubacterium ramulus converted 5 mM quercetin-3-glucoside to 1.7 ± 0.6 mM 3,4-dihydroxyphenylacetic acid, 7.6 ± 1.0 mM acetate, and 4.0 ± 0.4 mM butyrate.', 9914304);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3398, 'human', 'null', 'Isoquercitrin', 'null', 'From human feces two phenotypically different types of bacteria were isolated on quercetin-3-gluco_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x005f_x0002_side as carbon and energy source. Isolates of one type were identified as strains of Enterococcus casseliflavus. The sugar moiety (4 mM) was fermented to 5.5 ± 2.1 mM formate, 2.1 ± 0.7 mM acetate,1.6 ± 0.3 mM L-lactate, and 1.3 ± 0.4 mM ethanol. The second type of isolate was identified as Eubacterium ramulus. This organism was capable of degrading the aromatic ring system. Growing cultures of Eubacterium ramulus converted 5 mM quercetin-3-glucoside to 1.7 ± 0.6 mM 3,4-dihydroxyphenylacetic acid, 7.6 ± 1.0 mM acetate, and 4.0 ± 0.4 mM butyrate.', 9914304);
