INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3408, 'human', 'null', 'Daidzein', 'null', 'We isolated nine strains capable of metabolizing isoflavones to equol from human faeces. Seven of these strains could metabolize daidzein via dihydrodaidzein to equol, while the other two isolates could metabolize only dihydrodaidzein to equol.', 18450717);
