INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3425, 'human', 'null', 'D-Glucose', 'null', 'Acetate is readily absorbed from the rumen and subsequently used in fatty acid metabolism.', 8481001);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3426, 'human', 'null', 'D-Glucose', 'null', 'Succinate and formate, on the other hand, are considered intermediates of rumen fermentation which are further metabolized by other organisms. Succinate is thought to be an important intermediate for propionate formation , with the latter being readily absorbed from the rumen for gluconeogenesis.', 8481001);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3427, 'human', 'null', 'D-Glucose', 'null', 'Succinate and formate, on the other hand, are considered intermediates of rumen fermentation which are further metabolized by other organisms. Formate has been shown to be metabolized to methane by rumen methanogens.', 8481001);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3428, 'human', 'null', 'D-Glucose', 'null', 'Lactate is also an intermediate of the overall rumen fermentation and, when present in excess, has been correlated with acidosis.', 8481001);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3429, 'human', 'null', 'D-Glucose', 'null', 'Lactic acid bacteria, because the bifidobacterial pathway yields 2.5 ATP molecules from 1 mol of fermented glucose, as well as 1.5 mol of acetate and 1 mol of lactate [94]. In contrast, the homofermenta tive group of lactic acid bacteria (LAB) produces 2 mol of ATP and 2 mol of lactic acid from 1 mol of glucose, whereas heterofermentative LAB produce 1 mol each of lactic acid, ethanol and ATP per 1 mol of fermented glu cose.', 21484167);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3430, 'human', 'null', 'D-Glucose', 'null', 'Lactic acid bacteria, because the bifidobacterial pathway yields 2.5 ATP molecules from 1 mol of fermented glucose, as well as 1.5 mol of acetate and 1 mol of lactate [94]. In contrast, the homofermenta tive group of lactic acid bacteria (LAB) produces 2 mol of ATP and 2 mol of lactic acid from 1 mol of glucose, whereas heterofermentative LAB produce 1 mol each of lactic acid, ethanol and ATP per 1 mol of fermented glu cose.', 21484167);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3431, 'human', 'null', 'D-Glucose', 'null', 'Lactic acid bacteria, because the bifidobacterial pathway yields 2.5 ATP molecules from 1 mol of fermented glucose, as well as 1.5 mol of acetate and 1 mol of lactate [94]. In contrast, the homofermenta tive group of lactic acid bacteria (LAB) produces 2 mol of ATP and 2 mol of lactic acid from 1 mol of glucose, whereas heterofermentative LAB produce 1 mol each of lactic acid, ethanol and ATP per 1 mol of fermented glu cose.', 21484167);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3432, 'human', 'null', 'null', 'null', 'Due to the fact that bifidobacteria produce lactic acid as one of their main fermentation end products, they are often included in the lactic acid bacteria (LAB).', 21484167);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3433, 'human', 'null', '5,7-Dimethoxyflavone', 'null', 'Activity-guided screening for PMF-metabolizing intestinal bacteria under anaerobic conditions resulted in the isolation of a strict anaerobic bacterium, which was identified as Blautia sp. MRG-PMF1. The isolated MRGPMF1 was able to metabolize various PMFs to the corresponding demethylated flavones.The microbial conversion of bioactive 5,7-dimethoxyflavone (5,7-DMF) and 5,7,4�?trimethoxyflavone (5,7,4�?TMF) was studied in detail. 5,7-DMF and 5,7,4�?TMF were completely metabolized to 5,7-dihydroxyflavone (chrysin) and 5,7,4�?trihydroxyflavone (apigenin), respectively.', 25437273);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3434, 'human', 'null', '4\',5,7-Trimethoxyflavone', 'null', 'Activity-guided screening for PMF-metabolizing intestinal bacteria under anaerobic conditions resulted in the isolation of a strict anaerobic bacterium, which was identified as Blautia sp. MRG-PMF1. The isolated MRGPMF1 was able to metabolize various PMFs to the corresponding demethylated flavones.The microbial conversion of bioactive 5,7-dimethoxyflavone (5,7-DMF) and 5,7,4�?trimethoxyflavone (5,7,4�?TMF) was studied in detail. 5,7-DMF and 5,7,4�?TMF were completely metabolized to 5,7-dihydroxyflavone (chrysin) and 5,7,4�?trihydroxyflavone (apigenin), respectively.', 25437273);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3435, 'human', 'null', 'Ellagic Acid', 'null', 'Four gut bacteria strains (CEBAS 4A1, 4A2, 4A3, 4A4)isolated from a healthy donor and able to produce urolithins M6, C and isourolithin A, are described in the present study.Strains were found at high concentrations (�?07 cfu g�?feces).Comparison of the 16S rRNA gene sequences of the strains showed that the four isolates belong to the same species and that they are phylogenetically members of the family Eggerthellaceae.', 28824607);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3436, 'human', 'null', 'Ellagic Acid', 'null', 'Four gut bacteria strains (CEBAS 4A1, 4A2, 4A3, 4A4)isolated from a healthy donor and able to produce urolithins M6, C and isourolithin A, are described in the present study.Strains were found at high concentrations (�?07 cfu g�?feces).Comparison of the 16S rRNA gene sequences of the strains showed that the four isolates belong to the same species and that they are phylogenetically members of the family Eggerthellaceae.', 28824607);
