INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3440, 'human', 'null', 'DL-Alanine', 'null', 'For example, if R1 is a methyl group (-CH3), then the donor amino acid is an alanine, and the product of the oxidative deamination would be pyruvate, a central compounds of the intermediary metabolism.', 22325238);
