INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3451, 'human', 'increase', 'null', 'low-throughput', 'These data show that B dentium–secreted products, including acetate, can modulate 5-HT production by host enterochromaffin cells.', 32795610);
