INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3454, 'human', 'decrease', 'null', 'low-throughput', 'Conversely, enteroids treated with 10 mM BUT and PROP had a greater than 10-fold decrease in LGR5 compared to controls (CON; P < 0.05; Fig 4b). Only 1mM treatment of BUT was able to significantly decrease LGR5 expression (P < 0.05; Fig 4a).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3455, 'human', 'increase', 'null', 'low-throughput', 'Treatment with 10 mM SCFA significantly increased ALPI expression treatments but was highest (11-fold) in enteroids treated with PROP. There was no difference in ALPI expression in enteroids treated with 1 mM SCFAs (P > 0.05).', 32240190);
