INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3458, 'human', 'increase', 'null', 'low-throughput', 'Gene expression of MUC2 was increased 2-fold due to ACET treatment and 5-fold due to BUT treatment (P < 0.05; Fig 4b) but was not increased due to PROP treatment. There was no difference in MUC2 expression in enteroids treated with 1 mM SCFAs (P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3459, 'human', 'increase', 'null', 'low-throughput', 'Gene expression of MUC2 was increased 2-fold due to ACET treatment and 5-fold due to BUT treatment (P < 0.05; Fig 4b) but was not increased due to PROP treatment. There was no difference in MUC2 expression in enteroids treated with 1 mM SCFAs (P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3460, 'human', 'increase', 'null', 'low-throughput', 'Lysozyme (LYZ) increased due to BUT alone (P < 0.05)however there was no difference in ALPI expression in enteroids treated with 1 mM SCFAs(P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3461, 'human', 'increase', 'null', 'low-throughput', 'Enteroendocrine cell marker CHGA was significantly increased (170-fold) in BUT treated enteroids. There was no difference in CHGA expression in enteroids treated with 1\nmM SCFAs (P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3462, 'human', 'increase', 'null', 'low-throughput', 'Tuft cell marker DCLK1 was significantly elevated due to ACET(7-fold) and BUT (14-fold) treatment compared to CON (P < 0.05; Fig 4b). 1 mM ACET,BUT and PROP significantly increased DCLK1 expression (5-fold, 3.6-fold, and 5.8-fold,respectively; P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3463, 'human', 'increase', 'null', 'low-throughput', 'Tuft cell marker DCLK1 was significantly elevated due to ACET(7-fold) and BUT (14-fold) treatment compared to CON (P < 0.05; Fig 4b). 1 mM ACET,BUT and PROP significantly increased DCLK1 expression (5-fold, 3.6-fold, and 5.8-fold,respectively; P < 0.05).', 32240190);
