INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3465, 'human', 'increase', 'null', 'low-throughput', 'Anti-microbial peptide gene expression of REG3β and REG3γ (Fig 4b)were not increased due to ACET treatment, however, were significantly increased due to BUT(2.5-fold and 3-fold, respectively) compared to CON. There was no difference in REG3β and REG3γ expression in enteroids treated with 1 mM SCFAs (P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3466, 'human', 'increase', 'null', 'low-throughput', 'Anti-microbial peptide gene expression of REG3β and REG3γ (Fig 4b)were not increased due to ACET treatment, however, were significantly increased due to BUT(2.5-fold and 3-fold, respectively) compared to CON. There was no difference in REG3β and REG3γ expression in enteroids treated with 1 mM SCFAs (P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3467, 'human', 'increase', 'null', 'low-throughput', 'β-defensin 1 (DEFB1)was increased 75-fold and 66-fold respectively in BUT and PROP treated enteroids (P < 0.05; Fig4b).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3468, 'human', 'increase', 'null', 'low-throughput', 'β-defensin 1 (DEFB1)was increased 75-fold and 66-fold respectively in BUT and PROP treated enteroids (P < 0.05; Fig4b).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3469, 'human', 'increase', 'null', 'low-throughput', 'Tight junction marker expression of OCLN was only significantly elevated in ACET treated enteroids (4-fold; P < 0.05,Fig 4b).There was no difference in OCLN expression in enteroids treated with 1 mM SCFAs(P > 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3470, 'human', 'increase', 'null', 'low-throughput', 'CLDN3 and TJP1 were increased due to both ACET and BUT treatments(P < 0.05, Fig 4b). There was no difference in CLDN3 expression in enteroids treated with 1 mM SCFAs (P > 0.05), however 1 mM BUT decreased TJP1 expression more than 2-fold (P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3471, 'human', 'increase', 'null', 'low-throughput', 'CLDN3 and TJP1 were increased due to both ACET and BUT treatments(P < 0.05, Fig 4b). There was no difference in CLDN3 expression in enteroids treated with 1 mM SCFAs (P > 0.05), however 1 mM BUT decreased TJP1 expression more than 2-fold (P < 0.05).', 32240190);
