INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3473, 'human', 'increase', 'null', 'low-throughput', 'CLDN3 and TJP1 were increased due to both ACET and BUT treatments(P < 0.05, Fig 4b). There was no difference in CLDN3 expression in enteroids treated with 1 mM SCFAs (P > 0.05), however 1 mM BUT decreased TJP1 expression more than 2-fold (P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3474, 'human', 'increase', 'null', 'low-throughput', 'Tight junction related marker claudin-3 (CLDN3) expression was significantly increased by 10 mM BUT and 10 mM PROP (1.5 and 1.4-fold, respectively; P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3475, 'human', 'increase', 'null', 'low-throughput', 'Occludin (OCLN) expression was significantly increased by 10 mM BUT treatment alone (P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3476, 'human', 'increase', 'null', 'low-throughput', 'Ghrelin was significantly increased by all SCFAs in cell supernatants, with BUT and PROP showing highest concentrations (P < 0.05). Ghrelin was also significantly increased by 10 mM BUT alone in basolateral media (P < 0.05; Table 1).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3477, 'human', 'increase', 'null', 'low-throughput', 'Ghrelin was significantly increased by all SCFAs in cell supernatants, with BUT and PROP showing highest concentrations (P < 0.05). Ghrelin was also significantly increased by 10 mM BUT alone in basolateral media (P < 0.05; Table 1).', 32240190);
