INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3493, 'human', 'null', 'Levodopa', 'null', 'Here, we show that C. sporogenes deaminates levodopa, the main treatment in Parkinson’s disease, and identify the aromatic aminotransferase responsible for the initiation of the deamination pathway. The deaminate metabolite from levodopa, 3-(3,4-dihydroxyphenyl)propionic acid, elicits an inhibitory effect on ileal motility in an ex vivo model.', 33076930);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3494, 'human', 'null', '5-Hydroxytryptophan', 'null', '5-HTP was converted into two new unknown peaks (Additional File1: Fig. S2A, S2B), albeit to a much lesser extent compared to levodopa. Only the first peak could be detected and assigned by LC-MS as 5-hydroxyindole-3-lactic acid (5-HILA) by its predicted exact mass (Additional File 1:Fig. S2C).', 33076930);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3495, 'human', 'null', 'Tryptophan', 'null', 'Tryptophan and tyrosine were converted to their intermediates ILA (indole-3-lactic acid) and 4-HPLA (3-(4-hydroxyphenyl)lactic acid), respectively, as previously shown [11].', 33076930);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3496, 'human', 'null', 'Tyrosine', 'null', 'Tryptophan and tyrosine were converted to their intermediates ILA (indole-3-lactic acid) and 4-HPLA (3-(4-hydroxyphenyl)lactic acid), respectively, as previously shown [11].', 33076930);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3497, 'human', 'null', 'Levodopa', 'null', 'Analogous to tryptophan and tyrosine, levodopa was no longer deaminated to DHPPA but to its intermediate product 3-(3,4-dihydroxy phenyl)lactic acid (DHPLA) (Fig. 1d, e). ', 33076930);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3498, 'human', 'increase', 'null', 'low-throughput', 'The human ortholog HM74a is also a nicotinic acid receptor and likely has a similar role in anti-lipolysis.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3499, 'human', 'increase', 'null', 'low-throughput', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3500, 'human', 'increase', 'null', 'low-throughput', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3501, 'human', 'increase', 'null', 'low-throughput', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3502, 'human', 'increase', 'null', 'low-throughput', 'Both (D)- and (L)-OHB, but not acetoacetate or free acetone, elicited a Ca2 response in cells expressing HM74a but not HM74.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3503, 'human', 'increase', 'null', 'low-throughput', 'Racemic (DL)-OHB also showed some degree of activity on all receptors; however, it was more potent on HM74a and its ortholog PUMA-G  than on HM74.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3504, 'human', 'decrease', 'Diosmetin 7-O-beta-D-glucopyranoside', 'low-throughput', 'A Gram-negative anaerobic bacterium, strain 4, capable of metabolizing diosmetin-7-O-glucoside was newly isolated.Its 16S rRNA sequence displayed 99% similarity with that of Escherichia. Then strain 4 was identified as a species of thegenus Escherichia and was named Escherichia sp. 4. Additionally,  an ultraperformance liquid chromatography/quadrupole-time-of-flight mass spectrometry  technique combined with Metabolynx software method was established to screenthe metabolites of diosmetin-7-O-glucoside.', 25382172);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3505, 'human', 'null', 'Diosmetin 7-O-beta-D-glucopyranoside', 'null', 'A Gram-negative anaerobic bacterium, strain 4, capable of metabolizing diosmetin-7-O-glucoside was newly isolated.Its 16S rRNA sequence displayed 99% similarity with that of Escherichia. Then strain 4 was identified as a species of thegenus Escherichia and was named Escherichia sp. 4. Additionally,  an ultraperformance liquid chromatography/quadrupole-time-of-flight mass spectrometry  technique combined with Metabolynx software method was established to screenthe metabolites of diosmetin-7-O-glucoside.', 25382172);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3506, 'human', 'increase', 'null', 'low-throughput', 'We analyzed 50 colon adenomas from AA patients for both microsatellite instability (MSI) and the methylation status of SLC5A8 gene. This gene\'s product is involved in the transport of butyrate that has anti-proliferative properties through its effects on histone acetylation and gene expression. A proteomic analysis to check the expressed histones in adenoma and normal tissues was also performed.No association was found between SLC5A8 methylation and the MSI status. Also, there was no association between SLC5A8 methylation and the sex and age of the patients. However, there were more right sided adenomas with SLC5A8 methylation than the left sided ones. The proteomic analysis revealed distinct histone expression profiles between normal and adenoma tissues.SLC5A8 is highly methylated in AA colon adenomas which points to its potential use as a marker for early detection. The MSI rate is similar to that found in colon cancer tumors in AAs. These findings suggest that both processes stem from the same epigenetic and genetic events occurring at an early stage in colon carcinogenesis in AAs.', 21687703);
