INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3508, 'human', 'increase', 'null', 'low-throughput', 'We analyzed 50 colon adenomas from AA patients for both microsatellite instability (MSI) and the methylation status of SLC5A8 gene. This gene\'s product is involved in the transport of butyrate that has anti-proliferative properties through its effects on histone acetylation and gene expression. A proteomic analysis to check the expressed histones in adenoma and normal tissues was also performed.No association was found between SLC5A8 methylation and the MSI status. Also, there was no association between SLC5A8 methylation and the sex and age of the patients. However, there were more right sided adenomas with SLC5A8 methylation than the left sided ones. The proteomic analysis revealed distinct histone expression profiles between normal and adenoma tissues.SLC5A8 is highly methylated in AA colon adenomas which points to its potential use as a marker for early detection. The MSI rate is similar to that found in colon cancer tumors in AAs. These findings suggest that both processes stem from the same epigenetic and genetic events occurring at an early stage in colon carcinogenesis in AAs.', 21687703);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3509, 'human', 'null', 'null', 'null', 'In vitro cultivation of PD demonstrated its capacity to transform bile acids and production of succinate. Succinate supplementation in the diet decreased hyperglycemia in ob/ob mice via the activation of intestinal gluconeogenesis (IGN). Gavage with a mixture of LCA and UDCA reduced hyperlipidemia by activating the FXR pathway and repairing gut barrier integrity. Co-treatment with succinate and LCA/UDCA mirrored the benefits of LPD. The binding target of succinate was identified as fructose-1,6-bisphosphatase, the rate-limiting enzyme in IGN. The succinate and secondary bile acids produced by P. distasonis played key roles in the modulation of host metabolism.', 30605678);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3510, 'human', 'null', 'null', 'null', 'In vitro cultivation of PD demonstrated its capacity to transform bile acids and production of succinate. Succinate supplementation in the diet decreased hyperglycemia in ob/ob mice via the activation of intestinal gluconeogenesis (IGN). Gavage with a mixture of LCA and UDCA reduced hyperlipidemia by activating the FXR pathway and repairing gut barrier integrity. Co-treatment with succinate and LCA/UDCA mirrored the benefits of LPD. The binding target of succinate was identified as fructose-1,6-bisphosphatase, the rate-limiting enzyme in IGN. The succinate and secondary bile acids produced by P. distasonis played key roles in the modulation of host metabolism.', 30605678);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3516, 'human', 'null', 'Clindamycin', 'null', 'In the CDI chemostat model, clindamycin decreased valerate and deoxycholic acid concentrations and increased C difficile total viable counts (TVC) and valerate precursors, taurocholic acid, and succinate concentrations. After we stopped adding clindamycin, levels of bile acids and succinate recovered, whereas levels of valerate and valerate precursors did not. In the CDI chemostat model FMT increased valerate concentrations and decreased C difficile TVC (94% reduction), spore counts (86% reduction), and valerate precursor concentrations—concentrations of bile acids were unchanged.', 30025704);
