INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3549, 'human', 'null', 'Daidzin', 'null', 'Fecal bacteria from a healthy individual were screened for the specific bacteria involved in the metabolism of dietary isoflavonoids. Two strains of bacteria capable of producing primary and secondary metabolites from the natural isoflavone glycosides daidzin and genistin were detected. The metabolites were identified by comparison of their HPLC/mass, 1H NMR and UV spectra with those of standard and synthetic compounds. Both Escherichia coli HGH21 and the gram-positive strain HGH6 converted daidzin and genistin to the their respective aglycones daidzein and genistein. Under anoxic conditions, strain HGH6 further metabolized the isoflavones daidzein and genistein to dihydrodaidzein and dihydrogenistein, respectively.', 11195098);
