INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3573, 'human', 'null', 'D-Glucose', 'null', 'Two anaerobic, non-spore-forming, non-motile, Gram-negative-staining bacteria, strains YIT 12060T and YIT 12061T, were isolated from human faeces. Cells of strain YIT 12060T were coccoid to rod-shaped with round ends, positive for catalase, negative for indole and oxidase production, produced succinic and acetic acids as end products of glucose metabolism in peptone/yeast extract/glucose medium and had a DNA G+C content of 55.2 mol%. Phylogenetic analysis and biochemical data supported the affiliation of strain YIT 12060T to the genus Alistipes of the family ‘Rikenellaceae�? Strain YIT 12060T therefore represents a novel species of the genus Alistipes for which the name Alistipes indistinctus sp. nov. is proposed; the type strain is YIT 12060T.', 19667375);
