INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3589, 'human', 'decrease', 'Retinol', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 30566883);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3590, 'human', 'increase', 'Retinol', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 30566883);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3591, 'human', 'increase', 'Retinol', 'low-throughput', 'Retinoic acid (RA), a vitamin A metabolite, regulates transcriptional programs that drive protective or pathogenic immune responses in the intestine, in a manner dependent on RA concentration. Vitamin A is obtained from diet and is metabolized by intestinal epithelial cells (IECs), which operate in intimate association with microbes and immune cells. Here we found that commensal bacteria belonging to class Clostridia modulate RA concentration in the gut by suppressing the expression of retinol dehydrogenase 7 (Rdh7) in IECs. Rdh7 expression and associated RA amounts were lower in the intestinal tissue of conventional mice, as compared to germ-free mice. Deletion of Rdh7 in IECs diminished RA signaling in immune cells, reduced the IL-22-dependent antimicrobial response, and enhanced resistance to colonization by Salmonella Typhimurium. Our findings define a regulatory circuit wherein bacterial regulation of IEC-intrinsic RA synthesis protects microbial communities in the gut from excessive immune activity, achieving a balance that prevents colonization by enteric pathogens.', 30566883);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3596, 'human', 'null', 'Trimethylamine', 'null', 'We now show gut microbes, through generation of trimethylamine N-oxide (TMAO), directly contribute to platelet hyperreactivity and enhanced thrombosis potential. Plasma TMAO levels in subjects (n > 4,000) independently predicted incident (3 years) thrombosis (heart attack, stroke) risk. Direct exposure of platelets to TMAO enhanced sub maximal stimulus-dependent platelet activation from multiple agonists through augmented Ca2+ release from intracellular stores. Animal model studies employing dietary choline or TMAO, germ-free mice, and microbial transplantation collectively confirm a role for gut microbiota and TMAO in modulating platelet hyperresponsiveness and thrombosis potential and identify microbial taxa associated with plasma TMAO and thrombosis potential.', 26972052);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3597, 'human', 'null', 'Trimethylamine', 'null', 'We now show gut microbes, through generation of trimethylamine N-oxide (TMAO), directly contribute to platelet hyperreactivity and enhanced thrombosis potential. Plasma TMAO levels in subjects (n > 4,000) independently predicted incident (3 years) thrombosis (heart attack, stroke) risk. Direct exposure of platelets to TMAO enhanced sub maximal stimulus-dependent platelet activation from multiple agonists through augmented Ca2+ release from intracellular stores. Animal model studies employing dietary choline or TMAO, germ-free mice, and microbial transplantation collectively confirm a role for gut microbiota and TMAO in modulating platelet hyperresponsiveness and thrombosis potential and identify microbial taxa associated with plasma TMAO and thrombosis potential.', 26972052);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3609, 'human', 'increase', 'Linoleic acid', 'low-throughput', 'In this study, we investigated the effects of LA and LA-derived fatty acids on the activation of peroxisome proliferator-activated receptors (PPARs) which regulate whole-body energy metabolism. None of the fatty acids activated PPARd, whereas almost all activated PPARa in luciferase assays. Two fatty acids potently activated PPARg, a master regulator of adipocyte differentiation, with 10-oxo-12(Z)-octadecenoic acid (KetoA) having the most potency. In 3T3- L1 cells, KetoA induced adipocyte differentiation via the activation of PPARg, and increased adiponectin production and insulin-stimulated glucose uptake. These findings suggest that fatty acids, including KetoA, generated in gut by lactic acid bacteria may be involved in the regulation of host energy metabolism.', 25749343);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3610, 'human', 'increase', 'D-Fructose', 'low-throughput', 'A high-fructose diet caused the hippocampal neuroinflammatory response, reactive gliosis, and neuronal loss in C57BL/6N mice. Depletion of the gut microbiota using broad-spectrum antibiotics suppressed the hippocampal neuroinflammatory response in fructose-fed mice, but these animals still exhibited neuronal loss. Gut microbiota compositional alteration, short-chain fatty acids (SCFAs) reduction, intestinal epithelial barrier impairment, NOD-like receptor family pyrin domain-containing 6 (NLRP6) inflammasome dysfunction, high levels of serum endotoxin, and FITC-dextran were observed in fructose-fed mice. Of note, SCFAs, as well as pioglitazone (a selective peroxisome proliferator-activated receptor gamma (PPAR-γ) agonist), shaped the gut microbiota and ameliorated intestinal epithelial barrier impairment and NLRP6 inflammasome dysfunction in fructose-fed mice. Moreover, SCFAs-mediated NLRP6 inflammasome activation was inhibited by histamine (a bacterial metabolite) in ex vivo colonic explants and suppressed in murine CT26 colon carcinoma cells transfected with NLRP6 siRNA. However, pioglitazone and GW9662 (a PPAR-γ antagonist) exerted no impact on SCFAs-mediated NLRP6 inflammasome activation in ex vivo colonic explants, suggesting that SCFAs may stimulate NLRP6 inflammasome independently of PPAR-γ activation. SCFAs and pioglitazone prevented fructose-induced hippocampal neuroinflammatory response and neuronal loss in mice. Additionally, SCFAs activated colonic NLRP6 inflammasome and increased DCX+ newborn neurons in the hippocampal DG of control mice.', 31255176);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3614, 'human', 'increase', 'Tryptophan', 'low-throughput', 'Indole-3-propionic acid (IPA), a tryptophan metabolite produced by gut bacteria, is a potent anti-non-alcoholic steatohepatitis (NASH) microbial metabolite. Here, we demonstrate that administration of IPA modulates the microbiota composition in the gut and inhibits microbial dysbiosis in rats fed a high-fat diet. IPA induces the expression of tight junction proteins, such as ZO-1 and Occludin, and maintains intestinal epithelium homeostasis, leading to a reduction in plasma endotoxin levels. Interestingly, IPA inhibits NF-κB signaling and reduces the levels of proinflammatory cytokines, such as TNFα, IL-1β, and IL-6, in response to endotoxin in macrophages to repress hepatic inflammation and liver injury. Moreover, IPA is sufficient to inhibit the expression of fibrogenic and collagen genes and attenuate diet-induced NASH phenotypes. The beneficial effects of IPA on the liver are likely mediated through inhibiting the production of endotoxin in the gut.', 31506421);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3615, 'human', 'decrease', 'Tryptophan', 'low-throughput', 'Indole-3-propionic acid (IPA), a tryptophan metabolite produced by gut bacteria, is a potent anti-non-alcoholic steatohepatitis (NASH) microbial metabolite. Here, we demonstrate that administration of IPA modulates the microbiota composition in the gut and inhibits microbial dysbiosis in rats fed a high-fat diet. IPA induces the expression of tight junction proteins, such as ZO-1 and Occludin, and maintains intestinal epithelium homeostasis, leading to a reduction in plasma endotoxin levels. Interestingly, IPA inhibits NF-κB signaling and reduces the levels of proinflammatory cytokines, such as TNFα, IL-1β, and IL-6, in response to endotoxin in macrophages to repress hepatic inflammation and liver injury. Moreover, IPA is sufficient to inhibit the expression of fibrogenic and collagen genes and attenuate diet-induced NASH phenotypes. The beneficial effects of IPA on the liver are likely mediated through inhibiting the production of endotoxin in the gut.', 31506421);
