INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3637, 'human', 'null', 'D-Sorbitol', 'null', 'Three sequential fermentative batches were carried out with cell recycle in four simultaneously operating bioreactors maintained at pH 6.5, 30°C, and 100 rpm. P. acidipropionici ATCC 4875 was able to produce propionic and succinic acid from sorbitol. The concentration of propionic acid decreased slightly from 39.5 ± 5.2 g L�? to 34.4 ± 1.9 g L�?,and that of succinic acid increased significantly from 6.1 ± 2.1 g L�? to 14.8 ± 0.9 g L�? through the sequential batches. In addition, a small amount of acetic acid was produced that decreased from 3.3 ± 0.4 g L�? to 2.0 ± 0.3 g L�? through the batches. The major yield for propionic acid was 0.613 g g�? in the first batch and succinic acid it was 0.212 g g�? in the third batch. The minor yield of acetic acid was 0.029 g g�? ,in the second and third batches.', 25852990);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3638, 'human', 'null', 'D-Sorbitol', 'null', 'Three sequential fermentative batches were carried out with cell recycle in four simultaneously operating bioreactors maintained at pH 6.5, 30°C, and 100 rpm. P. acidipropionici ATCC 4875 was able to produce propionic and succinic acid from sorbitol. The concentration of propionic acid decreased slightly from 39.5 ± 5.2 g L�? to 34.4 ± 1.9 g L�?,and that of succinic acid increased significantly from 6.1 ± 2.1 g L�? to 14.8 ± 0.9 g L�? through the sequential batches. In addition, a small amount of acetic acid was produced that decreased from 3.3 ± 0.4 g L�? to 2.0 ± 0.3 g L�? through the batches. The major yield for propionic acid was 0.613 g g�? in the first batch and succinic acid it was 0.212 g g�? in the third batch. The minor yield of acetic acid was 0.029 g g�? ,in the second and third batches.', 25852990);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3639, 'human', 'increase', 'null', 'low-throughput', 'In the present study, we found that TMAO significantly upregulated the expression of proinflammatory markers, such as IL-1β, IL-6, and TNF-α in TH positive neurons, as well as NMDARs, which might further result in sympathetic hyperactivation within the LSG and promote the incidence of VA.', 30954457);
