INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3667, 'human', 'null', 'Dihydrodaidzein', 'null', 'In this study, chemically synthesized dihydrodaidzein was used as the substrate administered to a newly isolated rodshaped, gram-negative, anaerobic bacterium from human feces which can convert dihydrodaidzein to S-equol.', 29112296);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3668, 'human', 'null', 'daidzein', 'null', 'Clostridium sp. strain HGH6, that is capable of reducing daidzein to dihydrodaidzein, but further metabolism to tetrahydrodaidzein or equol did not occur.', 15640190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3669, 'human', 'decrease', 'null', 'low-throughput', 'Our result also demonstrated that butyrate intervention enhanced fecal SCFAs concentrations, and inhibited endotoxin levels in feces and serum. Correlation analysis indicated positive relation between endotoxin level and Desulfovibrionaceae abundance. Furthermore,  butyrate intervention inhibited expressions of IL-1β, IL-6 and MCP1/CCL2 in liver, as well as TLR4 in adipose tissue.', 15640190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3670, 'human', 'decrease', 'null', 'low-throughput', 'Our result also demonstrated that butyrate intervention enhanced fecal SCFAs concentrations, and inhibited endotoxin levels in feces and serum. Correlation analysis indicated positive relation between endotoxin level and Desulfovibrionaceae abundance. Furthermore,  butyrate intervention inhibited expressions of IL-1β, IL-6 and MCP1/CCL2 in liver, as well as TLR4 in adipose tissue.', 31295342);
