INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3673, 'human', 'null', 'Biochanin A', 'null', 'Eubacterium limosum (ATCC 8486), a strict anaerobe from the human intestinal tract that is capable of O-demethylation of several compounds, was tested for the ability to metabolize three methoxylated isoflavonoids, biochanin A, formononetin, and glycitein. High performance liquid chromatography elution profiles of metabolites produced from biochanin A, formononetin, and glycitein showed peaks that had identical retention times to authentic genistein, daidzein, and 6,7,4P-trihydroxyisoflavone, respectively.', 31295342);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3674, 'human', 'null', 'Formononetin', 'null', 'Eubacterium limosum (ATCC 8486), a strict anaerobe from the human intestinal tract that is capable of O-demethylation of several compounds, was tested for the ability to metabolize three methoxylated isoflavonoids, biochanin A, formononetin, and glycitein. High performance liquid chromatography elution profiles of metabolites produced from biochanin A, formononetin, and glycitein showed peaks that had identical retention times to authentic genistein, daidzein, and 6,7,4P-trihydroxyisoflavone, respectively.', 11040423);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3675, 'human', 'null', 'Glycitein', 'null', 'Eubacterium limosum (ATCC 8486), a strict anaerobe from the human intestinal tract that is capable of O-demethylation of several compounds, was tested for the ability to metabolize three methoxylated isoflavonoids, biochanin A, formononetin, and glycitein. High performance liquid chromatography elution profiles of metabolites produced from biochanin A, formononetin, and glycitein showed peaks that had identical retention times to authentic genistein, daidzein, and 6,7,4P-trihydroxyisoflavone, respectively.', 11040423);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3680, 'human', 'null', '(-)-Epigallocatechin gallate', 'null', 'The results showed that L. plantarum IFPL935 exhibited higher resistance to nongalloylated monomeric flavan-3-ols, A-type dimeric procyanidins, and cranberry extract than to (�?-epicatechin-3-O-gallate and B-type dimeric procyanidins. Despite these findings,the strain was capable of rapidly degrading (�?-epicatechin-3-O-gallate, but not A- or B-type dimeric procyanidins. However, it was able to produce large changes in the phenolic profile of the cranberry extract mainly due to the catabolism of hydroxycinnamic and hydroxybenzoic acids. Of most relevance was the fact that L. plantarum IFPL935 cleaved the heterocyclic ring of monomeric flavan-3-ols, giving rise to 1-(3�?4�?dihydroxyphenyl)-3-(2�?4�?6�?trihydroxyphenyl)propan-2-ol, activity exhibited by only a few human intestinal bacteria.', 22646528);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3681, 'human', 'null', '(-)-Epigallocatechin gallate', 'null', 'The results showed that L. plantarum IFPL935 exhibited higher resistance to nongalloylated monomeric flavan-3-ols, A-type dimeric procyanidins, and cranberry extract than to (�?-epicatechin-3-O-gallate and B-type dimeric procyanidins. Despite these findings,the strain was capable of rapidly degrading (�?-epicatechin-3-O-gallate, but not A- or B-type dimeric procyanidins. However, it was able to produce large changes in the phenolic profile of the cranberry extract mainly due to the catabolism of hydroxycinnamic and hydroxybenzoic acids. Of most relevance was the fact that L. plantarum IFPL935 cleaved the heterocyclic ring of monomeric flavan-3-ols, giving rise to 1-(3�?4�?dihydroxyphenyl)-3-(2�?4�?6�?trihydroxyphenyl)propan-2-ol, activity exhibited by only a few human intestinal bacteria.', 22646528);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3682, 'human', 'null', 'null', 'null', 'One important secondary metabolite of bifidobacteria is folate, which contributes to the one-carbon metabolism of the host and therefore enables maintenance of DNA methylation marks as explained below (41).', 23594611);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3683, 'human', 'increase', 'null', 'low-throughput', 'Furthermore, TMAO increased TGF-β receptor I expression, which promoted the phosphorylation of Smad2 and up-regulated the expression of α-SMA and collagen I. The ubiquitination of TGF-βRI was decreased in neonatal mouse fibroblasts after TMAO treatment. TMAO also inhibited the expression of smurf2. Inhibition of TGF-β1 receptor with the small molecule inhibitor SB431542 decreased TGF-β receptor I expression, reduced the phosphorylation of Smad2, down-regulated TMAO-induced α-SMA and collagen I expression in cardiac fibroblasts. Conclusions: Cardiac function and cardiac fibrosis were significantly exacerbated in mice fed diets supplemented with either choline or TMAO, probably through accelerating the transformation of fibroblasts into myofibroblasts, indicating activation of TGF-βRI/Smad2 pathway', 31299216);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3684, 'human', 'increase', 'null', 'low-throughput', 'Furthermore, TMAO increased TGF-β receptor I expression, which promoted the phosphorylation of Smad2 and up-regulated the expression of α-SMA and collagen I. The ubiquitination of TGF-βRI was decreased in neonatal mouse fibroblasts after TMAO treatment. TMAO also inhibited the expression of smurf2. Inhibition of TGF-β1 receptor with the small molecule inhibitor SB431542 decreased TGF-β receptor I expression, reduced the phosphorylation of Smad2, down-regulated TMAO-induced α-SMA and collagen I expression in cardiac fibroblasts. Conclusions: Cardiac function and cardiac fibrosis were significantly exacerbated in mice fed diets supplemented with either choline or TMAO, probably through accelerating the transformation of fibroblasts into myofibroblasts, indicating activation of TGF-βRI/Smad2 pathway', 31299216);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3685, 'human', 'decrease', 'null', 'low-throughput', 'Furthermore, TMAO increased TGF-β receptor I expression, which promoted the phosphorylation of Smad2 and up-regulated the expression of α-SMA and collagen I. The ubiquitination of TGF-βRI was decreased in neonatal mouse fibroblasts after TMAO treatment. TMAO also inhibited the expression of smurf2. Inhibition of TGF-β1 receptor with the small molecule inhibitor SB431542 decreased TGF-β receptor I expression, reduced the phosphorylation of Smad2, down-regulated TMAO-induced α-SMA and collagen I expression in cardiac fibroblasts. Conclusions: Cardiac function and cardiac fibrosis were significantly exacerbated in mice fed diets supplemented with either choline or TMAO, probably through accelerating the transformation of fibroblasts into myofibroblasts, indicating activation of TGF-βRI/Smad2 pathway', 31299216);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3686, 'human', 'null', 'Glycitein', 'null', 'The dichotomy between the biotransformation of polyphenols into their metabolites by gut microbiota and the modulation of gut microbiota composition by polyphenols contributes to positive health outcomes. Although there are many studies on the in vivo bioavailability of polyphenols, the mutual relationship between polyphenols and gut microbiota is not fully understood. This review focuses on the biotransformation of polyphenols by gut microbiota, modulation of gut microbiota by polyphenols, and the effects of these two-way mutual interactions on polyphenol bioavailability, and ultimately, human health.', 26861391);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3687, 'human', 'null', 'Glycitein', 'null', 'The dichotomy between the biotransformation of polyphenols into their metabolites by gut microbiota and the modulation of gut microbiota composition by polyphenols contributes to positive health outcomes. Although there are many studies on the in vivo bioavailability of polyphenols, the mutual relationship between polyphenols and gut microbiota is not fully understood. This review focuses on the biotransformation of polyphenols by gut microbiota, modulation of gut microbiota by polyphenols, and the effects of these two-way mutual interactions on polyphenol bioavailability, and ultimately, human health.', 26861391);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3688, 'human', 'null', 'Chlorogenic acid', 'null', 'Chlorogenic acid hydrolysing activities were essentially intracellular. These cinnamoyl esterase-producing organisms were devoid of other phenolic-degrading activities. The results show that certain gut bacteria, including some already recognized as potentially health-promoting (i.e. species belonging to the genera Bifidobacterium and Lactobacillus), are involved in the release of bioactive hydroxycinnamic acids in the human colon.', 11412317);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3689, 'human', 'null', 'Chlorogenic acid', 'null', 'Chlorogenic acid hydrolysing activities were essentially intracellular. These cinnamoyl esterase-producing organisms were devoid of other phenolic-degrading activities. The results show that certain gut bacteria, including some already recognized as potentially health-promoting (i.e. species belonging to the genera Bifidobacterium and Lactobacillus), are involved in the release of bioactive hydroxycinnamic acids in the human colon.', 11412317);
