INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3699, 'human', 'null', 'Phosphoenolpyruvate', 'null', 'Our attempt to revisit classic literature has revealed many gaps in our knowledge that can now be examined in the light of modern systems approaches. At the same time, descriptive sequence-based studies are serving an important complementary role in defining priorities for pursuing mechanism-level understanding of this otherwise exceedingly complex interplay between the microbial species that inhabit humans and the resulting interactions that occur between these species and the host.', 22018234);
