INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3723, 'human', 'null', 'Phytoestrogens', 'null', 'Nine healthy male adult subjects ingested 0.3 g/kg/day flaxseeds during 1 week. Gut bacteria as well as blood and fecal metabolites were analyzed. Ingestion of flaxseeds triggered a significant increase in the blood concentration of enterolignans, accompanied by fecal excretion of propionate and glycerol. Overall diversity and composition of dominant fecal bacteria remained individual specific throughout the study.', 25988339);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3724, 'human', 'null', 'Phytoestrogens', 'null', 'Nine healthy male adult subjects ingested 0.3 g/kg/day flaxseeds during 2 week. Gut bacteria as well as blood and fecal metabolites were analyzed. Ingestion of flaxseeds triggered a significant increase in the blood concentration of enterolignans, accompanied by fecal excretion of propionate and glycerol. Overall diversity and composition of dominant fecal bacteria remained individual specific throughout the study.', 25988339);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3725, 'human', 'null', 'Geniposide', 'null', 'Genipin, a deglycosylated form of geniposide, was cytotoxic at the concentrations that geniposide was not. As metabolic activation systems for geniposide, human intestinal bacterial cultures, fecal preparation (fecalase) and intestinal microbial enzyme mix were employed in the present study. When geniposide was incubated with human intestinal bacteria, either Bifidobacterium longum HY8001 or Bacteroides fragilis, for 24 h, the cultured media caused cytotoxicity in HepG3 cells.', 22553067);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3726, 'human', 'null', 'Geniposide', 'null', 'Genipin, a deglycosylated form of geniposide, was cytotoxic at the concentrations that geniposide was not. As metabolic activation systems for geniposide, human intestinal bacterial cultures, fecal preparation (fecalase) and intestinal microbial enzyme mix were employed in the present study. When geniposide was incubated with human intestinal bacteria, either Bifidobacterium longum HY8001 or Bacteroides fragilis, for 24 h, the cultured media caused cytotoxicity in HepG3 cells.', 22553067);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3740, 'human', 'increase', 'Retinol', 'low-throughput', 'We reported here that microbiota metabolite short-chain fatty acid acetate promoted intestinal IgA responses, which was mediated by \"metabolite-sensing\" GPR43. GPR43-/- mice demonstrated lower levels of intestinal IgA and IgA+ gut bacteria compared with those in wild type (WT) mice. Feeding WT but not GPR43-/- mice acetate but not butyrate promoted intestinal IgA response independent of T cells.', 27966553);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3741, 'human', 'null', 'Bile acid', 'null', 'The most important bile acid transformation is 7α-dehydroxylation, producing deoxycholic acid (DCA) and lithocholic acid (LCA). The enzymatic pathway carrying out 7α-dehydroxylation is restricted to a narrow phylogenetic group of commensal bacteria, the best-characterized of which is Clostridium scindens.we used a recently established, standardized gnotobiotic mouse model that is stably associated with a simplified murine 12-species \"oligo-mouse microbiota\" (Oligo-MM12).', 28066726);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3742, 'human', 'null', 'Bile acid', 'null', 'The most important bile acid transformation is 7α-dehydroxylation, producing deoxycholic acid (DCA) and lithocholic acid (LCA). The enzymatic pathway carrying out 7α-dehydroxylation is restricted to a narrow phylogenetic group of commensal bacteria, the best-characterized of which is Clostridium scindens.we used a recently established, standardized gnotobiotic mouse model that is stably associated with a simplified murine 12-species \"oligo-mouse microbiota\" (Oligo-MM12).', 28066726);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3743, 'human', 'decrease', 'null', 'low-throughput', 'Dietary and bacterial metabolites influence immune responses. This raises the question whether the increased incidence of allergies, asthma, some autoimmune diseases, cardiovascular disease, and others might relate to intake of unhealthy foods, and the decreased intake of dietary fiber. In recent years, new knowledge on the molecular mechanisms underpinning a \'diet-gut microbiota-physiology axis\' has emerged to substantiate this idea. Fiber is fermented to short chain fatty acids (SCFAs), particularly acetate, butyrate, and propionate. These metabolites bind \'metabolite-sensing\' G-protein-coupled receptors such as GPR43, GPR41, and GPR109A. These receptors play fundamental roles in the promotion of gut homeostasis and the regulation of inflammatory responses. For instance, these receptors and their metabolites influence Treg biology, epithelial integrity, gut homeostasis, DC biology, and IgA antibody responses. The SCFAs also influence gene transcription in many cells and tissues, through their inhibition of histone deacetylase expression or function.', 28658542);
