INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3749, 'human', 'increase', 'Linoleic Acid', 'low-throughput', 'In this study, we investigated the effects of novel fatty acid metabolite derivatives of linoleic acid generated by the gut lactic acid bacteria Lactobacillus plantarum on the Nrf2-ARE pathway. 10-Oxo-trans-11-octadecenoic acid (KetoC) protected HepG2 cells from cytotoxicity induced by hydrogen peroxide. KetoC also significantly increased cellular Nrf2 protein levels, ARE-dependent transcription, and the gene expression of antioxidative enzymes such as heme oxygenase-1 (HO-1), glutamate-cysteine ligase modifier subunit (GCLM), and Nad(p)h: quinone oxidoreductase 1 (NQO1) in HepG2 cells.', 26879219);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3750, 'human', 'increase', 'Linoleic Acid', 'low-throughput', 'In this study, we investigated the effects of novel fatty acid metabolite derivatives of linoleic acid generated by the gut lactic acid bacteria Lactobacillus plantarum on the Nrf2-ARE pathway. 10-Oxo-trans-11-octadecenoic acid (KetoC) protected HepG2 cells from cytotoxicity induced by hydrogen peroxide. KetoC also significantly increased cellular Nrf2 protein levels, ARE-dependent transcription, and the gene expression of antioxidative enzymes such as heme oxygenase-1 (HO-1), glutamate-cysteine ligase modifier subunit (GCLM), and Nad(p)h: quinone oxidoreductase 1 (NQO1) in HepG2 cells.', 26879219);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3751, 'human', 'null', 'Rutin', 'null', 'The average α-Lrhamnosidase activities on the p-nitrophenyl-α-L-rhamnopyranoside, rutin, and poncirin subtrates were 0.10 ± 0.07, 0.25 ± 0.08, and 0.15 ± 0.09 pmol/min/mg, respectively. To investigate the enzymatic properties, α-L-rhamnosidase-producing bacteria were isolated from the specimens, and the α-L-rhamnosidase gene was cloned from a selected organism, Bifidobacterium dentium, and expressed in E. coli. The cloned α-L-rhamnosidase gene contained a 2,673 bp sequcence encoding 890 amino acid residues. The cloned gene was expressed using the pET 26b(+) vector in E. coli BL21, and the expressed enzyme was purified using Ni(2+)-NTA and Q-HP column chromatography. The specific activity of the purified α-L-rhamnosidase was 23.3 μmol/min/mg.', 25179902);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3752, 'human', 'null', 'Poncirin', 'null', 'The average α-Lrhamnosidase activities on the p-nitrophenyl-α-L-rhamnopyranoside, rutin, and poncirin subtrates were 0.10 ± 0.07, 0.25 ± 0.08, and 0.15 ± 0.09 pmol/min/mg, respectively. To investigate the enzymatic properties, α-L-rhamnosidase-producing bacteria were isolated from the specimens, and the α-L-rhamnosidase gene was cloned from a selected organism, Bifidobacterium dentium, and expressed in E. coli. The cloned α-L-rhamnosidase gene contained a 2,673 bp sequcence encoding 890 amino acid residues. The cloned gene was expressed using the pET 26b(+) vector in E. coli BL21, and the expressed enzyme was purified using Ni(2+)-NTA and Q-HP column chromatography. The specific activity of the purified α-L-rhamnosidase was 23.3 μmol/min/mg.', 25179902);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3753, 'human', 'decrease', 'null', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 19865172);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3754, 'human', 'decrease', 'null', 'low-throughput', 'A feature of human ulcerative colitis and other colitic diseases is a change in \'healthy\' microbiota such as Bifidobacterium and Bacteriodes, and a concurrent reduction in SCFAs. Moreover, increased intake of fermentable dietary fibre, or SCFAs, seems to be clinically beneficial in the treatment of colitis. SCFAs bind the G-protein-coupled receptor 43 (GPR43, also known as FFAR2), and here we show that SCFA-GPR43 interactions profoundly affect inflammatory responses. Stimulation of GPR43 by SCFAs was necessary for the normal resolution of certain inflammatory responses, because GPR43-deficient (Gpr43(-/-)) mice showed exacerbated or unresolving inflammation in models of colitis, arthritis and asthma. This seemed to relate to increased production of inflammatory mediators by Gpr43(-/-) immune cells, and increased immune cell recruitment. Germ-free mice, which are devoid of bacteria and express little or no SCFAs, showed a similar dysregulation of certain inflammatory responses. GPR43 binding of SCFAs potentially provides a molecular link between diet, gastrointestinal bacterial metabolism, and immune and inflammatory responses.', 19865172);
