INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3763, 'human', 'null', 'Galbeta1,3GlcNAc', 'null', 'In the current study, we isolated a novel strain of Bifidobacterium kashiwanohense, named APCKJ1, from the faeces of a four-week old breastfed infant, based on the ability of the strain to utilise the HMO component fucosyllactose. We then determined the full genome sequence of this strain, and employed the generated data to analyze fucosyllactose metabolism in B. kashiwanohense APCKJ1. Transcriptomic and growth analyses, combined with metabolite analysis, in vitro hydrolysis assays and heterologous expression, allowed us to elucidate the pathway for fucosyllactose metabolism in B. kashiwanohense APCKJ1. Homologs of the key genes for this metabolic pathway were identified in particular in infant-derived members of the Bifdobacterium genus, revealing the apparent niche-specific nature of this pathway, and allowing a broad perspective on bifidobacterial fucosyllactose and L-fucose metabolism.', 31659215);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3764, 'human', 'null', 'N-Acetyl-D-lactosamine', 'null', 'In the current study, we isolated a novel strain of Bifidobacterium kashiwanohense, named APCKJ1, from the faeces of a four-week old breastfed infant, based on the ability of the strain to utilise the HMO component fucosyllactose. We then determined the full genome sequence of this strain, and employed the generated data to analyze fucosyllactose metabolism in B. kashiwanohense APCKJ1. Transcriptomic and growth analyses, combined with metabolite analysis, in vitro hydrolysis assays and heterologous expression, allowed us to elucidate the pathway for fucosyllactose metabolism in B. kashiwanohense APCKJ1. Homologs of the key genes for this metabolic pathway were identified in particular in infant-derived members of the Bifdobacterium genus, revealing the apparent niche-specific nature of this pathway, and allowing a broad perspective on bifidobacterial fucosyllactose and L-fucose metabolism.', 31659215);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3765, 'human', 'increase', 'null', 'low-throughput', 'A Prevotella and an Atopobium strain were chosen for further study, and shown to up-regulate two PPARγ-target genes, ANGPTL4 and ADRP. The molecular mechanisms of these activations involved the phosphorylation of PPARγ through ERK1/2. The responsible metabolites were shown to be heat sensitive but markedly diverged in size, emphasizing the diversity of bioactive compounds found in the intestine. Here we describe different mechanisms by which single intestinal bacteria can directly impact their host\'s health through transcriptional regulation.', 28266623);
