INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3769, 'human', 'null', 'Daidzein', 'null', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3770, 'human', 'null', 'Daidzin', 'null', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3771, 'human', 'null', 'Daidzein', 'null', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3772, 'human', 'null', 'Daidzein', 'null', 'Several kinds of carbohydrates such as sorbose, adonitol, and melezitose were found to enhance equol production from daidzein in an in vitro human fecal culture. Sorbose, one of the most effective carbohydrates, was used as a carbohydrate source for isolating the NATTS strain, which was a Gram-positive, non-spore-forming rod bacterium with high ability to convert daidzein to equol isolated from the 7th maintenance culture. The strain was found to belong to the genus Slackia family Coriobacteriaceae by 16S rRNA sequence-based analysis, and the prevalence of the Slackia sp. in Japanese adults was examined by reverse transcription-quantitative PCR (RT-qPCR), which was found to be 40% at a mean population level of 10(6) cells per gram of feces.', 20237913);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3773, 'human', 'null', 'Puerarin', 'null', 'A rod-shaped Gram-positive bacterium, strain CG19-1, capable of deglycosylating puerarin to daidzein was isolated from the corresponding suspension. However, the strictly anaerobic isolate was unable to utilize puerarin as sole carbon and energy source nor any of the tested carbohydrates. Comparative 16S rRNA sequence analysis indicated that strain CG19-1 is a new species of the Lachnospiraceae. Strain CG19-1 also converted other aromatic C-glucosides in addition to puerarin. The xanthone C-glucoside mangiferin was deglycosylated to norathyriol. The flavone C-glucosides homoorientin and vitexin were degraded to 3-(3,4-dihydroxyphenyl)propionic acid via luteolin and 3-(4-hydroxyphenyl)propionic acid respectively. In addition, strain CG19-1 converted flavonoid O-glucosides, but at rates that were lower than those of the C-glucosides tested. The isolate deglycosylated the isoflavone O-glucosides daidzin and genistin to daidzein and genistein respectively. Several O-glucosides of the flavones luteolin and apigenin undergoing deglycosylation were subsequently cleaved to 3-(3,4-dihydroxyphenyl)propionic acid and 3-(4-hydroxyphenyl)propionic acid respectively. Moreover, strain CG19-1 cleaved both O-desmethylangolensin and 6\'-hydroxy-O-desmethylangolensin to yield 2-(4-dihydroxyphenyl)propionic acid. The corresponding cleavage product, resorcinol, was only observed for O-desmethylangolensin.', 20946528);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3774, 'human', 'null', 'Vitexin', 'null', 'A rod-shaped Gram-positive bacterium, strain CG19-1, capable of deglycosylating puerarin to daidzein was isolated from the corresponding suspension. However, the strictly anaerobic isolate was unable to utilize puerarin as sole carbon and energy source nor any of the tested carbohydrates. Comparative 16S rRNA sequence analysis indicated that strain CG19-1 is a new species of the Lachnospiraceae. Strain CG19-1 also converted other aromatic C-glucosides in addition to puerarin. The xanthone C-glucoside mangiferin was deglycosylated to norathyriol. The flavone C-glucosides homoorientin and vitexin were degraded to 3-(3,4-dihydroxyphenyl)propionic acid via luteolin and 3-(4-hydroxyphenyl)propionic acid respectively. In addition, strain CG19-1 converted flavonoid O-glucosides, but at rates that were lower than those of the C-glucosides tested. The isolate deglycosylated the isoflavone O-glucosides daidzin and genistin to daidzein and genistein respectively. Several O-glucosides of the flavones luteolin and apigenin undergoing deglycosylation were subsequently cleaved to 3-(3,4-dihydroxyphenyl)propionic acid and 3-(4-hydroxyphenyl)propionic acid respectively. Moreover, strain CG19-1 cleaved both O-desmethylangolensin and 6\'-hydroxy-O-desmethylangolensin to yield 2-(4-dihydroxyphenyl)propionic acid. The corresponding cleavage product, resorcinol, was only observed for O-desmethylangolensin.', 20946528);
