INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3838, 'human', 'null', 'null', 'null', 'Lactobacillus casei strain Shirota intake increased defecation frequency, normalized stool consistency, and improved constipation related symptoms in Chinese adults with constipation. Through the use of metabolomic approaches, PIPA, which is a non-volatile metabolite in the gut, was identified as a potential target mediator in LcS-mediated constipation alleviation. Furthermore, PIPA could improve constipation symptoms, as shown by increases in the small intestine propulsive rate and the number of fecal pellets in a constipation mouse model, raising its possibility in the constipation therapy. Future studies should verify the anti-constipation function of PIPA and elucidate its potential mechanisms.', 30846982);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3841, 'human', 'decrease', 'Geniposide', 'low-throughput', 'Western blot analysis revealed that the activated GS inhibited Bcl-2 expression with a subsequent increase in Bax expression. Likewise, GS activation by IM stimulated caspase-3 and the production of reactive oxygen species (ROS). In addition, activated GS-induced apoptosis was confirmed by apoptosis and ROS assays; N-acetyl-l-cysteine (NAC) suppressed ROS production and apoptotic cell death. Activated GS induced sustained JNK phosphorylation. Moreover, activated GS-induced cell death was reversed by SP600125. Taken together, these findings suggest that human IM is able to metabolize GS into GP, and the related biological activities induce apoptosis through ROS/JNK signaling.', 22245672);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3842, 'human', 'increase', 'Geniposide', 'low-throughput', 'Western blot analysis revealed that the activated GS inhibited Bcl-2 expression with a subsequent increase in Bax expression. Likewise, GS activation by IM stimulated caspase-3 and the production of reactive oxygen species (ROS). In addition, activated GS-induced apoptosis was confirmed by apoptosis and ROS assays; N-acetyl-l-cysteine (NAC) suppressed ROS production and apoptotic cell death. Activated GS induced sustained JNK phosphorylation. Moreover, activated GS-induced cell death was reversed by SP600125. Taken together, these findings suggest that human IM is able to metabolize GS into GP, and the related biological activities induce apoptosis through ROS/JNK signaling.', 22245672);
