INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3845, 'human', 'decrease', 'null', 'low-throughput', 'We examined the effects of UV-killed F. prausnitzii, bacterial fractions,supernatants, or sterile medium on IL-8 secretion in Caco-2 cells,with or without IL-1 stimulation (SI Materials and Methods and Fig. 3A). Either UV-killed F. prausnitzii, membrane extracts, or cytoplasmic extracts, but not DNA or sterile medium, induce low levels of IL-8 secretion. UV-killed F. prausnitzii, bacterial fractions,and sterile medium did not inhibit IL-8 secretion induced by IL-1,compared with negative control. In contrast, supernatant from F.prausnitzii cultures significantly reduces IL-8 secretion induced by IL-1.', 18936492);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (3846, 'human', 'decrease', 'null', 'low-throughput', 'We examined the effects of UV-killed F. prausnitzii, bacterial fractions,supernatants, or sterile medium on IL-8 secretion in Caco-2 cells,with or without IL-1 stimulation (SI Materials and Methods and Fig. 3A). Either UV-killed F. prausnitzii, membrane extracts, or cytoplasmic extracts, but not DNA or sterile medium, induce low levels of IL-8 secretion. UV-killed F. prausnitzii, bacterial fractions,and sterile medium did not inhibit IL-8 secretion induced by IL-1,compared with negative control. In contrast, supernatant from F.prausnitzii cultures significantly reduces IL-8 secretion induced by IL-1.', 18936492);
