INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4091, 'human', 'null', 'Myricitrin', 'null', 'Specifically, the majority of the strains such as Escherichia sp. 12 could metabolize myricitrin (M1) to quercetin-3-O-rhamnoside (M2) and myricetin (M3) (Figure 1C), and the metabolites of some strains like Enterococcus sp. 45 were large amounts of myricetin (M3) and quercetin (M4) (Figure 1D), while the other strains, for example, Escherichia sp. 33, could degrade myricitrin completely to myricetin and quercetin.', 24882500);
