INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4122, 'human', 'null', 'Daidzein', 'null', 'In conclusion, the results obtained in this study suggest that the presence of Bacteroides genus in the fecal samples of control subjects seems to be involved in the daidzein transformation to equol, an antioxidative, anti-carcinogenic molecule, which shows the most active estrogenic properties of soy isoflavones.\n', 32218321);
