INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4131, 'human', 'null', 'Pyruvate', 'null', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4132, 'human', 'null', 'Pyruvate', 'null', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4133, 'human', 'null', 'Pyruvate', 'null', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4134, 'human', 'null', 'Pyruvate', 'null', 'According to the FDR-adjusted p-values (q-values) in multivariable linear regression, p-cresyl sulfate showed a significant association with six major genera, with positive correlations observed with Alistipes, Oscillibacter, and Subdoligranulum (q < 0.001, q < 0.001, and q = 0.023, respectively) and negative correlations with Lachnospira, Veillonella, and Megamonas (q = 0.039, q = 0.014, and q = 0.034, respectively). Serum p-cresyl glucuronide and indoxyl sulfate levels were positively correlated with Alistipes (q = 0.010 and q = 0.035, respectively) and Oscillibacter (q = 0.001 and q = 0.037, respectively). Serum TMAO levels were associated only with Oscillibacter (q = 0.006). Unexpectedly, we found Oscillibacter to be associated with all four measured uremic toxins, although each of these metabolites is derived from different parent compounds.', 32560104);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4135, 'human', 'increase', 'null', 'low-throughput', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4136, 'human', 'increase', 'null', 'low-throughput', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4137, 'human', 'increase', 'Trimethylamine', 'low-throughput', 'We found that TMAO treatment activated astrocytes, as indicated by a ~ 2-fold increase in LCN2 (Fig. 6a) and a ~ 3-fold increase in CD44 (Fig. 6b), a pro-inflammatory intercellular adhesion pro tein characteristic of reactive astrocytes [10].', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4138, 'human', 'increase', 'Trimethylamine', 'low-throughput', 'We found that TMAO treatment activated astrocytes, as indicated by a ~ 2-fold increase in LCN2 (Fig. 6a) and a ~ 3-fold increase in CD44 (Fig. 6b), a pro-inflammatory intercellular adhesion pro tein characteristic of reactive astrocytes [10].', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4139, 'human', 'decrease', 'Baicalin', 'low-throughput', 'As shown in Fig. 5a, treatment with 10�?0 μM of BE signifcantly reduced LPS-induced IL-8 secretion. Similar inhibitory efects were observed for BI at 15�?0 μM; however, BE showed more potent efects.', 31650468);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4140, 'human', 'decrease', 'null', 'low-throughput', 'As shown in Fig. 5a, treatment with 10�?0 μM of BE signifcantly reduced LPS-induced IL-8 secretion. Similar inhibitory efects were observed for BI at 15�?0 μM; however, BE showed more potent efects.', 31650468);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4141, 'human', 'increase', 'Trimethylamine', 'low-throughput', 'Plasma TMAO was positively associated with plasma levels of TNFα and IL-12 (Figures 3A,B), but not with IL-6 (p = 0.263, rho = 0.11) or IL-8.', 33042155);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4142, 'human', 'increase', 'Trimethylamine', 'low-throughput', 'Plasma TMAO was positively associated with plasma levels of TNFα and IL-12 (Figures 3A,B), but not with IL-6 (p = 0.263, rho = 0.11) or IL-8.', 33042155);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4143, 'human', 'increase', 'Trimethylamine', 'low-throughput', 'Herein, we found that plasma levels of LPS were significantly correlated with TMAOand the TMA precursors carnitine and y-BB in CVID patients (Figures 6A–C), indicating a relation between gut leakage and TMAO pathway metabolites.', 33042155);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4144, 'human', 'null', 'Secoisolariciresinol diglucoside', 'null', 'Over the first 30 min at 37 1C, the amount of SDG converted to SECO by resting cells of Clostridium sp. SDG Mt85-3Db was approximately 8- and 30-fold higher than the amount converted by B. distasonis DSM 20701T and B.ovatus SDG-Mt85-3Cy, respectively.', 16765860);
