INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4158, 'human', 'null', '5,7-Dihydroxy-2-(4-hydroxyphenyl)chroman-4-one', 'null', 'A hypothetical pathway for the degradation of narin genin by E. ramulus has been proposed by Schneider and Blaut (2000) (Fig. 1a). The first step in this pathway is the isomerization of naringenin to naringenin chalcone, which is subsequently reduced to phloretin. Phloretin is further\nhydrolyzed to phloroglucinol and 3(4-hydroxyphenyl)pro pionic acid.', 15127184);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4159, 'human', 'null', 'Naringenin chalcone', 'null', 'A hypothetical pathway for the degradation of narin genin by E. ramulus has been proposed by Schneider and Blaut (2000) (Fig. 1a). The first step in this pathway is the isomerization of naringenin to naringenin chalcone, which is subsequently reduced to phloretin. Phloretin is further\nhydrolyzed to phloroglucinol and 3(4-hydroxyphenyl)pro pionic acid.', 15127184);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4160, 'human', 'null', 'Phloretin', 'null', 'A hypothetical pathway for the degradation of narin genin by E. ramulus has been proposed by Schneider and Blaut (2000) (Fig. 1a). The first step in this pathway is the isomerization of naringenin to naringenin chalcone, which is subsequently reduced to phloretin. Phloretin is further\nhydrolyzed to phloroglucinol and 3(4-hydroxyphenyl)pro pionic acid.', 15127184);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4161, 'human', 'null', 'Phloretin', 'null', 'A hypothetical pathway for the degradation of narin genin by E. ramulus has been proposed by Schneider and Blaut (2000) (Fig. 1a). The first step in this pathway is the isomerization of naringenin to naringenin chalcone, which is subsequently reduced to phloretin. Phloretin is further\nhydrolyzed to phloroglucinol and 3(4-hydroxyphenyl)pro pionic acid.', 15127184);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4162, 'human', 'null', 'Apigenin', 'null', 'The flavone apigenin is presum ably reduced to the flavanone naringenin in a first step which is followed by an isomerization to the corresponding chalcone structure. The chalcone is reduced to the dihydrochalcone phloretin, which is subsequently hydrolyzed to phloroglucinol and 3-(4-hydroxyphenyl)propionic acid (23). Although the degradation pathway of flavones by E. ramulus has successfully been elucidated, the enzymes involved have so far escaped purification and characterization.', 15466559);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4163, 'human', 'null', '5,7-Dihydroxy-2-(4-hydroxyphenyl)chroman-4-one', 'null', 'The flavone apigenin is presum ably reduced to the flavanone naringenin in a first step which\nis followed by an isomerization to the corresponding chalcone structure. The chalcone is reduced to the dihydrochalcone phloretin, which is subsequently hydrolyzed to phloroglucinol and 3-(4-hydroxyphenyl)propionic acid (23). Although the degradation pathway of flavones by E. ramulus has successfully been elucidated, the enzymes involved have so far escaped purification and characterization.', 15466559);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4164, 'human', 'null', 'Naringenin chalcone', 'null', 'The flavone apigenin is presum ably reduced to the flavanone naringenin in a first step which\nis followed by an isomerization to the corresponding chalcone structure. The chalcone is reduced to the dihydrochalcone phloretin, which is subsequently hydrolyzed to phloroglucinol and 3-(4-hydroxyphenyl)propionic acid (23). Although the degradation pathway of flavones by E. ramulus has successfully been elucidated, the enzymes involved have so far escaped purification and characterization.', 15466559);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4165, 'human', 'null', 'Phloretin', 'null', 'The flavone apigenin is presum ably reduced to the flavanone naringenin in a first step which\nis followed by an isomerization to the corresponding chalcone structure. The chalcone is reduced to the dihydrochalcone phloretin, which is subsequently hydrolyzed to phloroglucinol and 3-(4-hydroxyphenyl)propionic acid (23). Although the degradation pathway of flavones by E. ramulus has successfully been elucidated, the enzymes involved have so far escaped purification and characterization.', 15466559);
