INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4170, 'human', 'null', 'Glycitein', 'null', 'Glycitein is demethoxylated in vitro by Eubacterium limosum to 6,7,40-trihydroxyisoflavone .', 19580283);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4171, 'human', 'null', 'Daidzein', 'null', 'Strains of Bacteroide ovatus spp., Streptococcus intermedius spp., and Ru minococcus productus SNU-Julong 732 (AY310748) as well as a stable mixed culture consisting of Enterococcus faecium EPI1, Lactobacillus mucosae EPI2, Finegoldia magna EPI3, and Veillo nella sp. EP have been isolated from human feces and reported to be able to convert daidzein into equol (16, 119-122) .', 19580283);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4172, 'human', 'null', 'Daidzein', 'null', 'Strains of Bacteroide ovatus spp., Streptococcus intermedius spp., and Ru minococcus productus SNU-Julong 732 (AY310748) as well as a stable mixed culture consisting of Enterococcus faecium EPI1, Lactobacillus mucosae EPI2, Finegoldia magna EPI3, and Veillo nella sp. EP have been isolated from human feces and reported to be able to convert daidzein into equol (16, 119-122) .', 19580283);
