INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4177, 'human', 'null', 'Daidzein', 'null', 'Strains of Bacteroide ovatus spp., Streptococcus intermedius spp., and Ru minococcus productus SNU-Julong 732 (AY310748) as well as a stable mixed culture consisting of Enterococcus faecium EPI1, Lactobacillus mucosae EPI2, Finegoldia magna EPI3, and Veillo nella sp. EP have been isolated from human feces and reported to be able to convert daidzein into equol (16, 119-122) .', 19580283);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4178, 'human', 'null', 'Dihydrodaidzein', 'null', 'The bacterial strain named Julong 732 is also able to metabolize dihydrodaidzein to S-equol (123). Thus, other bacteria have to be involved in the previous steps of the conversion of daidzein to equol .', 19580283);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4179, 'human', 'null', 'Isoxanthohumol', 'null', 'Isoxanthohumol is a prenylated flavanone from hops and beer that has interesting biological activities. It can be metabo lized in vivo by colonic microbiota to render 8-prenylnaringenin (133, 134). This metabolic O-demethylation is carried out by Eubacterium species and particularly by Eubacterium limosum.', 19580283);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4180, 'mouse', 'null', 'Cholesterol', 'null', 'unclassifed Lachnospiraceae, Oscillibacter,  Clostridium IV and Clostridium XlVa of phylum Firmicutes identifed upon RSB application showed similar  trends of correlation. Te relative abundance of the predominant RSB-enriched gut bacterial genus of unclas sifed Lachnospiraceae was positively associated with the concentrations of nine increased metabolites, includ ing cholic acid, 7-dehydrocholesterol, 11-deoxycorticosterone, retinol, chenodeoxycholic acid, L-phenylalanine,  L-glutamate, 3-phenylpropanoic acid and (5Z, 8Z, 11Z, 14Z, 17Z)-eicosapentaenoic acid, and negatively cor related with the concentrations of four metabolites showing decreasing trends, including L-isoleucine, tetra decanoic acid, indole-3-acetic acid, and benzoic acid.', 31780788);
