INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4243, 'mouse', 'decrease', 'null', 'low-throughput', 'Ratelimited enzymes in the process of TG synthesis of the DGAT1/2 mRNA level in the HFD group were signifificantly increased compared with the LFD group. The DGAT2 mRNA level in the HFD-CBM group decreased in the same range as the LFD group, whereas signifificant differences of the DGAT1 mRNA level were not found between the HFD group and the HFD-CBM group.', 24166662);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4249, 'mouse', 'decrease', 'null', 'low-throughput', 'TMAO inhibits SIRT1 expression, induces oxidative stress, and impairs NO production both in vivo and in vitro.', 29325896);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4250, 'mouse', 'decrease', 'null', 'low-throughput', 'By conducting a miRNA microarray screening, we revealed that expression of miRNA-10b in macrophages can be reduced by PCA. Functional analyses demonstrated that miRNA-10b directly represses ABCA1 and ABCG1 and negatively regulates cholesterol efflux from murine- and human-derived macrophages. Further in vitro and ex vivo analyses verified that PCA accelerates macrophage cholesterol efflux, correlating with the regulation of miRNA-10b-ABCA1/ABCG1 cascade, whereas Cy-3-G consumption promoted macrophage RCT and regressed atherosclerotic lesion in a gut microbiotaendependent manner.', 22821931);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4251, 'mouse', 'increase', 'null', 'low-throughput', 'By conducting a miRNA microarray screening, we revealed that expression of miRNA-10b in macrophages can be reduced by PCA. Functional analyses demonstrated that miRNA-10b directly represses ABCA1 and ABCG1 and negatively regulates cholesterol efflux from murine- and human-derived macrophages. Further in vitro and ex vivo analyses verified that PCA accelerates macrophage cholesterol efflux, correlating with the regulation of miRNA-10b-ABCA1/ABCG1 cascade, whereas Cy-3-G consumption promoted macrophage RCT and regressed atherosclerotic lesion in a gut microbiotaendependent manner.', 22821931);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4252, 'mouse', 'increase', 'null', 'low-throughput', 'By conducting a miRNA microarray screening, we revealed that expression of miRNA-10b in macrophages can be reduced by PCA. Functional analyses demonstrated that miRNA-10b directly represses ABCA1 and ABCG1 and negatively regulates cholesterol efflux from murine- and human-derived macrophages. Further in vitro and ex vivo analyses verified that PCA accelerates macrophage cholesterol efflux, correlating with the regulation of miRNA-10b-ABCA1/ABCG1 cascade, whereas Cy-3-G consumption promoted macrophage RCT and regressed atherosclerotic lesion in a gut microbiotaendependent manner.', 22821931);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4253, 'mouse', 'decrease', 'null', 'low-throughput', 'We extended our study to human samples to determine the effect of bile acids on CXCL16 mRNA expression of human liver sinusoidal endothelial cells. Similar to the mouse study, primary bile acids CDCA and TCA induced CXCL16 mRNA expression in SK-HEP1 cells (Fig. 5H). Next, the correlation between bile acids and CXCL16 expression was tested in nontumor liver tissues from HCC or cholangiocarcinoma patients of the Thailand Initiative for Genomics and Expression Research in Liver Cancer (TIGER-LC) cohort (34). Primary bile acid CDCA levels correlated with CXCL16 expression (Fig. 5I), whereas inverse correlation was seen for the secondary bile acid glycolithocholate (GLCA) (fig. S6I). The primary/secondary ratio was associated with CXCL16 increase (fig. S6J), indicating that the opposing effect of bile acids on CXCL16 expression also exists in humans.', 29798856);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4254, 'mouse', 'decrease', 'null', 'low-throughput', 'In summary,this study showed that it is butyrate, in stead of other substances produced by F.prausnitzii,inhibiting HDAC1 to activate Foxp3 and block the IL-6/STAT3/IL-17 pathway,thus regulating Th17/Treg cells and exerting an anti-inflammatory effect in IBD animal models.', 29796620);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4255, 'mouse', 'decrease', 'null', 'low-throughput', 'In summary,this study showed that it is butyrate, in stead of other substances produced by F.prausnitzii,inhibiting HDAC1 to activate Foxp3 and block the IL-6/STAT3/IL-17 pathway,thus regulating Th17/Treg cells and exerting an anti-inflammatory effect in IBD animal models.', 29796620);
