INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4258, 'mouse', 'increase', 'null', 'low-throughput', 'In summary,this study showed that it is butyrate, in stead of other substances produced by F.prausnitzii,inhibiting HDAC1 to activate Foxp3 and block the IL-6/STAT3/IL-17 pathway,thus regulating Th17/Treg cells and exerting an anti-inflammatory effect in IBD animal models.', 29796620);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4259, 'mouse', 'null', '4-Hydroxyphenylacetic acid', 'null', 'To identify the bacteria responsible, 26 strains representing 25 of the dominant human colonic species were screened for phenyl metabolite formation. Seven strains produced significant amounts of both PAA and 4-hydroxyPAA. These included five out of seven Bacteroidetes (Bacteroides thetaiotaomicron, Bacteroides eggerthii, Bacteroides ovatus, Bac teroides fragilis, Parabacteroides distasonis), and two out of 17 Firmicutes (Eubacterium hallii and Clostridium bartlettii). These species also produced indole-3-acetic acid (IAA), the corresponding tryptophan metabolite, but C. bartlettii showed 100 times higher IAA production than the other six strains. Four strains were further tested and PAA formation was substantially increased by phenylalanine, 4-hydroxyPAA by tyrosine and IAA by tryptophan.', 23349065);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4260, 'mouse', 'null', '4-Hydroxyphenylacetic acid', 'null', 'To identify the bacteria responsible, 26 strains representing 25 of the dominant human colonic species were screened for phenyl metabolite formation. Seven strains produced significant amounts of both PAA and 4-hydroxyPAA. These included five out of seven Bacteroidetes (Bacteroides thetaiotaomicron, Bacteroides eggerthii, Bacteroides ovatus, Bac teroides fragilis, Parabacteroides distasonis), and two out of 17 Firmicutes (Eubacterium hallii and Clostridium bartlettii). These species also produced indole-3-acetic acid (IAA), the corresponding tryptophan metabolite, but C. bartlettii showed 100 times higher IAA production than the other six strains. Four strains were further tested and PAA formation was substantially increased by phenylalanine, 4-hydroxyPAA by tyrosine and IAA by tryptophan.', 23349065);
