INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4418, 'mouse', 'increase', 'null', 'low-throughput', 'IVAS stimulated a dose-dependent increase in glucose transport through glucose transporter GLUT4- and PI3K-dependent mechanisms. IVAS also up regulated GLUT1, GLUT4, and PI3K p85a protein, and increased phosphorylation of Akt.', 30183376);
