INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4439, 'mouse', 'null', 'Lactic acid', 'null', 'We tested different Coprococcus strains for their ability to utilise lactate for growth. C. eutactus ATCC 27759 and C. comes ATCC 27758 could not grow on lactate, but C. catus GD/7 was able to grow with 25 mM lactate on YCFA medium containing 30 mM acetate. Propionate became the main product and substantial lactate utilisation also occurred in the presence of 10 mM fructose.', 24553467);
