INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4523, 'mouse', 'increase', 'Tyrosine', 'low-throughput', 'Here we show using untargeted metabolomics that levels of phenyl sulfate, a gut microbiota-derived metabolite, increase with the progression of diabetes in rats overexpressing human uremic toxin transporter SLCO4C1 in the kidney, and are decreased in rats with limited proteinuria.', 31015435);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4524, 'mouse', 'increase', 'Tyrosine', 'low-throughput', 'although there was no difference between in the preserved tubular area and fibrotic area at the light microscopic level, the expression levels of representative inflammatory genes, TNF-α (Tnfa) and MCP-1 (Ccl2), the fibrotic gene TGF-α1 (Tgfb1), fibronectin (Fn1), and collagen I (Col1a1) were increased in PS-treated db/db kidney. It was reported that db/db mice develop renal fibrosis.', 31015435);
