INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4530, 'mouse', 'null', 'Daidzein', 'null', 'Equol is a metabolite of daidzein that is produced by intestinal microbiota.The rod-shaped and Gram-positive anaerobic equol-producing intestinal bacterium Slackia TM-30 was isolated from healthy human faeces.', 26455424);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4534, 'mouse', 'increase', 'null', 'low-throughput', 'Live B. dentium-monoassociated mice exhibited increased colonic expression of goblet cell markers Krüppel-like factor 4 (Klf4), Trefoil factor 3 (Tff3), Relm-β, Muc2, and several glycosyltransferases compared to both heat-killed B. dentium and germfree counterparts.', 31213556);
