INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4549, 'mouse', 'null', 'null', 'null', 'A specific human-associated gut microbe, Clostridium orbiscindens,produced DAT and rescued antibiotic-treated influenza-infected mice.Consistent with our hypothesis that DAT protects from influenza infection by enhancing type I IFN signaling before infection.', 28774928);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4550, 'mouse', 'increase', 'null', 'low-throughput', 'Oxidative stress and inflammation in the kidney have been demonstrated to play a pivotal role in the initiation and progression of obesity-related renal injury [20e22]. To further determine the possible molecular mechanisms by which elevated TMAO levels induce renal interstitial fibrosis and dysfunction, we measured expression of NOX-4 (a constitutive active enzyme responsible for the production of reactive oxygen species) and proinflammatory cytokines in the kidney. As presented in Fig. 4, expression of NOX-4(Fig. 4A and B) and pro-inflammatory cytokines TNF-a (Fig. 4A and C) and IL-1 b (Fig. 4A and D) was significantly increased in mice fed a HFD, compared with mice fed a LFD, but was reduced by DMB treatment. Expression of NOX-4, TNF-a and IL-1 b in mice fed a LFD was not affected by DMB treatment.', 28942145);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4551, 'mouse', 'increase', 'null', 'low-throughput', 'Oxidative stress and inflammation in the kidney have been demonstrated to play a pivotal role in the initiation and progression of obesity-related renal injury [20e22]. To further determine the possible molecular mechanisms by which elevated TMAO levels induce renal interstitial fibrosis and dysfunction, we measured expression of NOX-4 (a constitutive active enzyme responsible for the production of reactive oxygen species) and proinflammatory cytokines in the kidney. As presented in Fig. 4, expression of NOX-4(Fig. 4A and B) and pro-inflammatory cytokines TNF-a (Fig. 4A and C) and IL-1 b (Fig. 4A and D) was significantly increased in mice fed a HFD, compared with mice fed a LFD, but was reduced by DMB treatment. Expression of NOX-4, TNF-a and IL-1 b in mice fed a LFD was not affected by DMB treatment.', 28942145);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4552, 'mouse', 'increase', 'null', 'low-throughput', 'Oxidative stress and inflammation in the kidney have been demonstrated to play a pivotal role in the initiation and progression of obesity-related renal injury [20e22]. To further determine the possible molecular mechanisms by which elevated TMAO levels induce renal interstitial fibrosis and dysfunction, we measured expression of NOX-4 (a constitutive active enzyme responsible for the production of reactive oxygen species) and proinflammatory cytokines in the kidney. As presented in Fig. 4, expression of NOX-4(Fig. 4A and B) and pro-inflammatory cytokines TNF-a (Fig. 4A and C) and IL-1 b (Fig. 4A and D) was significantly increased in mice fed a HFD, compared with mice fed a LFD, but was reduced by DMB treatment. Expression of NOX-4, TNF-a and IL-1 b in mice fed a LFD was not affected by DMB treatment.', 28942145);
