INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4585, 'mouse', 'null', 'null', 'null', 'We were able to identify a few metabolites specific to the humanized Salmonella-infected group, including two metabolites in the glutathione pathway. In particular, we identified glutathione disulfide and glutathione cysteine disulfide in higher abundance in humanized Salmonella-infected mice. Salmonella infection triggers vast amounts of oxidative stress, and glutathione metabolism is important for protection against oxidative stress.', 30401779);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4586, 'mouse', 'null', 'null', 'null', 'We were able to identify a few metabolites specific to the humanized Salmonella-infected group, including two metabolites in the glutathione pathway. In particular, we identified glutathione disulfide and glutathione cysteine disulfide in higher abundance in humanized Salmonella-infected mice. Salmonella infection triggers vast amounts of oxidative stress, and glutathione metabolism is important for protection against oxidative stress.', 30401779);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4587, 'mouse', 'increase', 'null', 'low-throughput', 'SCFAs binding to GPR43 on colonic epithelial cells stimulates K þ efflux and hyperpolarization,which lead to NLRP3 inflammasome activation.', 25828455);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4588, 'mouse', 'increase', 'null', 'low-throughput', 'NaB corrected the HFD-induced gut microbiota imbalance in mice, while it considerably elevated the abundances of the beneficial bacteria Christensenellaceae, Blautia and Lactobacillus . These bacteria can produce butyric acid in what seems like a virtuous circle. And butyrate restored HFD induced intestinal mucosa damage, increased the expression of ZO-1 in small intestine, further decreased the levels of gut endotoxin in serum and liver compared with HF group.', 28104981);
