INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4591, 'mouse', 'increase', 'null', 'low-throughput', 'Taken together, these experiments suggest that RYGB restores intestinal NLRP6 inflammasome expression by increasing taurine and decreasing histamine in the gut.', 31602628);
