INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4593, 'mouse', 'decrease', 'Lipopolysaccharide', 'low-throughput', 'Equol inhibited the lipopolysaccharide (LPS)-induced TLR4 activation, MAPK activation,NF-kB-mediated transcription of inflammatory mediators, production of nitric oxide (NO), release of prostaglandin E2 (PGE-2), secretion of tumor necrosis factor-α (TNF-α) and interleukin 6 (IL-6),in Lipopolysaccharide (LPS)-activated murine microglia cells.', 28264445);
