INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4635, 'mouse', 'increase', 'null', 'low-throughput', 'To this end, DCA feeding was performed in HFD-fed mice treated with vancomycin (Figure 2(a,b)). Intriguingly, DCA feeding alone in VCM-treated HFD-fed mice was observed to induce substantial proinflammatory macrophages (iNOS+) infiltration and increase the expression of multiple proinflammatory factors (IL-6, TNF-α, IL-1β, iNOS) in the colon tissue (Figure 2(c–f)), mimicking the inflammatory intestinal damage induced by HFD.', 33006494);
