INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4639, 'mouse', 'increase', 'null', 'low-throughput', 'Indeed, DCA stimulation could induce potent increase of mRNA expression level of M2-mAchR in macrophages, and selective inhibition of M2-mAchR significantly reduced theproduction of TNF-α, NO and IL-6 triggered by DCA (Figure 4(d,e) and Supplementary Figure 4c).', 33006494);
