INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4645, 'mouse', 'increase', 'null', 'low-throughput', 'At the concentrations tested, indole, 2-oxindole, kynurenic acid and indole-3-acetic acid elicited significant Cyp1a1 induction relative to vehicle (~5-fold, p < .01). 2, 8-dihydroxyquinoline induced Cyp1a1 to a lesser yet significant extent (1.3-fold, p < .01). None of the remaining tryptophan metabolites elicited significant Cyp1a1 inducibility.', 32783770);
