INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4651, 'mouse', 'null', 'Tryptophan', 'null', 'We have shown that breast milk tryptophan and Bifidobacterium infantis result in a metabolite (indole-3-lactic acid) response, which is anti-inflammatory via inhibition of the aryl hydrocarbon receptor transcription factor which stimulates an IL-8 response.', 32229728);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4656, 'mouse', 'increase', 'null', 'low-throughput', 'Duodenal murine enteroids were exposed to 1 and 5 mM SCFAs for 24 h. Expression of stem cell marker leucine-rich repeat-containing G-protein coupled receptor 5 (Lgr5) was increased more than 2-fold in murine enteroids treated with 5 mM ACET (P < 0.05). Conversely, enteroids treated with 5 mM BUT, or PROP had greater than 5-fold decreases in Lgr5 compared to CON (P < 0.05; Fig 2b). There was no difference in Lgr5 expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4657, 'mouse', 'decrease', 'null', 'low-throughput', 'Duodenal murine enteroids were exposed to 1 and 5 mM SCFAs for 24 h. Expression of stem cell marker leucine-rich repeat-containing G-protein coupled receptor 5 (Lgr5) was increased more than 2-fold in murine enteroids treated with 5 mM ACET (P < 0.05). Conversely, enteroids treated with 5 mM BUT, or PROP had greater than 5-fold decreases in Lgr5 compared to CON (P < 0.05; Fig 2b). There was no difference in Lgr5 expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
