INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4659, 'mouse', 'increase', 'null', 'low-throughput', 'Enterocyte biomarker alkaline phosphatase (Alpi) was significantly increased in response to all SCFA treatments but was highest (3.5-fold;P < 0.05) in enteroids treated with PROP. There was no difference in Alpi expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
