INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4662, 'mouse', 'decrease', 'null', 'low-throughput', 'Gene expression of goblet cell marker mucin 2 (Muc2) was not significantly affected by ACET treatment, however, Muc2 was significantly decreased due to both BUT and PROP treatment (3-fold and 10-fold respectively;P < 0.05). Muc2 expression was not altered in murine enteroids treated with 1 mM SCFAs(P > 0.05; Fig 2a).', 32240190);
