INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4664, 'mouse', 'increase', 'null', 'low-throughput', 'Paneth cell marker lysozyme (Lyz) had a tendency (P = 0.08) to increase due to BUT treatment but there was no effect observed when treated with 1 mM SCFAs (P > 0.05;Fig 2a).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4665, 'mouse', 'increase', 'null', 'low-throughput', 'Enteroendocrine cell marker chromogranin A (Chga) was only significantly increased in BUT treated enteroids at both 1 mM and 5 mM concentrations (P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4666, 'mouse', 'increase', 'null', 'low-throughput', 'Tuft cell marker doublecortin-like kinase 1 (Dclk1) was significantly elevated in response to 5 mM ACET (3-fold) and PROP (2-fold) treatments compared to CON (P < 0.05; Fig 2b). There was no difference in Dclk1 expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4667, 'mouse', 'increase', 'null', 'low-throughput', 'Tuft cell marker doublecortin-like kinase 1 (Dclk1) was significantly elevated in response to 5 mM ACET (3-fold) and PROP (2-fold) treatments compared to CON (P < 0.05; Fig 2b). There was no difference in Dclk1 expression in murine enteroids treated with 1 mM SCFAs (P > 0.05; Fig 2a).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4668, 'mouse', 'increase', 'null', 'low-throughput', 'Antimicrobial peptide gene expression of c-type lectins regenerating islet-derived protein 3β (Reg3β) and 3γ (Reg3γ; Fig 2b) were increased moderately due to ACET treatment (20-fold and 40-fold), but were much more significantly increased due to BUT (150-fold and 350-fold,respectively) and PROP (250-fold, and 480-fold, respectively, P < 0.05) compared to CON.Only 1 mM BUT increased Reg3β and Reg3γ expression (80-fold and 100-fold respectively;P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4669, 'mouse', 'increase', 'null', 'low-throughput', 'Antimicrobial peptide gene expression of c-type lectins regenerating islet-derived protein 3β (Reg3β) and 3γ (Reg3γ; Fig 2b) were increased moderately due to ACET treatment (20-fold and 40-fold), but were much more significantly increased due to BUT (150-fold and 350-fold,respectively) and PROP (250-fold, and 480-fold, respectively, P < 0.05) compared to CON.Only 1 mM BUT increased Reg3β and Reg3γ expression (80-fold and 100-fold respectively;P < 0.05).', 32240190);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4670, 'mouse', 'increase', 'null', 'low-throughput', 'Antimicrobial peptide, β-defensin 1 (Defb1), was increased 3.5-fold due to ACET and BUT treatment, and 6-fold due to PROP treatment (P < 0.05); Fig 2b). 1 mM PROP was sufficient to increase Defb1 expression 2-fold compared to CON (P < 0.05).', 32240190);
