INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4691, 'mouse', 'decrease', 'null', 'low-throughput', 'Relative to the SAP + IAH group, the levels of claudin-2, MMP9, and TNF-α were significantly lower in the two treatment groups (P < 0.05; Figures 5A,B).', 33192557);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4692, 'mouse', 'increase', 'null', 'low-throughput', 'LPS significantly decreased the level of TEER (P < 0.01), while treatment with PA moderated the reduced TEER (P < 0.05). Secondly, we utilized immunoblotting to analyze the protein expression levels of ZO-1, occludin, and claudin-1. As shown in Figures 2B–E, the protein expression levels of ZO-1, occludin, and claudin-1 were lower in the LPS group than in the control group (P < 0.01). This LPS-induced alteration of tight junction protein expression was inhibited by PA (P < 0.05). These results suggest that PA can enhance and protect intestinal barrier function against LPS in IEC-6 cells.', 33041816);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4693, 'mouse', 'increase', 'null', 'low-throughput', 'LPS significantly decreased the level of TEER (P < 0.01), while treatment with PA moderated the reduced TEER (P < 0.05). Secondly, we utilized immunoblotting to analyze the protein expression levels of ZO-1, occludin, and claudin-1. As shown in Figures 2B–E, the protein expression levels of ZO-1, occludin, and claudin-1 were lower in the LPS group than in the control group (P < 0.01). This LPS-induced alteration of tight junction protein expression was inhibited by PA (P < 0.05). These results suggest that PA can enhance and protect intestinal barrier function against LPS in IEC-6 cells.', 33041816);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4694, 'mouse', 'increase', 'null', 'low-throughput', 'LPS significantly decreased the level of TEER (P < 0.01), while treatment with PA moderated the reduced TEER (P < 0.05). Secondly, we utilized immunoblotting to analyze the protein expression levels of ZO-1, occludin, and claudin-1. As shown in Figures 2B–E, the protein expression levels of ZO-1, occludin, and claudin-1 were lower in the LPS group than in the control group (P < 0.01). This LPS-induced alteration of tight junction protein expression was inhibited by PA (P < 0.05). These results suggest that PA can enhance and protect intestinal barrier function against LPS in IEC-6 cells.', 33041816);
