INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4819, 'mouse', 'increase', 'null', 'low-throughput', 'Here we show that the fatty acid-derived ketone body (D)-OHB specifically activates PUMA-G/HM74a at concentrations observed in serum during fasting.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4820, 'mouse', 'increase', 'null', 'low-throughput', 'Both (D)- and (L)-OHB, but not acetoacetate or free acetone, elicited a Ca2 response in cells expressing HM74a but not HM74.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4821, 'mouse', 'increase', 'null', 'low-throughput', 'Racemic (DL)-OHB also showed some degree of activity on all receptors; however, it was more potent on HM74a and its ortholog PUMA-G  than on HM74.', 15929991);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4825, 'mouse', 'increase', 'Tryptophan', 'high-throughput', 'Polybrominated diphenyl ethers (PBDEs) are persistent environmental toxicants associated with increased risk for metabolic syndrome.PBDEs altered the largest number of metabolites in the LIC; most were regulated by PBDEs in GF conditions. Importantly, intestinal microbiome was necessary for PBDE-mediated decreases in branched-chain and aromatic amino acid metabolites, including 3-indolepropionic acid, a tryptophan metabolite recently shown to be protective against inflammation and diabetes. Gene-metabolite networks revealed a positive association between the hepatic glycan synthesis gene a-1,6-mannosyltransferase (Alg12) mRNA and mannose, which are important for protein glycosylation. Glycome changes have been observed in patients with metabolic syndrome. In LIC of CV mice, 23 bacterial taxa were regulated by PBDEs. Correlations of certain taxa with distinct serum metabolites further highlight a modulatory role of the microbiome in mediating PBDE effects. In summary, PBDEs impact intermediary metabolism in an intestinal microbiome–dependent manner, suggesting that dysbiosis may contribute to PBDE-mediated toxicities that include metabolic syndrome.', 31123037);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (4826, 'mouse', 'decrease', 'null', 'high-throughput', 'Differential expression ratios and FDR p-value of genes involved in various intermediary metabolism pathways  in livers of PBDE-exposed CV and GF mice. Data were obtained from RNA-Seq experiments and differential expression was  determined using CuffDiff.', 31123037);
