INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5047, 'mouse', 'null', 'Vorinostat', 'null', 'Metabolite profiles of P. mallochii CCH01 were obviously changed by SAHA treatment. Four metabolites (1�?), including two new natural sclerotioramine derivatives, isochromophilone XIV (1) and isochromophilone XV (2), and two known compounds, sclerotioramine (3) and (+)- sclerotiorin (4), were isolated and purified from P. mallochii CCH01 treated with SAHA.', 31632360);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5048, 'mouse', 'null', 'Vorinostat', 'null', 'Metabolite profiles of P. mallochii CCH01 were obviously changed by SAHA treatment. Four metabolites (1�?), including two new natural sclerotioramine derivatives, isochromophilone XIV (1) and isochromophilone XV (2), and two known compounds, sclerotioramine (3) and (+)- sclerotiorin (4), were isolated and purified from P. mallochii CCH01 treated with SAHA.', 31632360);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5053, 'mouse', 'null', 'Isoxanthohumol', 'null', 'Recently, it was shown that the exposure to the potent hop phytoestrogen 8-prenylnaringenin (8-PN) depends on intestinal bacterial activation of isoxanthohumol (IX), but this occurs in only one-third of tested individuals. As the butyrate-producing Eubacterium limosum can produce 8-PN from IX, a probiotic strategy was applied to investigate whether 8-PN production could be increased in low 8-PN producers, thus balancing phytoestrogen exposure.', 18567753);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5054, 'mouse', 'decrease', 'P-Cresol', 'low-throughput', 'In the present study, we investigated the immunological effects of pCS derived from intestinal bacteria in mice. For this purpose, we fed mice a tyrosine-rich diet that causes the accumulation of pCS in their blood. The mice were shown to exhibit decreased Th1-driven 2, 4-dinitrofluorobenzene-induced contact hypersensitivity response. The concentration of pCS in blood was negatively correlated with the degree of the contact hypersensitivity response. In contrast, the T cell-dependent antibody response was not influenced by the accumulated pCS. We also examined the in vitro cytokine responses by T cells in the presence of pCS. The production of IFN-γ was suppressed by pCS. Further, pCS decreased the percentage of IFN-γ-producing Th1 cells. Our results suggest that intestinal bacteria-derived pCS suppressesTh1-type cellular immune responses', 24161588);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5055, 'mouse', 'increase', 'P-Cresol', 'low-throughput', 'In the present study, we investigated the immunological effects of pCS derived from intestinal bacteria in mice. For this purpose, we fed mice a tyrosine-rich diet that causes the accumulation of pCS in their blood. The mice were shown to exhibit decreased Th1-driven 2, 4-dinitrofluorobenzene-induced contact hypersensitivity response. The concentration of pCS in blood was negatively correlated with the degree of the contact hypersensitivity response. In contrast, the T cell-dependent antibody response was not influenced by the accumulated pCS. We also examined the in vitro cytokine responses by T cells in the presence of pCS. The production of IFN-γ was suppressed by pCS. Further, pCS decreased the percentage of IFN-γ-producing Th1 cells. Our results suggest that intestinal bacteria-derived pCS suppressesTh1-type cellular immune responses', 24161588);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5056, 'mouse', 'null', 'Pectin', 'null', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5057, 'mouse', 'null', 'Pectin', 'null', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5058, 'mouse', 'null', 'Pectin', 'null', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5059, 'mouse', 'null', 'Pectin', 'null', 'The purpose of this study was to elucidate the effect of pectin on the polyamine production by defined bacterial species in vivo. Germfree male Wistar rats (n = 18) were randomly assigned to one of three treatments: (i) monoassociation with Bacteroides thetaiotaomicron + fiber-free diet; (ii) diassociation with B. thetaiotaomicron + Fusobacterium varium + fiber-free diet or (iii) diassociation with B. thetaiotaomicron + F. varium + fiber-free diet + 10% pectin. The cecal contents of monoassociated rats fed fiber-free diet contained large amounts (1.51+/-0.21 micromol/dry total cecum content) of spermidine which was the major polyamine. The cecum of diassociated rats fed the fiber-free diet contained even higher concentrations of spermidine (2.53+/-0.21 micromol/dry total cecum content) and also putrescine, which was now the dominant polyamine (putrescine 0.32+/-0.28 vs. 3.01+/-0.28 micromol/dry total cecum content; monoassociation vs. diassociation).', 10801923);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5088, 'mouse', 'increase', 'null', 'low-throughput', 'Transverse aortic constriction (TAC) was performed to induce cardiac hypertrophy in Sprague-Dawley (SD) rats. We observed that TMAO levels were significantly elevated in SD rats after 6 weeks of TAC, suggesting the potential role of TMAO in regulating cardiac hypertrophy. In cultured cardiomyocytes, TMAO treatment stimulated cardiac hypertrophy, as indicated by increased cell area of cardiomyocytes and expression of hypertrophic markers including atrial natriuretic peptide (ANP) and beta-myosin heavy chain (β-MHC). Additionally, TMAO treatment induced cardiac hypertrophy and cardiac fibrosis in SD rats. Reducing TMAO synthesis by antibiotics (Abs) attenuated TAC-induced cardiac hypertrophy and fibrosis. Furthermore, pharmacological inhibition of Smad3 by SIS3 significantly reduced the expression of ANP and β-MHC, and cardiomyocyte cell size in TMAO-treated group. These data for the first time demonstrate that gut microbe-derived metabolite TMAO induces cardiac hypertrophy and fibrosis involving Smad3 signaling, suggesting that inhibition of gut microbes or generation of TMAO may become a potential target for the prevention and treatment of cardiac hypertrophy.', 30068915);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5089, 'mouse', 'increase', 'null', 'low-throughput', 'Transverse aortic constriction (TAC) was performed to induce cardiac hypertrophy in Sprague-Dawley (SD) rats. We observed that TMAO levels were significantly elevated in SD rats after 6 weeks of TAC, suggesting the potential role of TMAO in regulating cardiac hypertrophy. In cultured cardiomyocytes, TMAO treatment stimulated cardiac hypertrophy, as indicated by increased cell area of cardiomyocytes and expression of hypertrophic markers including atrial natriuretic peptide (ANP) and beta-myosin heavy chain (β-MHC). Additionally, TMAO treatment induced cardiac hypertrophy and cardiac fibrosis in SD rats. Reducing TMAO synthesis by antibiotics (Abs) attenuated TAC-induced cardiac hypertrophy and fibrosis. Furthermore, pharmacological inhibition of Smad3 by SIS3 significantly reduced the expression of ANP and β-MHC, and cardiomyocyte cell size in TMAO-treated group. These data for the first time demonstrate that gut microbe-derived metabolite TMAO induces cardiac hypertrophy and fibrosis involving Smad3 signaling, suggesting that inhibition of gut microbes or generation of TMAO may become a potential target for the prevention and treatment of cardiac hypertrophy.', 30068915);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5090, 'mouse', 'increase', 'Linoelaidic acid', 'low-throughput', 'Therefore, in this study, we investigated the effects of KetoA [10-oxo-12(Z)-octadecenoic acid]—a linoleic acid metabolite produced by gut lactic acid bacteria—on whole-body energy metabolism and found that dietary intake of KetoA could enhance energy expenditure in mice, thereby protecting mice from diet-induced obesity.', 28754711);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5091, 'mouse', 'increase', 'Linoelaidic acid', 'low-throughput', 'Ucp1 expression levels were also observed to have increased after administration of KetoA.', 28754711);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5092, 'mouse', 'increase', 'Linoelaidic acid', 'low-throughput', 'We also confirmed that administration of KetoA induced not only Ucp1, but other genes that are related to BAT function, such as b3AR, Pgc1a , Cpt1b , and Tbx1  in BAT and inguinal WAT of WT\nmice.', 28754711);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5093, 'mouse', 'increase', 'Linoelaidic acid', 'low-throughput', 'We also confirmed that administration of KetoA induced not only Ucp1, but other genes that are related to BAT function, such as b3AR, Pgc1a , Cpt1b , and Tbx1  in BAT and inguinal WAT of WT\nmice.', 28754711);
