INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5104, 'mouse', 'increase', 'null', 'high-throughput', 'It should be noted that the observed Akkermansia muciniphila-induced decrease of Fiaf is not significant. These results are partially supported by the effects of both butyrate and propionate stimulation, leading to significant increase in Fiaf expression, while the expression of Gpr43 and Pparis significantly decreased .', 25118238);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5105, 'mouse', 'decrease', 'null', 'high-throughput', 'Akkermansia muciniphila leads to significantly decreased expression of Gpr43 and Ppar and increased expression of Hdac3 and Hdac5.', 25118238);
