INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5109, 'mouse', 'increase', 'null', 'high-throughput', 'Acetate had no significant effect on the expression of Fiaf, Gpr43, Hdac5, or Ppar, while the expression of Hdac3 was significantly increased by acetate.', 25118238);
