INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5286, 'mouse', 'decrease', 'null', 'high-throughput', 'To analyze the effect of microbiota and SCFA on the main regulators of gene expression in the intestinal epithelium, we focused on the effects of these conditions on transcription factor expression (Fig. 3A). We observed that major overlap of effects on transcription factor expression was evident after treatment with Akkermansia muciniphila and propionate and butyrate. However, butyrate additionally affected expression of specific transcription factors in the intestinal epithelium of organoids not affected by other conditions (Fig. 3A). The expression of a very small numberof transcription factors was affected specifically by exposure of organoids to acetate or propionate (Fig. 3A).', 25118238);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5304, 'mouse', 'null', 'null', 'null', 'The results clearly showed that the high dose of PIPA could improve the intestinal movement and alleviate constipation symptoms in AD induced constipation mice.', 30846982);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5305, 'mouse', 'null', 'null', 'null', 'The results showed that the AD groups had lower levels of ACh and 5-HT in colonic tissue and that the H-PIPA dose induced an increase in both colonic ACh and 5-HT but without significant differences from those in the AD group.', 30846982);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5306, 'mouse', 'null', 'null', 'null', 'The results showed that the AD groups had lower levels of ACh and 5-HT in colonic tissue and that the H-PIPA dose induced an increase in both colonic ACh and 5-HT but without significant differences from those in the AD group.', 30846982);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5307, 'mouse', 'increase', 'null', 'low-throughput', 'Butyrate is a short-chain fatty acid derived from the metabolism of indigestible carbohydrates by the gut microbiota. Butyrate contributes to gut homeostasis, but it may also control inflammatory responses and host physiology in other tissues. Butyrate inhibits histone deacetylases, thereby affecting gene transcription, and also signals through the metabolite-sensing G protein receptor (GPR)109a.', 31366236);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5308, 'mouse', 'increase', 'null', 'low-throughput', 'The protective effect of butyrate was further confirmed in situ by enhanced expression of WT-1 (Fig. 1D),podocin, and podoplanin (Supplemental Fig. S3). In ad_x0002_dition, analysis of glomeruli ultrastructure revealed a well-preserved podocytelayer surrounding the GBM with presence of slit diaphragm and reduced FP effacement in butyrate-treated mice at early and later time points (Fig.1E). Over 60 d, all butyrate-treated mice survived ADRinduced nephropathy, compared with only about 20% of nontreated mice (Fig. 1F).', 31366236);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5309, 'mouse', 'decrease', 'null', 'low-throughput', 'We also assessed the gene expression levels of important fibrotic markers such as Tgf-b, Fsp1, ActaII, col4a1, and the enzymes involved in matrix remodeling, Mmp9 and Timp1 (Fig. 3C). Butyrate-treated mice showed lower levels of fibrotic markers both at d 7 and at d 14 compared with nontreated mice.', 31366236);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5310, 'mouse', 'decrease', 'null', 'low-throughput', 'We also assessed the gene expression levels of important fibrotic markers such as Tgf-b, Fsp1, ActaII, col4a1, and the enzymes involved in matrix remodeling, Mmp9 and Timp1 (Fig. 3C). Butyrate-treated mice showed lower levels of fibrotic markers both at d 7 and at d 14 compared with nontreated mice.', 31366236);
