INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5314, 'mouse', 'decrease', 'null', 'low-throughput', 'Renal inflammation is a common finding in ADR nephropathy. Injured resident kidney cells release chemokines that promote the recruitment ofmacrophages, which play a pivotal role as disease progresses. CD68 staining in renal cortex showed, at early stages of the disease, a slightly positive staining in nontreated mice, whereby we identified several foci of infiltrating CD68-positive cells at d 14 surrounding the glomeruli (Fig. 4A). Butyrate treatment significantly reduced the infiltration of CD68-positive cells, as well as gene expression of chemokines such as ccl2 and ccl3 and important proinflammatory cytokines such as Tnf-a and Il-1b in renal tissue (Fig. 4B). Protein levels for the proinflammatory cytokines in renal tissue were also significantly reduced by butyrate treatment (Fig. 4C).', 31366236);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5315, 'mouse', 'decrease', 'null', 'low-throughput', 'Renal inflammation is a common finding in ADR nephropathy. Injured resident kidney cells release chemokines that promote the recruitment ofmacrophages, which play a pivotal role as disease progresses. CD68 staining in renal cortex showed, at early stages of the disease, a slightly positive staining in nontreated mice, whereby we identified several foci of infiltrating CD68-positive cells at d 14 surrounding the glomeruli (Fig. 4A). Butyrate treatment significantly reduced the infiltration of CD68-positive cells, as well as gene expression of chemokines such as ccl2 and ccl3 and important proinflammatory cytokines such as Tnf-a and Il-1b in renal tissue (Fig. 4B). Protein levels for the proinflammatory cytokines in renal tissue were also significantly reduced by butyrate treatment (Fig. 4C).', 31366236);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5316, 'mouse', 'decrease', 'null', 'low-throughput', 'Renal inflammation is a common finding in ADR nephropathy. Injured resident kidney cells release chemokines that promote the recruitment ofmacrophages, which play a pivotal role as disease progresses. CD68 staining in renal cortex showed, at early stages of the disease, a slightly positive staining in nontreated mice, whereby we identified several foci of infiltrating CD68-positive cells at d 14 surrounding the glomeruli (Fig. 4A). Butyrate treatment significantly reduced the infiltration of CD68-positive cells, as well as gene expression of chemokines such as ccl2 and ccl3 and important proinflammatory cytokines such as Tnf-a and Il-1b in renal tissue (Fig. 4B). Protein levels for the proinflammatory cytokines in renal tissue were also significantly reduced by butyrate treatment (Fig. 4C).', 31366236);
