INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5330, 'mouse', 'decrease', 'Ellagic acid', 'low-throughput', 'Thus, the gut bacterial metabolite UA increases miR-10a-5p levels thereby downregulating Orai1/STIM1/STIM2 expression, store operated Ca2+ entry, and proliferation of murine CD4+ T cells.', 31417547);
