INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5337, 'mouse', 'decrease', 'Cholesterol', 'low-throughput', 'Altered substrate oxidation and fecal fat excretion in LHFD-fed GF mice is linked to decreased hepatic Cyp7a1 and Nr1h4 expression.', 27900259);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5338, 'mouse', 'decrease', 'Cholesterol', 'low-throughput', 'Altered substrate oxidation and fecal fat excretion in LHFD-fed GF mice is linked to decreased hepatic Cyp7a1 and Nr1h4 expression.', 27900259);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5339, 'mouse', 'decrease', 'Linoleic acid', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5340, 'mouse', 'decrease', 'Linoleic acid', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5341, 'mouse', 'increase', 'Linoleic acid', 'low-throughput', '10-Hydroxy-cis-12-octadecenoic acid (HYA), a gut microbial metabolite of linoleic acid, suppressed TNF and dextran sulfate sodium-induced changes in the expression of TJ-related molecules, occludin, zonula occludens-1, and myosin light chain kinase. HYA also suppressed the expression of TNF receptor 2 (TNFR2) mRNA and protein expression in Caco-2 cells and colonic tissue. In addition, HYA suppressed the protein expression of TNFR2 in murine intestinal epithelial cells. Furthermore, HYA significantly up-regulated G protein-coupled receptor (GPR) 40 expression in Caco-2 cells.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5342, 'mouse', 'decrease', 'Linoleic acid', 'low-throughput', 'IFN-TNF-induced an increase in FD-4 permeability;however, the pretreatment of HYA and linoleic acid signififcantly suppressed this increase (Fig. 2C). In contrast, the pretreatment of HYB did not alter IFN-TNF-induced changes in TER and FD-4 permeability. As shown in Fig. 2D,IFN-TNF-induced a marked increase in the secretion of IL-8, which is a major pro-inflammatory cytokine. However,the pretreatment of HYA significantly suppressed IL-8 secretion.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5343, 'mouse', 'increase', 'Linoleic acid', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5344, 'mouse', 'increase', 'Linoleic acid', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5345, 'mouse', 'increase', 'Linoleic acid', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5346, 'mouse', 'decrease', 'Linoleic acid', 'low-throughput', 'Pretreatment of HYA, but not HYB, significantly restored IFN-TNF-induced changes in the expression of occludin, ZO-1, claudin-1, and MLCK.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5347, 'mouse', 'decrease', 'Linoleic acid', 'low-throughput', 'The pretreatment of HYA suppressed IFN-induced up-regulation of TNFR2 (but not TNFR1), and it subsequently decreased the ratio of phospho-INF-B p65 expression induced by cytokines (Fig. 3, B and C). In contrast, pretreatment of HYB did not show the same inhibitory effects as HYA.', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5348, 'mouse', 'increase', 'Linoleic acid', 'low-throughput', 'It was noteworthy that the pretreatment of HYA augmented the mRNA expression of GPR40 and GPR43 but not GPR120, PPAR, and GPR41 in Caco-2 cells (Fig. 4A). However, the pretreatment of HYB did not up-regulate GPR40 and GPR43 expression (Fig. 4A).', 25505251);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5349, 'mouse', 'decrease', 'null', 'low-throughput', 'The expression levels of IL�? (Fig. 5A and B) and its receptors CXCR1 (Fig. 5A and C) and CXCR2 (Fig. 5A and D) were significantly increased in the non‑infarct LV of MI + VEH rats compared with the LV of SHAM + VEH rats; however, the expression of these proteins was normalized by DMB treatment.', 31180562);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5350, 'mouse', 'decrease', 'null', 'low-throughput', 'The expression levels of IL�? (Fig. 5A and B) and its receptors CXCR1 (Fig. 5A and C) and CXCR2 (Fig. 5A and D) were significantly increased in the non‑infarct LV of MI + VEH rats compared with the LV of SHAM + VEH rats; however, the expression of these proteins was normalized by DMB treatment.', 31180562);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5351, 'mouse', 'decrease', 'null', 'low-throughput', 'The expression levels of IL�? (Fig. 5A and B) and its receptors CXCR1 (Fig. 5A and C) and CXCR2 (Fig. 5A and D) were significantly increased in the non‑infarct LV of MI + VEH rats compared with the LV of SHAM + VEH rats; however, the expression of these proteins was normalized by DMB treatment.', 31180562);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5352, 'mouse', 'increase', 'null', 'low-throughput', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5353, 'mouse', 'increase', 'null', 'low-throughput', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5354, 'mouse', 'increase', 'null', 'low-throughput', 'Accordingly, in livers from TLR2-defcient mice, the expression of SASP factors, such as IL1β,  Groα, and IL6, was significantly reduced in HSCs, suggesting that TLR2-mediated signaling induced the expression of SASP factors (Fig. 2F). Notably, however, the presence of p21 and 53BP1 foci was still observed in activated HSCs from TLR2-deficient mice (Fig. 2F). The majority of senescent \nsignals are detected in the HSCs but not in HCC cells in the tumor region (Supplementary Fig. S2). Taken together, these results suggest that TLR2-mediated signaling is important for the upregulation of SASP factors in senescent HSCs but not for the induction of senescent cell-cycle arrest.', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5355, 'mouse', 'increase', 'null', 'low-throughput', 'Consistent with our previous report, the expression of the senescence inducers p21 (encoded by Cdkn1a) and p16 (encoded by Cdkn2a) was upregulated by DCA treatment (Fig. 3B). Notably, the expression levels of TLR2 and SASP factors, such as IL1β, Groα, and IL6, were significantly enhanced by LTA in DCA-induced senescent HSCs (Fig. 3C).', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5356, 'mouse', 'increase', 'null', 'low-throughput', 'Consistent with our previous report, the expression of the senescence inducers p21 (encoded by Cdkn1a) and p16 (encoded by Cdkn2a) was upregulated by DCA treatment (Fig. 3B). Notably, the expression levels of TLR2 and SASP factors, such as IL1β, Groα, and IL6, were significantly enhanced by LTA in DCA-induced senescent HSCs (Fig. 3C).', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5357, 'mouse', 'increase', 'null', 'low-throughput', 'The expression of COX2, but not COX1, in DCA-treated primary HSCs was significantly induced by increasing amounts of LTA (Fig. 4C), and the COX2 expression was dependent on TLR2 (Supplementary \nFig. S3). Indeed, we confirmed that TLR2 was expressed in HSCs and this expression was enhanced by LTA alone or DCA plus LTA treatment (Supplementary Fig. S8A).', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5358, 'mouse', 'decrease', 'null', 'low-throughput', 'The production of IFNγ and TNFα, which are known to activate antitumor immune responses and inhibit cancer cell growth, was significantly and specifically attenuated by PGE2.', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5359, 'mouse', 'decrease', 'null', 'low-throughput', 'The production of IFNγ and TNFα, which are known to activate antitumor immune responses and inhibit cancer cell growth, was significantly and specifically attenuated by PGE2.', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5360, 'mouse', 'increase', 'null', 'low-throughput', 'In contrast, the production of IL10, a potent anti-inflammatory cytokine, and IL6, a known tumor-promoting cytokine, in immune cells was slightly but significantly enhanced (Supplementary Fig. S8D).', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5361, 'mouse', 'increase', 'null', 'low-throughput', 'In contrast, the production of IL10, a potent anti-inflammatory cytokine, and IL6, a known tumor-promoting cytokine, in immune cells was slightly but significantly enhanced (Supplementary Fig. S8D).', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5362, 'mouse', 'increase', 'null', 'low-throughput', 'PGE2 is known to be recognized by four types of receptors: PTGER1, PTGER2, PTGER3, and PTGER4 (37, 38). In our mouse model, the expression of PTGER4, but not other PGE2 receptors, was significantly upregulated in tumor tissues (Fig. 5C),', 28202625);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5363, 'mouse', 'increase', 'null', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5364, 'mouse', 'decrease', 'null', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5365, 'mouse', 'increase', 'null', 'low-throughput', 'Indole 3-propionic acid (IPA), in the context of indole, is a ligand for PXR in vivo, and IPA downregulated enterocyte TNF-a while it upregulated junctional protein-coding mRNAs. PXR_deficient mice showed a distinctly ‘‘leaky’’gut physiology coupled with upregulation of the Toll-like receptor (TLR) signaling pathway.', 25065623);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5366, 'mouse', 'increase', 'null', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5367, 'mouse', 'increase', 'null', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5368, 'mouse', 'increase', 'null', 'low-throughput', 'For critical validation of the ex vivo experiments demonstrating IPA effects on junctional regulators, we coadministered C. sporogenes to germ-free mice in the presence or absence of\nL-tryptophan (Figure 1D). We verified that C. sporogenes inoculation led to production of IPA in vivo (thus, it was assumed that indoles were present) (Figure 1E). Germ-free mice exposed to\nC. sporogenes had a significant reduction in FITC-dextran recovery from the serum and this was further reduced in the presence of L-tryptophan dosing (Figure 1F). The mice intestinal mucosa\nexposed to C. sporogenes demonstrated significant induction of PXR target genes (Mdr1, Cyp3a11, Ugt1a1), which was further augmented in the presence of L-tryptophan (Figure 1G).', 25065623);
