INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5411, 'mouse', 'increase', 'null', 'high-throughput', 'UroA/UAS03 treatment attenuates TNBS-induced colitis in mice. Colitis was induced by intrarectal administration of TNBS (2.5 mg/mouse) in C57BL/6 (8 week age old, n = 5/group) mice. Mice were orally treated with vehicle or UroA (20 mg/kg) or UAS03 (20 mg/kg body weight) every 12 h post-TNBS instillation for 60 h and the experiment terminated at 72 h. Representative data from one of three independent experiments is shown. a Percent body weight loss (No TNBS- Solid black line; Veh + TNBS- Solid red line; UroA + TNBS- Solid blue line; UAS03 + TNBS- Solid purple line). b disease activity index, c intestinal permeability, d colon lengths were measured. e Gross morphological changes of colon, f ratio of colon weight/length, g colonic myeloperoxidase (MPO) levels, h serum IL-6, TNF-α, CXCL1, and IL-1β levels, i microphotographs of hematoxylin and eosin (H&E) stained sections of colons and inflammation scores are shown. Scale bar indicates 300 μm. j Cldn4 expression in the colons of these mice (n = 3) was measured by immunoblots and quantified. Statistical analysis was performed (unpaired t-test) using Graphpad Prism software. Error bars, ±SEM ***p < 0.001; **p < 0.01\n*p < 0.05. Source Data are provided as a Source Data File.', 30626868);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5412, 'mouse', 'increase', 'null', 'high-throughput', 'UroA/UAS03 treatment attenuates TNBS-induced colitis in mice. Colitis was induced by intrarectal administration of TNBS (2.5 mg/mouse) in C57BL/6 (8 week age old, n = 5/group) mice. Mice were orally treated with vehicle or UroA (20 mg/kg) or UAS03 (20 mg/kg body weight) every 12 h post-TNBS instillation for 60 h and the experiment terminated at 72 h. Representative data from one of three independent experiments is shown. a Percent body weight loss (No TNBS- Solid black line; Veh + TNBS- Solid red line; UroA + TNBS- Solid blue line; UAS03 + TNBS- Solid purple line). b disease activity index, c intestinal permeability, d colon lengths were measured. e Gross morphological changes of colon, f ratio of colon weight/length, g colonic myeloperoxidase (MPO) levels, h serum IL-6, TNF-α, CXCL1, and IL-1β levels, i microphotographs of hematoxylin and eosin (H&E) stained sections of colons and inflammation scores are shown. Scale bar indicates 300 μm. j Cldn4 expression in the colons of these mice (n = 3) was measured by immunoblots and quantified. Statistical analysis was performed (unpaired t-test) using Graphpad Prism software. Error bars, ±SEM ***p < 0.001; **p < 0.01\n*p < 0.05. Source Data are provided as a Source Data File.', 30626868);
