INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5492, 'mouse', 'decrease', 'null', 'low-throughput', 'In line with these clinical findings, VSL#3 and CLA significantly ameliorated gross pathology in colon, MLN and spleen, colonic histopathology such as leukocyte infiltration  and mucosal thickening , and colonic mRNA expression such as TNF-a and MCP-1 in comparison to untreated control mice with DSS colitis.', 22363592);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5493, 'mouse', 'decrease', 'null', 'low-throughput', 'In line with these clinical findings, VSL#3 and CLA significantly ameliorated gross pathology in colon, MLN and spleen, colonic histopathology such as leukocyte infiltration  and mucosal thickening , and colonic mRNA expression such as TNF-a and MCP-1 in comparison to untreated control mice with DSS colitis.', 22363592);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5498, 'mouse', 'increase', 'null', 'low-throughput', 'Here, we tested the hypothesis that the gut microbiota could induce maturation of the adult ENS through release of 5-HT and activation of 5-HT4 receptors.', 29866843);
