INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5569, 'mouse', 'null', 'Genistein', 'null', 'We isolated a strictly anaerobic bacterium (Mt1B8) from the mouse intestine which converted daidzein via dihydrodaidzein to equol as well as genistein via dihydrogenistein to 5-hydroxy-equol.', 18539813);
