INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5597, 'mouse', 'increase', 'null', 'low-throughput', 'Furthermore, benzoate, an inhibitor of d-amino acid oxidases (DAAO), can increase d-serine,thereby enhancing NMDAR activation [125,126].', 32290475);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5598, 'mouse', 'increase', 'Bile acid', 'low-throughput', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 32668198);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5599, 'mouse', 'increase', 'Bile acid', 'low-throughput', 'Reconstitution with a single bacterial species, Clostridium scindens, or its derived metabolite, the secondary bile acid deoxycholic acid, can restore pDC- and MyD88-dependent type I IFN responses to restrict systemic CHIKV infection and transmission back to vector mosquitoes. ', 32668198);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5600, 'mouse', 'null', 'Tryptophan', 'null', 'HSD significantly reduces intestinal Lactobacillus murinus in hypertensive FVB/N mice, while L murinus can metabolize trypto phan in the diet to produce indole, thereby inhibiting T lymphocyte differentiation into Th17 cells, alleviating inflammation and lowering BP.', 32078445);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5601, 'mouse', 'decrease', 'null', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5602, 'mouse', 'decrease', 'null', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5603, 'mouse', 'decrease', 'null', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5604, 'mouse', 'increase', 'null', 'low-throughput', 'Moreover, the culture supernatant of B fra gilis YCH46 could significantly reduce the corticoste rone level and reverse the abnormal expressions of Mr, Cyp11a1, Cyp11b1, Hsd11b1, and Hsd11b2 in high salt–fed mice colon tissues (Figure 5E through 5J). Namely, B fragilis effectively counteracted HSD effects on intesti nal corticosterone metabolism and dramatically reduced intestinal corticosterone production level.', 32078445);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5605, 'mouse', 'increase', 'null', 'low-throughput', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5606, 'mouse', 'increase', 'null', 'low-throughput', 'Here, we elucidate a micro biome-dependent pathway by which SG increases CA7S production. We show that a microbial metabolite,lithocholic acid (LCA), is increased in murine portal veins post-SG and by activating the vitamin D receptor, induces hepatic mSult2A1/hSULT2A expression to drive CA7S production. An SG-induced shift in the micro biome increases gut expression of the bile acid transporters Asbt and Osta, which in turn facilitate selective transport of LCA across the gut epithelium. Cecal microbiota transplant from SG animals is sufficient to recreate the pathway in germ-free (GF) animals. \nand GLP-1 secretion, causally connecting a microbial metabolite with the improvement of diabetic phe notypes.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5607, 'mouse', 'increase', 'null', 'low-throughput', 'We determined that CA7S is a potent agonist of the G-protein-coupled recep tor TGR5 (GPBAR1) and induces GLP-1 secretion. When administered to diet-induced obese (DIO) mice, CA7S in creases insulin secretion and induces systemic glucose clearance.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5608, 'mouse', 'increase', 'null', 'low-throughput', 'We determined that CA7S is a potent agonist of the G-protein-coupled recep tor TGR5 (GPBAR1) and induces GLP-1 secretion. When administered to diet-induced obese (DIO) mice, CA7S in creases insulin secretion and induces systemic glucose clearance.', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5609, 'mouse', 'decrease', 'null', 'low-throughput', 'Consistent with our in vitro results showing that LCA inhibits expression of Asbt and Osta, SG-CMT mice exhibited significantly higher levels of Asbt and Osta expression in the distal ileum compared with sham-CMT (Figure 7E).', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5610, 'mouse', 'decrease', 'null', 'low-throughput', 'Consistent with our in vitro results showing that LCA inhibits expression of Asbt and Osta, SG-CMT mice exhibited significantly higher levels of Asbt and Osta expression in the distal ileum compared with sham-CMT (Figure 7E).', 33434516);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5611, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5612, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5613, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5614, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Concentrations of pro-inflammatory cytokines com monly associated with neuroinflammation (IL1-β, IL 6, and TNF-α) and the anti-inflammatory cytokine IL-10 were measured in whole-brain lysates from young and old mice and are presented in Fig. 3a. Whole-brain concentrations of pro-inflammatory cytokines were all ~ 50�?00% higher in old vs. young mice (all p < 0.05).Old mice also tended to have (presumably compensato ry) higher brain IL-10 compared to young mice (p =0.07).', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5615, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Next, we measured the pro-inflammatory tran scription factor nuclear factor kappa B (NF-κB), which is a key regulator of pro-inflammatory cytokine signal ing. Although abundance of phosphorylated (i.e., acti vated) NF-κB was similar between brains from young and old mice (p = 0.49), old mice had ~ 50% higher abundance of total NF-κB (p < 0.001; Fig. 3b), suggest ing a greater capacity to upregulate pro-inflammatory cytokine production.', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5616, 'mouse', 'increase', 'Trimethylamine', 'low-throughput', 'Finally, LCN2, an established marker of reactive astrocytes involved in the innate immune response to bacteria [5, 63], was higher in brain lysates from old compared to young mice (p < 0.05;Fig. 3c).', 32862276);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5617, 'mouse', 'increase', 'null', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5618, 'mouse', 'increase', 'null', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5619, 'mouse', 'increase', 'null', 'low-throughput', 'In this study, we observed that in mice exposed to HFD or without intestinal epithelial cell AhR expression, the efect of diet was more signifcant than the absence of AhR on the fecal microbiome composition. On the other hand, the absence of AhR had a more pronounced efect on the fecal metabolome than diet. Tryptophan metabolites were among those that were signifcantly altered in the metabolome, and integrated microbiome and metabolome analysis predicted three taxa—unclas sifed Clostridiales, unclassifed Desulfovibrionaceae, and Akkermansia—as key contributors to the synthesis and/or degradation of tryptophan metabolites. Our study highlights the use of multi-omic analysis to investigate the relationship between microbiome and metabolome and suggests possible taxa that can be targeted to manip ulate the microbiome for CRC prevention.', 33256731);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5620, 'mouse', 'increase', 'null', 'low-throughput', 'mRNA levels of TNF-α and IL-1β in the WAT of ob/ob mice were, respectively, 17- and 4-fold higher than those of C57BL/6 J mice (Fig. 2A). Te iNOS and COX-2 in WAT were also, respectively, 5.4- and 2.2-fold higher than those of C57BL/6 J mice (Fig. 2A). Hepatic gene expression of IL-6 was signifcantly increased in ob/ob mice compared with C57BL/6 J mice although TNF-α and IL-1β were not markedly increased (Fig. 2B).', 32296105);
