INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5632, 'mouse', 'increase', 'Tryptophan', 'low-throughput', 'Interestingly, in the same mice, indole induced a dramatic increase of the expression of the adrenomedullary Pnmt gene, which is involved in catecholamine biosynthesis.', 32569990);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5633, 'mouse', 'decrease', 'null', 'low-throughput', 'To illuminate the molecular mechanism underpinning the hyperlipidemia-ameliorating role of DNJ, we further examined the impact of DNJ on hepatic genes that are involved in lipid synthesis (SREBP1c, FAS, ACC, GPAT, SCD, ChREBP, SREBP2, and HMGR), transport (FATP, FABP, LXR, and CD36) and oxidation (CPT1, PPAR , AMPK, and ACO). Compared with the normal control mice, mice that received gavage of DNJ alone showed decreased transcription of lipogenic genes (Fig. 2 and Table 1), with no significant effects on genes participating in lipid transport (except CD36) and oxidation (see Fig. S2 in the supple mental material, suggesting that DNJ may prevent hyperlipidemia via inhibiting lipid biosynthesis.', 33024047);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5634, 'mouse', 'decrease', 'null', 'low-throughput', 'To illuminate the molecular mechanism underpinning the hyperlipidemia-ameliorating role of DNJ, we further examined the impact of DNJ on hepatic genes that are involved in lipid synthesis (SREBP1c, FAS, ACC, GPAT, SCD, ChREBP, SREBP2, and HMGR), transport (FATP, FABP, LXR, and CD36) and oxidation (CPT1, PPAR , AMPK, and ACO). Compared with the normal control mice, mice that received gavage of DNJ alone showed decreased transcription of lipogenic genes (Fig. 2 and Table 1), with no significant effects on genes participating in lipid transport (except CD36) and oxidation (see Fig. S2 in the supple mental material, suggesting that DNJ may prevent hyperlipidemia via inhibiting lipid biosynthesis.', 33024047);
