INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5653, 'mouse', 'decrease', 'null', 'low-throughput', 'The expression of IL-1, IL-17 and TNF-α were higher in the intestinal tract of the germ free mice that had not received a human flora fecal transplant than in those that had received a fecal transplant, and the expression of IL-1, IL 17 and TNF-α decreased significantly after the fecal transplant (Fig. 4c, p < 0.01).', 33233042);
