INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5656, 'mouse', 'decrease', 'null', 'low-throughput', 'Compared with the germ free group, the expression of NF-κB decreased significantly in the colon after transplantation of intestinal flora (p < 0.05), and the intake of stachyose downregulated the expression of NF-κB (p < 0.05).', 33233042);
INSERT INTO `metabolite_gene_change_results` (`index`, `host_type`, `Alteration`, `substrate_name`, `throughput`, `description`, `Evidence`) VALUES (5657, 'mouse', 'increase', 'null', 'low-throughput', 'As shown in Fig. 4h and i, the expression of occludin and ZO-1 in the colon tissue of germ-free mice significantly increased after human fecal transplantation (p < 0.05).', 33233042);
